int rc4_hmac_md5_get_ct_params(
    const EVP_CIPHER *c, EVP_CIPHER_CTX *ct, EVP_CIPHER_CTX *ct2,
    const unsigned char *key, const unsigned char *iv, size_t iv_len)
{
    if (ct2 != NULL) {
        /*
         * We create a 'parent' contet which contains a copy of the key and
         * implements the full cipher. We then create a 'child' contet which
         * has a NULL key and IV but otherwise inherits from the parent. The
         * parent contet can be used for IV generation and the child for
         * encryption.
         */
        if (EVP_Cipher_CTX_copy(ct2, ct) != 1)
            return 0;
        if (key != NULL)
            memcpy(ct2->key, key, EVP_CIPHER_CTX_key_length(ct2));
        ct->num = 0;
        memcpy(ct->iv, iv, iv_len);
    }
    return 1;
}

