void Auth::Digest::Config::init(const char *params)
{
    debugs(85, 4, "initialising");

#if USE_AUTH
    char const *space = strchr(params, ' ');
    int timeout = 0;
    unsigned int counter = 0;

    if (space == NULL)
        space = params + strlen(params);

    if (params != space) {
        timeout = atoi(string(params, space).c_str());
        params = space + 1;

        space = strchr(params, ' ');
        if (space == NULL)
            space = params + strlen(params);

        counter = (unsigned int) atoi(string(params, space).c_str());
    }

    debugs(85, 5, "digest auth timeout = " << timeout);
    debugs(85, 5, "digest auth nonce reference counter = " << counter);

    /* authScheme is deleted when config is reloaded or changed */
    if (authScheme != NULL)
        delete authScheme;

    authScheme = new Auth::Digest::Scheme(counter, timeout, NULL);
#else
    (void)params;
#endif
}

