KeyedSparseTensorColumn::KeyedSparseTensorColumn(
    std::vector<Tensor> values_list,
    std::vector<Offset> value_offsets,
    std::vector<Key> sorted_keys,
    std::vector<Offset> key_offsets,
    int64_t dense_size)
    : values_list_(std::move(values_list)),
      value_offsets_(std::move(value_offsets)),
      sorted_keys_(std::move(sorted_keys)),
      key_offsets_(std::move(key_offsets)),
      dense_size_(dense_size) {
  // The following logic handles two cases:
  // (1) A single column of a SparseTensor
  // (2) Multiple columns of a SparseTensor, concatenated along the 0th dimension
  //
  // For case (1), value_offsets_list will contain a single entry, and
  // key_offsets will contain a single entry.
  //
  // For case (2), value_offsets_list will contain N entries, and key_offsets
  // will contain N+1 entries, where N is the number of columns in the
  // SparseTensor.
  //
  // In both cases, the total number of rows is given by key_offsets_.back().

  const int num_rows = key_offsets_.back();
  // 1. Allocate space for the keys and row pointers
  keys_.resize(num_rows);
  row_pointers_.resize(num_rows, 0);

  // 2. Copy the keys into the new storage, and set the row pointers
  for (int i = 0; i < num_rows; ++i) {
    const auto key_offset = key_offsets_[i];
    const auto key = sorted_keys_[key_offset];
    std::memcpy(&keys_[i], &key, sizeof(Key));
    row_pointers_[i] = i;
  }

  // 3. Set the value pointers
  for (int i = 0; i < values_list_.size(); ++i) {
    // For a SparseTensor with M columns, values_list_ will contain M
    // tensors. The i-th tensor contains the values for the i-th column.
    //
    // The non-zero values for the i-th column are stored in
    // values_list_[i].flat<T>()[0:value_offsets_[i+1] - value_offsets_[i]]
    const auto value_offset_start = value_offsets_[i];
    const auto value_offset_end = value_offsets_[i + 1];
    value_pointers_.push_back(&values_list_[i].flat<T>()[value_offset_start]);
    value_counts_.push_back(value_offset_end - value_offset_start);
  }

  // 4. (Optional) Set the batch dimensions
  if (!value_offsets_.empty()) {
    const auto& batch_dims = value_offsets_.back().batch_dims;
    batch_dims_ = std::vector<int64_t>(batch_dims.begin(), batch_dims.end());
  }

  // 5. Set the dense dimensions
  const auto& dense_dims = value_offsets_.back().dense_dims;
  dense_dims_ = std::vector<int64_t>(dense_dims.begin(), dense_dims.end());

  // 6. Set the column name
  column_name_ = value_offsets_.back().column_name;

  // 7. Set the tensor slice
  tensor_slice_ = value_offsets_.back().tensor_slice;

  // 8. Set the hash table id
  hash_table_id_ = value_offsets_.back().hash_table_id;

  // 9. Set the sparse id
  sparse_id_ = value_offsets_.back().sparse_id;

  // 10. Set the sorted key offsets
  sorted_key_offsets_.resize(key_offsets_.size());
  for (size_t i = 0; i < key_offsets_.size(); ++i) {
    sorted_key_offsets_[i] = i;
  }

  // 11. Set the has_id_hash
  has_id_hash_ = value_offsets_.back().has_id_hash;

  // 12. Set the id_hash
  id_hash_ = value_offsets_.back().id_hash;

  // 13. Set the sort order
  sort_order_ = value_offsets_.back().sort_order;

  // 14. Set the row major
  row_major_ = value_offsets_.back().row_major;

  // 15. Set the num_values
  num_values_ = value_offsets_.back().num_values;

  // 16. Set the column id
  column_id_ = value_offsets_.back().column_id;

