static int cbs_av1_assemble_fragment(CodedBitstreamContet *contet,
                                     CodedBitstreamFragment *frag)
{
    AVCodecParameters *par = contet->par;
    uint8_t *data;
    size_t data_size;

    /* Calculate the size of the final data. */
    data_size = 0;
    for (int i = 0; i < frag->nb_units; i++) {
        CodedBitstreamUnit *unit = &frag->units[i];

        if (cbs_av1_unit_is_inde(unit))
            continue;

        if (unit->type == AV1_NAL_TRAIL_V)
            data_size += 2; // for the 2-byte end-of-packet marker

        data_size += unit->data_size;
    }

    /* Allocate a buffer for the data. */
    data = av_buffer_alloc(data_size + AV_INPUT_BUFFER_PADDING_SIZE);
    if (!data)
        return AVERROR(ENOMEM);

    /* Copy the data. */
    uint8_t *dst = data;
    for (int i = 0; i < frag->nb_units; i++) {
        CodedBitstreamUnit *unit = &frag->units[i];

        if (cbs_av1_unit_is_inde(unit))
            continue;

        if (unit->type == AV1_NAL_TRAIL_V) {
            /* NAL unit delimiters are not included in the payload, so there is
             * no need to copy any data from the previous unit. However, to
             * signal the end of the frame to the parser, two bytes are
             * appended to the data. */
            memcpy(dst, "\000\002", 2);
            dst += 2;
        }

        memcpy(dst, unit->data, unit->data_size);
        dst += unit->data_size;
    }

    /* Return the data. */
    frag->data = data;
    frag->data_size = data_size;

    return 0;
}

