	bin->java_cp_count = read_be16 (buf);
	if (bin->verbose) {
		eprintf ("[info] Loading %d cp entries\n", bin->java_cp_count);
	}
	if (bin->java_cp_count > 0) {
		bin->java_cp = calloc (bin->java_cp_count, sizeof (r_bin_java_cp_t));
		if (!bin->java_cp) {
			return 0;
		}
	}
	for (i = 0; i < bin->java_cp_count; i++) {
		r_bin_java_cp_t *cp = &bin->java_cp[i];
		ut8 tag = buf[id++];
		cp->type = tag;
		switch (tag) {
		case 1: // UTF8
			cp->str = malloc (sz - id + 1);
			if (!cp->str) {
				return 0;
			}
			memcpy (cp->str, buf + id, sz - id);
			cp->str[sz - id] = 0;
			id = sz + 1;
			break;
		case 3: // INTEGER
		case 4: // FLOAT
		case 5: // LONG
		case 6: // DOUBLE
		case 7: // CLASS
		case 8: // STRING
		case 9: // FIELDREF
		case 10: // METHODREF
		case 11: // INTERFACEMETHODREF
		case 12: // NAMEANDTYPE
			cp->val = read_be32 (&buf[id]);
			id += 4;
			break;
		default:
			eprintf ("[warn] Unknown tag %d\n", tag);
			return 0;
		}
	}
	// Redirect string id to point to the actual utf8 string id
	for (i = 0; i < bin->java_cp_count; i++) {
		r_bin_java_cp_t *cp = &bin->java_cp[i];
		if (cp->type == 8) { // STRING
			ut32 utf8_id = cp->val;
			cp->val = str_id++;
			bin->java_cp[utf8_id - 1].refcount++;
		}
	}
	return id;
