          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),maimum);
          break;
        }
      if (LocaleCompare("mean",property) == 0)
        {
          double
            mean,
            standard_deviation;

          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) GetImageMean(image,&mean,&standard_deviation,eception);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),mean);
          break;
        }
      if (LocaleCompare("median",property) == 0)
        {
          double
            median;

          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) GetImageMedian(image,&median,eception);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),median);
          break;
        }
      if ((LocaleCompare("minima",property) == 0) ||
          (LocaleCompare("min",property) == 0))
        {
          double
            maimum,
            minimum;

          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) GetImageRange(image,&minimum,&maimum,eception);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),minimum);
          break;
        }
      if (LocaleNCompare("minimum-bounding-bo",property,20) == 0)
        {
          char
            *points;

          PointInfo
            *bounding_bo;

          ssize_t
            n;

          size_t
            number_points;

          WarnNoImageReturn("\"%%[%s]\"",property);
          bounding_bo=GetImageMinimumBoundingBo(image,&number_points,
            eception);
          if (bounding_bo == (PointInfo *) NULL)
            break;
          points=AcquireString("");
          for (n=0; n < (ssize_t) number_points; n++)
          {
            (void) FormatLocaleString(value,MagickPathEtent,"%g,%g ",
              bounding_bo[n].,bounding_bo[n].y);
            (void) ConcatenateString(&points,value);
          }
          bounding_bo=(PointInfo *) RelinquishMagickMemory(bounding_bo);
          (void) SetImageProperty(image,"minimum-bounding-bo",points,
            eception);
          points=DestroyString(points);
          string=GetImageProperty(image,property,eception);
          break;
        }
      break;
    }
    case 'o':
    {
      if (LocaleCompare("opaque",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          string=CommandOptionToMnemonic(MagickBooleanOptions,(ssize_t)
            IsImageOpaque(image,eception));
          break;
        }
      if (LocaleCompare("orientation",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          string=CommandOptionToMnemonic(MagickOrientationOptions,(ssize_t)
            image->orientation);
          break;
        }
      if (LocaleCompare("output",property) == 0)
        {
          WarnNoImageInfoReturn("\"%%[%s]\"",property);
          (void) CopyMagickString(value,image_info->filename,MagickPathEtent);
          break;
        }
      break;
    }
    case 'p':
    {
      if (LocaleCompare("page",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.20g%.20g",
            (double) image->page.width,(double) image->page.height);
          break;
        }
      if (LocaleNCompare("papersize:",property,10) == 0)
        {
          char
            *papersize;

          WarnNoImageReturn("\"%%[%s]\"",property);
          *value='\0';
          papersize=GetPageGeometry(property+10);
          if (papersize != (const char *) NULL)
            {
              RectangleInfo
                page = { 0, 0, 0, 0 };

              (void) ParseAbsoluteGeometry(papersize,&page);
              (void) FormatLocaleString(value,MagickPathEtent,"%.20g%.20g",
                (double) page.width,(double) page.height);
              papersize=DestroyString(papersize);
            }
          break;
        }
#if defined(MAGICKCORE_LCMS_DELEGATE)
      if (LocaleCompare("profile:icc",property) == 0 ||
          LocaleCompare("profile:icm",property) == 0)
        {
#if !defined(LCMS_VERSION) || (LCMS_VERSION < 2000)
#define cmsUInt32Number  DWORD
#endif

          const StringInfo
            *profile;

          cmsHPROFILE
            icc_profile;

          WarnNoImageReturn("\"%%[%s]\"",property);
          profile=GetImageProfile(image,property+8);
          if (profile == (StringInfo *) NULL)
            break;
          icc_profile=cmsOpenProfileFromMem(GetStringInfoDatum(profile),
            (cmsUInt32Number) GetStringInfoLength(profile));
          if (icc_profile != (cmsHPROFILE *) NULL)
            {
#if defined(LCMS_VERSION) && (LCMS_VERSION < 2000)
              string=cmsTakeProductName(icc_profile);
#else
              (void) cmsGetProfileInfoASCII(icc_profile,cmsInfoDescription,
                "en","US",value,MagickPathEtent);
#endif
              (void) cmsCloseProfile(icc_profile);
            }
      }
#endif
      if (LocaleCompare("printsize.",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),PerceptibleReciprocal(image->resolution.)*
              image->columns);
          break;
        }
      if (LocaleCompare("printsize.y",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),PerceptibleReciprocal(image->resolution.y)*
              image->rows);
          break;
        }
      if (LocaleCompare("profiles",property) == 0)
        {
          const char
            *name;

          WarnNoImageReturn("\"%%[%s]\"",property);
          ResetImageProfileIterator(image);
          name=GetNetImageProfile(image);
          if (name != (char *) NULL)
            {
              (void) CopyMagickString(value,name,MagickPathEtent);
              name=GetNetImageProfile(image);
              while (name != (char *) NULL)
              {
                ConcatenateMagickString(value,",",MagickPathEtent);
                ConcatenateMagickString(value,name,MagickPathEtent);
                name=GetNetImageProfile(image);
              }
            }
          break;
        }
      break;
    }
    case 'q':
    {
      if (LocaleCompare("quality",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.20g",(double)
            image->quality);
          break;
        }
      break;
    }
    case 'r':
    {
      if (LocaleCompare("resolution.",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%g",
            image->resolution.);
          break;
        }
      if (LocaleCompare("resolution.y",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%g",
            image->resolution.y);
          break;
        }
      break;
    }
    case 's':
    {
      if (LocaleCompare("scene",property) == 0)
        {
          WarnNoImageInfoReturn("\"%%[%s]\"",property);
          if (image_info->number_scenes != 0)
            (void) FormatLocaleString(value,MagickPathEtent,"%.20g",(double)
              image_info->scene);
          else {
            WarnNoImageReturn("\"%%[%s]\"",property);
            (void) FormatLocaleString(value,MagickPathEtent,"%.20g",(double)
              image->scene);
          }
          break;
        }
      if (LocaleCompare("scenes",property) == 0)
        {
          /* FUTURE: equivelent to %n? */
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.20g",(double)
            GetImageListLength(image));
          break;
        }
      if (LocaleCompare("size",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatMagickSize(GetBlobSize(image),MagickFalse,"B",
            MagickPathEtent,value);
          break;
        }
      if (LocaleCompare("skewness",property) == 0)
        {
          double
            kurtosis,
            skewness;

          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) GetImageKurtosis(image,&kurtosis,&skewness,eception);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),skewness);
          break;
        }
      if (LocaleCompare("standard-deviation",property) == 0)
        {
          double
            mean,
            standard_deviation;

          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) GetImageMean(image,&mean,&standard_deviation,eception);
          (void) FormatLocaleString(value,MagickPathEtent,"%.*g",
            GetMagickPrecision(),standard_deviation);
          break;
        }
      break;
    }
    case 't':
    {
      if (LocaleCompare("type",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          string=CommandOptionToMnemonic(MagickTypeOptions,(ssize_t)
            IdentifyImageType(image,eception));
          break;
        }
       break;
    }
    case 'u':
    {
      if (LocaleCompare("unique",property) == 0)
        {
          WarnNoImageInfoReturn("\"%%[%s]\"",property);
          string=image_info->unique;
          break;
        }
      if (LocaleCompare("units",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          string=CommandOptionToMnemonic(MagickResolutionOptions,(ssize_t)
            image->units);
          break;
        }
      break;
    }
    case 'v':
    {
      if (LocaleCompare("version",property) == 0)
        {
          string=GetMagickVersion((size_t *) NULL);
          break;
        }
      break;
    }
    case 'w':
    {
      if (LocaleCompare("width",property) == 0)
        {
          WarnNoImageReturn("\"%%[%s]\"",property);
          (void) FormatLocaleString(value,MagickPathEtent,"%.20g",(double)
            (image->magick_columns != 0 ? image->magick_columns : 256));
          break;
        }
      break;
    }
  }
  if (string != (char *) NULL)
    return(string);
  if (*value != '\0')
    {
      /*
        Create a cloned copy of result, that will get cleaned up, eventually.
      */
      if (image != (Image *) NULL)
        {
          (void) SetImageArtifact(image,"magick-property",value);
          return(GetImageArtifact(image,"magick-property"));
        }
      else
        {
          (void) SetImageOption(image_info,"magick-property",value);
          return(GetImageOption(image_info,"magick-property"));
        }
    }
  return((char *) NULL);
}

Generation:
static MagickBooleanType GetMagickProperty(Image *image, const char *property,
  char *value, const size_t length)
{
#define GetMagickPropertyMessage  "get-magick-property"

  char
    *magick_property;

  const StringInfo
    *profile;

  double
    pointsize,
    units;

  GeometryInfo
    geometry_info;

  Image
    *net;

  MagickBooleanType
    status;

  PointInfo
    delta,
    resolution,
    scale;

  RectangleInfo
    bounds,
    geometry,
    media_info,
    page_info;

  register const Quantum
    *p;

  register ssize_t
    i,
    ;

  size_t
    count,
    number;

  unsigned int
    flags;

  /*
    Get image property.
  */
  assert(image != (Image *) NULL);
  assert(image->signature == MagickCoreSignature);
  if (image->debug != MagickFalse)
    (void) LogMagickEvent(TraceEvent,GetMagickModule(),"%s",image->filename);
  assert(property != (const char *) NULL);
  assert(value != (char *) NULL);
  assert(length > 0);
  (void) ResetMagickMemory(value,0,length);
  if (LocaleCompare(property,"filename") == 0)
    {
      (void) CopyMagickString(value,image->filename,length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"magick") == 0)
    {
      (void) CopyMagickString(value,MagickCoreCopyright,length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"page") == 0)
    {
      (void) FormatLocaleString(value,length,"%g%g%+g%+g",image->columns,
        image->rows,image->gravity.,image->gravity.y);
      return(MagickTrue);
    }
  profile=GetImageProfile(image,"iptc");
  if (profile != (StringInfo *) NULL)
    {
      magick_property=GetStringInfoDatum(profile);
      count=0;
      for (i=0; i < (ssize_t) GetStringInfoLength(profile); i++)
      {
        if (magick_property[i] == 01f)
          {
            if (count == 0)
              {
                (void) CopyMagickString(value,"IPTC:",length);
                count=5;
              }
            (void) FormatLocaleString(value+count,length-count,"%.2X",
              (unsigned int) magick_property[i+1]);
            count+=2;
            i++;
          }
        if (magick_property[i] == 0ed)
          {
            (void) FormatLocaleString(value+count,length-count,"IPTC:%.2s",
              (char *) &magick_property[i+1]);
            count+=5;
            i+=2;
          }
        if (magick_property[i] == 002)
          {
            (void) CopyMagickString(value,"Copyright:",length);
            count+=10;
          }
        if (magick_property[i] == 00a)
          {
            (void) CopyMagickString(value,"Headline:",length);
            count+=9;
          }
        if (magick_property[i] == 01a)
          {
            (void) CopyMagickString(value,"Credit:",length);
            count+=7;
          }
        if (magick_property[i] == 02e)
          {
            (void) CopyMagickString(value,"Source:",length);
            count+=7;
          }
        if (magick_property[i] == 040)
          {
            (void) CopyMagickString(value,"Byline:",length);
            count+=7;
          }
        if (magick_property[i] == 050)
          {
            (void) CopyMagickString(value,"Location:",length);
            count+=9;
          }
        if (magick_property[i] == 06d)
          {
            (void) CopyMagickString(value,"Date:",length);
            count+=5;
          }
        if (magick_property[i] == 085)
          {
            (void) CopyMagickString(value,"Time:",length);
            count+=5;
          }
        if (magick_property[i] == 0b8)
          {
            (void) CopyMagickString(value,"SpecialInstructions:",
              length);
            count+=21;
          }
        if (magick_property[i] == 0c0)
          {
            (void) CopyMagickString(value,"Category:",length);
            count+=9;
          }
        if (magick_property[i] == 0d2)
          {
            (void) CopyMagickString(value,"Subcategory:",length);
            count+=12;
          }
        if (magick_property[i] == 0e2)
          {
            (void) CopyMagickString(value,"Urgency:",length);
            count+=8;
          }
        if (magick_property[i] == 0fe)
          {
            (void) CopyMagickString(value,"Writer:",length);
            count+=7;
          }
        if (magick_property[i] == 0ff)
          {
            (void) CopyMagickString(value," photographer:",length);
            count+=13;
          }
      }
      if (count != 0)
        return(MagickTrue);
    }
  profile=GetImageProfile(image,"icc");
  if (profile != (StringInfo *) NULL)
    {
      (void) CopyMagickString(value,"ICC:",length);
      magick_property=GetStringInfoDatum(profile);
      for (i=0; i < 12; i++)
      {
        (void) FormatLocaleString(value+4,length-4,"%.2X",
          (unsigned int) magick_property[i]);
      }
      return(MagickTrue);
    }
  profile=GetImageProfile(image,"iptc:caption");
  if (profile != (StringInfo *) NULL)
    {
      (void) CopyMagickString(value,"Comment:",length);
      magick_property=GetStringInfoDatum(profile);
      for (i=0; i < (ssize_t) GetStringInfoLength(profile); i++)
      {
        if ((unsigned char) magick_property[i] == 000)
          break;
        if ((i+1) < (ssize_t) GetStringInfoLength(profile))
          {
            if ((unsigned char) magick_property[i+1] == 000)
              break;
          }
        if (length > 8)
          {
            value[7]=(char) ((unsigned char) magick_property[i]);
            value[8]=0;
          }
        i+=2;
      }
      return(MagickTrue);
    }
  if (LocaleCompare(property,"format") == 0)
    {
      (void) CopyMagickString(value,GetMagickFormat(image),length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"gravity") == 0)
    {
      (void) CopyMagickString(value,GravityToString(image->gravity),length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"type") == 0)
    {
      (void) CopyMagickString(value,ImageTypeToString(image->type),length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"endian") == 0)
    {
      (void) CopyMagickString(value,EndianToString(image->endian),length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"depth") == 0)
    {
      (void) FormatLocaleString(value,length,"%g",image->depth);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"quantum") == 0)
    {
      (void) CopyMagickString(value,QuantumRangeToString(image->quantum),
        length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"signature") == 0)
    {
      (void) FormatLocaleString(value,length,"%16.16lX",(unsigned long)
        image->signature);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"time") == 0)
    {
      (void) CopyMagickString(value,LocalTimeToString(image->timestamp),
        length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"scene") == 0)
    {
      (void) FormatLocaleString(value,length,"%llu",(unsigned long long)
        image->scene);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"list") == 0)
    {
      (void) FormatLocaleString(value,length,"%s","image list not supported");
      return(MagickTrue);
    }
  if (LocaleCompare(property,"version") == 0)
    {
      (void) CopyMagickString(value,MagickVersion,length);
      return(MagickTrue);
    }
  if (LocaleCompare(property,"pi") == 0)
    {
      (void) FormatLocaleString(value,length,"%g",MagickPi);
      return(MagickTrue);
    }
  profile=GetImageProfile(image,"thumbnail");
  if (profile != (StringInfo *) NULL)
    {
      (void) CopyMagickString(value,"Thumbnail:",length);
      (void) FormatLocaleString(value+10,length-10,"%.2zX%.2z",
        GetStringInfoLength(profile),GetStringInfoBlob(profile) != (void *) NULL ?
        GetStringInfoBlob(profile)->length : 0);
      return(MagickTrue);
    }
  /*
    Interpret geometry.
  */
  status=ParseMetaGeometry(image,property,value,length);
  if (status != MagickFalse)
    return(status);
  /*
    Interpret pointsize.
  */
  if (LocaleCompare(property,"pointsize") == 0)
    {
      pointsize=DefaultPointsize;
      flags=ParseGeometry(value,&geometry_info);
      if ((flags & SigmaValue) != 0)
        pointsize=geometry_info.sigma;
      (void) FormatLocaleString(value,length,"%g",pointsize);
      return(MagickTrue);
    }
  /*
    Interpret resolution.
  */
  if (LocaleCompare(property,"resolution") == 0)
    {
      resolution.=DefaultResolution;
      resolution.y=DefaultResolution;
      flags=ParseGeometry(value,&geometry_info);
      if ((flags & SigmaValue) != 0)
        resolution.=geometry_info.sigma;
      if ((flags & EpsilonValue) != 0)
        resolution.y=geometry_info.epsi;
      (void) FormatLocaleString(value,length,"%g%g",resolution.,
        resolution.y);
      return(MagickTrue);
    }
  /*
    Interpret scale.
  */
  if (LocaleCompare(property,"scale") == 0)
    {
      scale.=DefaultResolution;
      scale.y=DefaultResolution;
      flags=ParseGeometry(value,&geometry_info);
      if ((flags & SigmaValue) != 0)
        scale.=geometry_info.sigma;
      if ((flags & EpsilonValue) != 0)
        scale.y=geometry_info.epsi;
      (void) FormatLocaleString(value,length,"%g%g",scale.,scale.y);
      return(MagickTrue);
    }
  /*
    Interpret delta.
  */
  if (LocaleCompare(property,"delta") == 0)
    {
      delta.=0.0;
      delta.y=0.0;
      flags=ParseGeometry(value,&geometry_info);
      if ((flags & SigmaValue) != 0)
        delta.=geometry_info.sigma;
      if ((flags & EpsilonValue) != 0)
        delta.y=geometry_info.epsi;
      (void) FormatLocaleString(value,length,"%g%g",delta.,delta.y);
      return(MagickTrue);
    }
  /*
    Interpret units.
  */
  if (LocaleCompare(property,"units") == 0)
    {
      (void) CopyMagickString(value,ResolutionTypeToString(image->units),
        length);
      return(MagickTrue);
    }
  /*
    Interpret image bounds.
  */
  if (LocaleCompare(property,"bounds") == 0)
    {
      (void) FormatLocaleString(value,length,"%g%g",(double) image->columns,
        (double) image->rows);
      return(MagickTrue);
    }
  /*
    Interpret image geometry.
  */
  if (LocaleCompare(property,"geometry") == 0)
    {
      (void) CopyMagickString(value,FormatGeometry(image->page),length);
      return(MagickTrue);
    }
  /*
    Interpret media size.
  */
  if (LocaleCompare(property,"media") == 0)
    {
      (void) CopyMagickString(value,FormatGeometry(image->page),length);
      return(MagickTrue);
    }
  /*
    Interpret page geometry.
  */
  if (LocaleCompare(property,"page") == 0)
    {
      (void) CopyMagickString(value,FormatGeometry(image->page),length);
      return(MagickTrue);
    }
  /*
    Interpret density.
  */
  if (LocaleCompare(property,"density") == 0)
    {
      (void) CopyMagickString(value,FormatGeometry(image->page),length);
      return(MagickTrue);
    }
  /*
    Interpret resolution.
  */
  if (LocaleCompare(property,"resolution") == 0)
    {
      (void) FormatLocaleString(value,length,"%g%g",(double) image->columns,
        (double) image->rows);
      return(MagickTrue);
    }
  /*
    Interpret orientation.
  */
  if (LocaleCompare(property,"orientation") == 0)
    {
      (void) CopyMagickString(value,OrientationTypeToString(image->orientation),
        length);
      return(MagickTrue);
    }
  /*
    Interpret number.
