  if (LocaleCompare(property,"number") == 0)
    {
      net=image;
      if (image->previous != (Image *) NULL)
        {
          for (i=0; (ssize_t) i < image->scene; i++)
          {
            if (image->previous->scene != image->scene)
              break;
            image=image->previous;
          }
          net=image->previous;
        }
      if ((net != (Image *) NULL) &&
          (LocaleCompare(net->magick,"NET") == 0 ||
           LocaleCompare(net->magick,"PACKBITS") == 0 ||
