      return(MagickTrue);
    }
  /*
    Interpret opaque.
  */
  if (LocaleCompare(property,"opaque") == 0)
    {
      (void) FormatLocaleString(value,length,"%s",IsImageOpaque(image) ?
        "true":"false");
