    }
  /*
    Interpret progress.
  */
  if (LocaleCompare(property,"progress") == 0)
    {
      (void) FormatLocaleString(value,length,"%g",(double)
        (image->scene-progress));
      return(MagickTrue);
    }
  /*
    Interpret server.
  */
  if (LocaleCompare(property,"server") == 0)
    {
      (void) CopyMagickString(value,GetMagickHostName(),length);
      return(MagickTrue);
    }
  /*
    Interpret trait.
  */
  if (LocaleCompare(property,"trait") == 0)
    {
      (void) FormatLocaleString(value,length,"%.20g",(double) image->alpha_trait);
      return(MagickTrue);
