BOOL QueryServiceConfig(
    SC_HANDLE hService,          // handle to service
    LPQUERY_SERVICE_CONFIG lpsvcConfig, // buffer for service configuration
    DWORD cbBufSize,           // size of service configuration buffer
    LPDWORD lpcbBytesNeeded )   // number of bytes returned
{
    DWORD cbBytesNeeded;

    // Query the service config using the service control manager.
    if (!::QueryServiceConfig(hService,
                               NULL,
                               0,
                               &cbBytesNeeded))
    {
        if (GetLastError() != ERROR_INSUFFICIENT_BUFFER)
            return FALSE;
    }

    // If the supplied buffer is not large enough, return the
    // required buffer size.
    if (cbBufSize < cbBytesNeeded)
    {
        *lpcbBytesNeeded = cbBytesNeeded;
        return FALSE;
    }

    // Otherwise, get the service config.
    if (!::QueryServiceConfig(hService,
                               lpsvcConfig,
                               cbBufSize,
                               &cbBytesNeeded))
        return FALSE;

    // If the service name was not returned, put something
    // reasonable in the buffer.  This is for NT 3.51 and NT 4.0
    // where the service name is not returned.
    if (lpsvcConfig->lpServiceName[0] == L'\0')
    {
        DWORD dwDisplayName;
        // Try to get the display name.
        if (::QueryServiceConfig(hService,
                                 lpsvcConfig,
                                 cbBufSize,
                                 &cbBytesNeeded))
        {
            dwDisplayName = lpsvcConfig->dwDisplayNameLength;
            lpsvcConfig->dwDisplayNameLength = 0;
        }
        else
            dwDisplayName = 0;

        // If no display name, use the service name as the
        // name of the service.
        if (dwDisplayName == 0)
        {
            lpsvcConfig->lpServiceName[0] = L'\0';
            lpsvcConfig->dwServiceNameLength = 0;
        }
        else
        {
            // Convert the display name to a service name.
            if (!::GetServiceKeyName(NULL,
                                     lpsvcConfig->lpDisplayName,
                                     lpsvcConfig->lpServiceName,
                                     cbBufSize))
                return FALSE;

            lpsvcConfig->dwServiceNameLength = (DWORD)lstrlen(lpsvcConfig->lpServiceName);
        }
    }

    return TRUE;
}   // QueryServiceConfig

