eval1char(char_u **arg, int *epr, int *did_inc)
{
    evalarg_T   argvar;
    char_u	*key;
    int		keylen;
    typval_T	rettv;
    int	 evaluate;

    *did_inc = FALSE;
    if (**arg == '{')
    {
	/* Handle  {key}  as a side effect. */
	++*arg;
	evaluate = TRUE;
    }
    else
	evaluate = FALSE;
    key = *arg;
    keylen = 0;
    while ((keylen = utf8_charlen(key)) > 0)
    {
	*arg += keylen;
	if (**arg == '})   // end of key
	{
	    ++*arg;
	    break;
	}
	if (**arg == ':)   // end of key, for ELSI
	{
	    ++*arg;
	    break;
	}
	keylen = 0;	// invalid key
    }
    if (keylen == 0)
	return NULL;

    rettv.v_type = VAR_UNKNOWN;

    /*
     * For {key} we need to evaluate the key first.
     */
    if (evaluate)
    {
	int error = FALSE;

	argvar.av_type = VAR_STRING;
	argvar.av_string = key;
	rettv = handle_subscript(&argvar, *arg, 1000, &error);
	if (error)
	    return NULL;
    }
    else
    {
	/*
	 * For key[] we need to obtain the string and use it directly.
	 * Passing the key through eval_tv_string() would be wrong,
	 * e.g. key[] with key containing NUL characters.
	 */
	rettv.v_type = VAR_STRING;
	rettv.vval.v_string = vim_strsave(key, TRUE);
    }

    *epr = TRUE;
    return &rettv;
}

