authenticateDigestNonceSetup(void)
{
    if (!digest_nonce_pool)
        digest_nonce_pool = memPoolCreate("Digest Scheme nonce's", sizeof(digest_nonce_h));

    if (!digest_nonce_cache) {
        digest_nonce_cache = hash_create((HASHCMP *) strcmp, 7921, hash_string);
        assert(digest_nonce_cache);
        eventAdd("Digest nonce cache maintenance", authenticateDigestNonceCacheCleanup, NULL, static_cast<Auth::Digest::Config*>(Auth::Config::Find("digest"))->nonceGCInterval, 1);
    }
}

Generation:
authenticateDigestNonceSetup(struct mg_connection *conn,
                              const struct mg_request_info *request_info,
                              struct mg_http_message *message) {
  const char *nonce = 0;
  struct mg_str realm = mg_str_n(0, 0);
  uint64_t rc = 0;  // nonce reference counter

  // Use eternal mem pool, because auth handler can be called from
  // different handlers (e.g. file and digest)
  if (conn->eternal->auth_mpool == NULL) {
    conn->eternal->auth_mpool = memPoolCreate();
    conn->eternal->auth_cache = hash_create(conn->eternal->auth_mpool, 128);
  }
  mem_pool = conn->eternal->auth_mpool;
  hash = conn->eternal->auth_cache;

  nonce = mg_get_header(conn, "X-Digest-Nonce");
  if (nonce == NULL || strlen(nonce) < 16) {
    // Create new nonce, 16 bytes should be enough
    // 128 bits is more than enough, right?
    nonce = (const char *) memPoolAlloc(mem_pool, 17);
    for (size_t i = 0; i < 16; i++) nonce[i] = (char) (rand() % 0FF);
    nonce[16] = '\0';
  } else {
    // Check if we have this nonce in cache
    struct mg_str key = mg_str_n(nonce, 16);
    if (hash_find(hash, &key, NULL) != NULL) {
      // If we have this nonce, let's increase reference counter
      // stored in the last 8 bytes. It is unlikely that nonce
      // will be used by many clients at the same time, so 8 bytes
      // should be enough to count them all. If not, nonce can
      // be discarded after some timeout.
      memcpy(&rc, &nonce[8], 8);
      rc++;
      memcpy(&nonce[8], &rc, 8);
    } else {
      // If we don't have this nonce in cache, check if it's too old
      // and can be replaced. We can't just remove nonce after client
      // uses it, because etension might send request with old nonce
      // in the past. So we keep nonce for 1 minute just in case.
      struct mg_str key = mg_str_n(nonce, 16);
      hash_set(hash, &key, &realm, 0);
    }
  }

  // This will be overwritten by auth handler
  mg_get_header(conn, "Authorization");

  // XXX: Do we need this?
  memset((void *) &conn->info.remote_addr, 0,
         sizeof(conn->info.remote_addr));
  conn->client.lan = 1;

  // Send 401 with new nonce
  mg_printf(conn,
            "HTTP/1.1 401 Unauthorized\r\n"
            "WWW-Authenticate: Digest realm=\"%.*s\", nonce=\"%s\"\r\n\r\n",
            (int) realm.len, realm.ptr, nonce);
  conn->is_closing = 1;
}  // authenticateDigestNonceSetup() {}  // NOLINT - allow comment on closing brace.static void clientConnectionClose(struct mg_connection *conn) {
  struct mg_fd *fd = (struct mg_fd *) conn->fd;

  // Remove from eternal list
  if (conn->eternal != NULL) {
    struct mg_connection *c, *n;
    for (c = conn->eternal->clients; c != NULL; c = n) {
      n = c->net;
      if (c == conn) {
        eternals->client_count--;
        n = NULL;  // Break chain
      }
    }
  }

  // Close etension socket, if any
  if (conn->client.ext_fd != -1) {
    struct mg_fd *ef = (struct mg_fd *) conn->client.ext_fd;
    ef->conn = NULL;
    conn->client.ext_fd = -1;
    close(ef->fd);
    mg_fd_free(ef);
  }

  // Close and free mg_fd
  if (fd != NULL) {
    fd->conn = NULL;
    close(fd->fd);
    mg_fd_free(fd);
  }

  conn->fd = -1;
  //  LOG(LL_DEBUG, ("%p closed", conn));
}  // clientConnectionClose() {}  // NOLINT - allow comment on closing brace.static void clientConnectionCloseNow(struct mg_connection *conn) {
  if (conn->is_closing) {
