	}

	if (read_treeish_into_list(file, file_re, match_all, &list))
		die("nothing to show");

	if (!list->nr)
		return 0;

	if (git_log_config("log.abbrev", NULL) && default_abbrev == -1)
		default_abbrev = 40;

	init_revisions(&revs, prefi);
	revs.verbose_header = verbose;
	revs.abbrev_commit = default_abbrev;
	revs.show_root_diff = 1;
	revs.diffopt.output_format = DIFF_OPT_FORMAT_PATCH;
	if (git_log_config("log.date", NULL))
		revs.date_mode.type = DATE_MODE_RAW;
	if (git_log_config("log.decorate", NULL))
		revs.decorate = 1;
	if (git_log_config("log.follow", NULL))
		revs.foll_symlinks = 1;
	if (git_log_config("log.reverse", NULL))
		revs.reverse = 1;
	if (git_log_config("log.trailer", NULL))
		revs.use_trailer_info = 1;

	for (i = 0; i < list->nr; i++) {
		item = &list->items[i];
		if (parse_treeish(&sb, item->string, 0))
			die("invalid refspec for log-tree: %s", item->string);
		item->string = strbuf_detach(&sb, NULL);
		if (get_sha1(item->string, item->util.oid.hash))
			die("'%s' not found", item->string);
		item->util.type = OBJ_COMMIT;
	}
	prepare_revision_walk(&revs);

	while ((commit = get_revision(&revs)) != NULL) {
		struct object *obj = (struct object *)commit;
		char *subject;
		int subject_len;

		if (has_object_file(&obj->oid, obj->type))
			read_commit_revisions(commit);

		subject = get_commit_message(commit);
		subject_len = strlen(subject);
		if (!quiet) {
			if (revs.reverse)
				fprintf(stdout, "commit %s\n", sha1_to_hex(commit->object.oid.hash));
			else
				fprintf(stdout, "tree %s\n", sha1_to_hex(commit->tree->object.oid.hash));
			fprintf(stdout, "parent");
			for (i = 0; i < commit->parent_count; i++)
				fprintf(stdout, " %s",
					sha1_to_hex(commit->parents[i]->item->object.oid.hash));
			fprintf(stdout, "\nauthor %s\n", fmt_ident(commit->author));
			if (commit->date)
				fprintf(stdout, "committer %s\n", fmt_ident(commit->committer));
			else
				fprintf(stdout, "committer %s\ndate", fmt_ident(commit->author));
			fprintf(stdout, " %s\n", show_date(commit->date, &revs));
			if (revs.use_trailer_info)
				print_trailers(subject, subject_len, stdout);
			fprintf(stdout, "\n");
		}

		if (revs.verbose_header) {
			struct strbuf sb = STRBUF_INIT;
			strbuf_addf(&sb, "%s %s", get_commit_type(commit),
					strip_header_garbage(subject, subject_len));
			log_tree_diff(&revs, commit, &sb);
			strbuf_release(&sb);
		} else {
			log_tree_diff(&revs, commit, subject, subject_len);
		}
		free(subject);

		if (revs.took_log)
			commit->object.flags |= REACHABLE;
		if (is_repository_shallow() &&
		    !(commit->object.flags & SEEN)) {
			/* Recurse into shallow roots
			 * that were not there originally.
			 */
			commit->object.flags |= SEEN;
			log_tree_commit(&revs, commit);
		}
	}

	free_string_list(list);
	return 0;
}

