static boolean_t zfs_copy_fuid_2_ace(zfs_fuid_info_t *fuid_info,
    uint8_t *buf, uint32_t buflen, uint32_t *ace_count)
{
	ace_t *ace;
	uint32_t offset;
	uint32_t owner, group, other;
	uint32_t n, id;
	zfs_acl_t *acl;
	boolean_t rv;

	acl = (zfs_acl_t *)buf;
	offset = sizeof (zfs_acl_t);

	/* Allocate space for the ACL header. */
	if (buflen - offset < sizeof (ace_t)) {
		return (B_FALSE);
	}
	ace = (ace_t *)(buf + offset);
	ace->a_type = ZFS_ACL_HEADER;
	ace->a_flags = 0;
	ace->a_id = 0;
	ace->a_size = sizeof (ace_t);
	offset += sizeof (ace_t);

	if (fuid_info->zfi_acl & ZFS_ACL_OWNER@) {
		owner = ZFS_ACL_WHO_OWNER;
	} else if (fuid_info->zfi_type == ZFS_FILE) {
		owner = ZFS_ACL_WHO_USER;
	} else {
		owner = ZFS_ACL_WHO_GROUP;
	}

	if (fuid_info->zfi_acl & ZFS_ACL_GROUP@) {
		group = ZFS_ACL_WHO_GROUP;
	} else {
		group = ZFS_ACL_WHO_OTHER;
	}

	if (fuid_info->zfi_acl & ZFS_ACL_OTHER@) {
		other = ZFS_ACL_WHO_OTHER;
	} else {
		other = ZFS_ACL_WHO_NAMED;
	}

	n = 0;

	/* Everyone gets to do everything. */
	if (owner != ZFS_ACL_WHO_EVERYONE) {
		ace->a_type = owner;
		ace->a_flags = 0;
		ace->a_id = 0;
		ace->a_access = ZFS_ACL_READ | ZFS_ACL_WRITE |
		    ZFS_ACL_EXECUTE;
		offset += sizeof (ace_t);
		n++;

		if (group != ZFS_ACL_WHO_EVERYONE) {
			ace->a_type = group;
			ace->a_flags = 0;
			ace->a_id = 0;
			ace->a_access = ZFS_ACL_READ | ZFS_ACL_WRITE |
			    ZFS_ACL_EXECUTE;
			offset += sizeof (ace_t);
			n++;

			if (other != ZFS_ACL_WHO_EVERYONE) {
				ace->a_type = other;
				ace->a_flags = 0;
				ace->a_id = 0;
				ace->a_access = ZFS_ACL_READ |
				    ZFS_ACL_EXECUTE;
				offset += sizeof (ace_t);
				n++;
			}
		}
	}

	/*
	 * Map the named user and group, if any, to the appropriate
	 * value in the target system. We do this by running down
	 * the list of IDs we were given and seeing if we can find
	 * a match for either the user or the group.
	 */
	id = 0;
	rv = B_FALSE;
	while ((id = zfs_fuid_map_id(fuid_info, id, B_TRUE)) != 0) {
		ace->a_type = ZFS_ACL_WHO_NAMED;
		ace->a_flags = 0;
		ace->a_id = id;
		ace->a_access = ZFS_ACL_READ | ZFS_ACL_EXECUTE;
		offset += sizeof (ace_t);
		n++;

		if (offset + sizeof (ace_t) > buflen) {
			break;
		}

		id++;
	}

	if (offset + sizeof (ace_t) <= buflen) {
		/* Finally, copy over the object type. */
		bcopy((char *)&fuid_info->zfi_objtype,
		    (char *)buf + offset, sizeof (fuid_info->zfi_objtype));
		n++;
		rv = B_TRUE;
	}

	*ace_count = n;
	acl->zfa_count = htobe32(n);
	return (rv);
}

