void CodeGenerator::visitTryCatchFinallyNode(TryCatchFinallyNode* node)
{
    Node* tryBlock = node->tryBlock();
    Vector<Label*, 8> catchLabels;
    Vector<ExceptionHandler*, 8> handlers;
    Label* endOfTryBlock = newLabel();
    Label* endOfTryStatement = newLabel();

    // Emit code for the try block, and then jump to the finally block.
    // We don't emit the finally block until after the catch blocks.
    emitNode(tryBlock);
    jump(endOfTryBlock);

    // For each catch block, emit a label, then the catch block,
    // and then a jump to the finally block.
    for (unsigned i = 0; i < node->catchBlockCount(); ++i) {
        CatchBlockNode* catchBlock = node->catchBlock(i);
        catchLabels.append(newLabel());
        addExceptionHandler(
            ExceptionHandler(catchBlock->parameter(), catchBlock->handler(), catchLabels[i]));
        emitLabel(catchLabels[i]);
        emitNode(catchBlock);
        jump(endOfTryStatement);
    }

    // Emit the finally block, if it eists.
    if (node->finallyBlock()) {
        // The finally block is responsible for jumping to the end of the
        // try statement. It may do so conditionally, so we use a label
        // to represent the end of the finally block itself.
        Label* endOfFinallyBlock = newLabel();
        emitNode(node->finallyBlock());
        jump(endOfFinallyBlock);
        emitLabel(endOfFinallyBlock);
    }

    // Emit labels to represent the ends of the try block and the try
    // statement. The try block label is used to suppress exception
    // handling for code in the try block itself. The try statement
    // label is used by the finally block to ensure that it runs to
    // completion.
    emitLabel(endOfTryBlock);
    m_code.add(OpcodeInfo::get(op_endtry));
    for (unsigned i = 0; i < catchLabels.size(); ++i) {
        m_code.addJump(catchLabels[i]);
    }
    emitLabel(endOfTryStatement);

    // The exception handler for a try/catch/finally statement is responsible
    // for unwinding the stack, so it must be added after the finally block
    // is emitted. The catch blocks themselves are responsible for catching
    // exceptions, so their handlers are added when the catch blocks are
    // emitted.
    addExceptionHandler(ExceptionHandler(node->exceptionParameter(), this, endOfTryBlock));

    // Restore the state of the finally block register and the catch block
    // register to their values prior to entry into this try/catch/finally
    // statement. If there is no enclosing try/catch/finally statement, then
    // both registers are empty, and this operation has the net effect of
    // discarding information about any currently active catch blocks.
    m_code.add(OpcodeInfo::get(op_rethrow));
}

