static bool init_keys(void)
{
	if (prepare_key_area() < 0)
		return false;

	/* Generate and store the keys in the .data..rodata MTE tag range */
	bin_key = (u8 *)data_area + sizeof(data_area);
	nonce_key = bin_key + KEY_SIZE;
	hkdf_key = nonce_key + KEY_SIZE;

	get_random_bytes(bin_key, KEY_SIZE);
	get_random_bytes(nonce_key, KEY_SIZE);
	get_random_bytes(hkdf_key, KEY_SIZE);

	return true;
}

