  CHECK_STATUS;
  CHECK_ARG(0, napi_number, "number");

  napi_value result;
  double time;
  status = napi_get_value_double(env, args[0], &time);
  CHECK_STATUS;
  status = napi_create_date(env, time, &result);
  CHECK_STATUS;

  return napi_set_result(env, info, result);
