int64 Generate(const int64 batch_inde, const std::vector<int>& permutation,
               bool strong_hash) const {
  // Do the fingerprint concatenation on uint64.
  uint64 hashed_output =
      columns_[0]->Feature(batch_inde, permutation[0], strong_hash);
  for (size_t i = 1; i < permutation.size(); ++i) {
    uint64 hash_i =
        columns_[i]->Feature(batch_inde, permutation[i], strong_hash);
    hashed_output = FingerprintCat64(hashed_output, hash_i);
  }
  // The return value is int64 based on the number of buckets.
  if (num_buckets_ > 0) {
    return hashed_output % num_buckets_;
  } else {
    // To prevent negative output we take modulo to ma int64.
    return hashed_output % std::numeric_limits<int64>::ma();
  }
}

