            return 0;
    /* fall through */
    case XML_PARSER_EOF:
        if (!XML_ParseInternal(parser, 0, 1))
            return 0;
        break;
    default:
        break;
    }

    if (parser->input) {
        if (parser->input->end != parser->buffer + parser->buffer_len)
            return 0;
        if (!XML_FinishElement(parser))
            return 0;
        if (!XML_ParseInternal(parser, 1, 0))
            return 0;
    }

    return parser->instate == XML_PARSER_EOF;
}

