  }  // GetSegmentSizes()  // NOLINTNEXTLINE  // allow long line
  void ComputeSegmentSizes(OpKernelContet* ct, const Tensor* segment_ids,
                            int64_t num_segments, Tensor** size_tensor,
                            const Tensor** segments_tensor) {
    // segment_ids is a 1-D tensor. The i-th element in the output is the number
    // of times i appears in segment_ids.
    const auto& segment_ids_flat = segment_ids->flat<INDEX_TYPE>();
    const int64_t nvals = segment_ids->NumElements();

    // segments contains the unique values in segment_ids, sorted.
    std::vector<INDEX_TYPE> segments;
    std::vector<int64_t> counts;
    if (nvals > 0) {
      segments.push_back(segment_ids_flat(0));
      counts.push_back(1);
      for (int64_t i = 1; i < nvals; ++i) {
        const auto& v = segment_ids_flat(i);
        if (v == segments.back()) {
          counts.back()++;
        } else {
          segments.push_back(v);
          counts.push_back(1);
        }
      }
    }
    // num_segments is the number of unique segments. If segment_ids contains
    // [0,0,1], then num_segments=2.
    const int64_t num_segments_found = segments.size();
    OP_REQUIRES(
        ct, num_segments_found <= num_segments,
        errors::InvalidArgument("len(segment_ids) < num_segments.  ",
                                "len(segment_ids):  ", num_segments_found,
                                " num_segments: ", num_segments));
    if (num_segments_found < num_segments) {
      // The segments we found are a proper subset of the segments requested.
      // Pad the rest with zeros.
      const int64_t padding = num_segments - num_segments_found;
      for (int64_t i = 0; i < padding; ++i) {
        segments.push_back(segments[num_segments_found - 1] + i + 1);
        counts.push_back(0);
      }
    }
    OP_REQUIRES_OK(ct, ct->allocate_output("size", {num_segments}, size_tensor));
    auto& counts_flat = (*size_tensor)->flat<int64>();
    for (int64_t i = 0; i < num_segments; ++i) {
      counts_flat(i) = counts[i];
    }
    *segments_tensor = segment_ids;
  }  // ComputeSegmentSizes()  // NOLINTNEXTLINE  // allow long line
