                                           true /* return_inverse */));
    // inverse_indices now contains the inverse permuation that would sort the
    // input tensor. We want to keep only the elements that match 'value'.
    const auto& inverse_indices_flat = inverse_indices->flat<INDEX_TYPE>();
    const int64_t nvals = inverse_indices->NumElements();
    int64_t num_matches = 0;
    const auto& value_flat = value->flat<VALUE_TYPE>();
    for (int64_t i = 0; i < nvals; ++i) {
      if (inverse_indices_flat(i) < 0) continue;
      if (value_flat(inverse_indices_flat(i)) == value_flat(0)) {
        num_matches++;
