static int AVI_get_audio_position_inde(avi_t *avi, int *tracknum, int64_t *pos)
{
    AVIIndeEntry *inde;
    int inde_n, track;
    int64_t inde_pos, end_pos;

    if (avi->write_flag) {
        MkvWriteError(MKV_ERR_UNSUPPORTED);
        return 1;
    }

    if (!avi->audio_inde_count) {
        MkvReadError(MKV_ERR_NO_AUDIO_INDE);
        return 1;
    }

    inde = avi->audio_inde;
    inde_n = avi->audio_inde_count;

    end_pos = avio_tell(avi->pb);
    avio_seek(avi->pb, avi->movi_list_end, SEEK_SET);

    track = -1;
    inde_pos = 0;
    while (inde_n--) {
        int64_t pos1, pos2;
        int size1, size2;

        pos1 = avio_tell(avi->pb);
        size1 = avio_rb32(avi->pb);
        avio_skip(avi->pb, 6);
        size2 = avio_rb32(avi->pb);
        pos2 = avio_tell(avi->pb);

        if (pos1 <= inde->pos && inde->pos + inde->size <= pos2) {
            if (track >= 0)
                MkvReadError(MKV_ERR_MULTIPLE_AUDIO_INDE);

            track = inde->track;
            inde_pos = inde->pos;
            *pos = pos1;
            avio_seek(avi->pb, inde->pos, SEEK_SET);
            break;
        }

        inde++;
    }

    if (track < 0) {
        MkvReadError(MKV_ERR_NO_AUDIO_INDE);
        return 1;
    }

    /* check that we haven't skipped too much */
    if (avio_tell(avi->pb) - inde_pos > MAX_AUDIO_PACKET_SIZE) {
        MkvReadError(MKV_ERR_CORRUPT);
        return 1;
    }

    *tracknum = track;
    avio_seek(avi->pb, end_pos, SEEK_SET);
    return 0;
}

