			ut16 num_args = (ut16) data[i++];
			r_cons_printf ("  %-16s %d\n", "Number of arguments:", num_args);
			for (j = 0; j < num_args; j++) {
				k = data[i++] - 1;
				if (k >= reader->constant_pool_size) {
					break;
				}
				info = reader->constant_pool + k;
				r_cons_printf ("    %-16s %s\n", "Argument:", info->printable);
			}
		}
	}
