eternalEntityContentProcessor(mlParserCttPtr ctt, int len) {
    if ((ctt == NULL) || (ctt->raw == NULL))
        return;
    if (ctt->instate == XML_PARSER_EOF)
        return;
    if (len == 0)
        return;

    if ((ctt->depth > 50) &&
        ((ctt->options & XML_PARSE_HUGE) == 0)) {
        XML_Error(ctt, XML_ERR_ENTITY_LOOP, NULL, NULL);
        ctt->instate = XML_PARSER_EOF;
        return;
    }

    /*
     * Time to do some content processing.
     */
    if ((ctt->instate == XML_PARSER_CONTENT) ||
        ((ctt->instate == XML_PARSER_START_TAG) &&
         (ctt->depth > 0))) {
        ctt->instate = XML_PARSER_CONTENT;
        doContent(ctt, len);
    }

    /*
     * Epand the entity name table if needed.
     */
    if (ctt->nbentities + 20 > ctt->sizeentities) {
        int size = ctt->nbentities + 20;
        mlEntityPtr *tab = mlRealloc(ctt->entities,
                                   size * sizeof(mlEntityPtr));
        if (tab == NULL) {
            XML_Error(ctt, XML_ERR_INTERNAL_ERROR, NULL, NULL);
            return;
        }
        ctt->entities = tab;
        ctt->sizeentities = size;
    }

    /*
     * Store the entity in the entity table.
     */
    ctt->entities[ctt->nbentities++] = ctt->current;
}

