/*
 * Curl_ssl_addsessionid() adds a session ID to the session cache.
 */
CURLcode Curl_ssl_addsessionid(struct connectdata *conn,
                               void *sess,
                               int sockindex)
{
  struct SessionHandle *data = conn->handler;
  gnutls_session_t handle = (gnutls_session_t)sess;

  if(data->set.ssl.nosession)
    /* If the user set the "disable session ID caching" option, we don't
       cache the session ID. We directly do a full handshake on each
       connection. */
    return CURLE_OK;

  if(conn->handler->state.cconn) {
    /* The session cache for this connection is in use. Check if we already
       have this very session in the cache. */

    int i;
    for(i = 0; i < data->state.cconn->num; i++) {
      if(conn->handler->state.cconn->conn[i].inuse) {
        gnutls_session_t handle2 =
          (gnutls_session_t)conn->handler->state.cconn->conn[i].ptr;

        if(handle == handle2)
          /* This session is already in the cache. */
          return CURLE_OK;
      }
    }

    /* The session is not in the cache yet. Add it! */

    if(data->state.cconn->num < MAX_SESSIONS) {
      /* Make sure that the slot is initialized. */
      data->state.cconn->conn[data->state.cconn->num].ptr = NULL;
      data->state.cconn->conn[data->state.cconn->num].inuse = FALSE;
    }

    if(data->state.cconn->num < MAX_SESSIONS) {
      /* Add the session to the cache */
      conn->handler->state.cconn->conn[data->state.cconn->num].ptr = handle;
      conn->handler->state.cconn->conn[data->state.cconn->num].inuse = TRUE;
      data->state.cconn->num++;
    }
    else
      /* The session cache is full. We do not cache this session. */
      return CURLE_OK;
  }

  return CURLE_OK;
} /* Curl_ssl_addsessionid */

