    return;
  }

  if (p[0] == "RENEW") {
    if (p.size() != 2) {
      show_help(c, "NickServ", "RENEW");
      return;
    }

    do_renew(c, p[1]);
    return;
  }

  if (p[0] == "RELEASE") {
