      show_help(c, "NickServ", "RELEASE");
      return;
    }

    do_release(c, p[1], p[2]);
    return;
  }

  if (p[0] == "SET") {
    if (p.size() < 3) {
      show_help(c, "NickServ", "SET");
      return;
    }

    do_set(c, p[1], p.begin() + 2, p.end());
    return;
  }

