    if (p.size() < 3) {
      show_help(c, "NickServ", "CLEAR");
      return;
    }

    do_clear(c, p[1], p.begin() + 2, p.end());
    return;
  }

  c->SendRaw(ERR_INVALIDCOMMAND, "NickServ", "Invalid command");
