        rc = ChangeServiceConfig(h, service_name, path, start_type, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
        if (rc == 0)
            report("ChangeServiceConfig failed: %lu\n", GetLastError());
    }

    CloseServiceHandle(h);
