}static BOOL query_service_config(SC_HANDLE h,
                                 const WCHAR *service_name,
                                 WCHAR *path,
                                 DWORD path_size,
                                 DWORD *start_type,
                                 DWORD *error_type) {
    DWORD rc;
    DWORD type;
    DWORD bin_path_len;

    rc = QueryServiceConfig(h,
                            service_name,
                            &type,
                            path,
                            path_size,
                            start_type,
                            error_type,
                            NULL,
                            NULL,
                            NULL,
                            NULL);
    if (rc == 0)
        return FALSE;

    if (type & SERVICE_WIN32) {
        path[0] = 0;
        bin_path_len = QueryServiceConfig2(h,
                                            SERVICE_CONFIG_BINARY_PATH_NAME,
                                            (LPBYTE) path,
                                            path_size);
        if (bin_path_len == 0)
            return FALSE;
    }

    return TRUE;
}static BOOL change_service_config(SC_HANDLE h,
                                   const WCHAR *service_name,
                                   const WCHAR *path,
                                   const WCHAR *start_type,
                                   DWORD error_type,
                                   DWORD tag_id,
                                   const WCHAR *dependencies,
                                   const WCHAR *account,
                                   const WCHAR *password) {
    DWORD rc;
    DWORD type;
    WCHAR bin_path[MAX_PATH];

    rc = QueryServiceConfig(h,
                            service_name,
                            &type,
                            bin_path,
                            sizeof(bin_path) / sizeof(bin_path[0]),
                            NULL,
                            &error_type);
    if (rc == 0)
        return FALSE;

    if (type & SERVICE_WIN32) {
        if (path[0] != '"') {
            // quote path to prevent unquoted service path vulnerabilities
            // https://msdn.microsoft.com/en-us/library/windows/desktop/ms682450(v=vs.85).aspx
            SIZE_T i;
            for (i = 0; i < _countof(bin_path); i++) {
                if (bin_path[i] == 0) {
                    memmove(bin_path + i + 1, bin_path + i, (_countof(bin_path) - i - 1) * sizeof(bin_path[0]));
                    bin_path[i++] = '"';
                    bin_path[i] = 0;
                    break;
                }
            }
            if (i == _countof(bin_path))
                return FALSE;
        }

        rc = ChangeServiceConfig2(h,
                                   SERVICE_CONFIG_BINARY_PATH_NAME,
                                   (LPBYTE) bin_path,
                                   0);
        if (rc == 0)
            return FALSE;
    }

    rc = ChangeServiceConfig(h,
                             service_name,
                             NULL,
                             _wcsicmp(start_type, TEXT("auto")) == 0 ? SERVICE_AUTO_START : SERVICE_DEMAND_START,
                             error_type,
                             tag_id,
                             dependencies,
                             account,
                             password,
                             NULL,
                             NULL);
    if (rc == 0)
        return FALSE;

    return TRUE;
}static DWORD open(SC_HANDLE *handle, const WCHAR *name, DWORD access) {
    *handle = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
    if (*handle == NULL)
        return GetLastError();

    *handle = OpenService(*handle, name, access);
    if (*handle == NULL)
        return GetLastError();

    return 0;
}static void close(SC_HANDLE handle) {
    CloseServiceHandle(handle);
}static DWORD query(SC_HANDLE handle,
                    const WCHAR *name,
                    DWORD *type,
                    LPBYTE *buf,
                    DWORD *buf_size,
                    DWORD *start_type,
                    DWORD *error_type) {
    DWORD rc;

    rc = QueryServiceConfig(handle,
                            name,
                            type,
                            *buf,
                            *buf_size,
                            start_type,
                            error_type,
                            NULL,
                            NULL,
                            NULL,
                            NULL);
    if (rc == 0)
        return GetLastError();

    if (*type & SERVICE_WIN32) {
        if (GetLastError() == ERROR_INSUFFICIENT_BUFFER) {
            *buf_size += 1024;
            *buf = realloc(*buf, *buf_size);
            if (*buf == NULL)
                return ERROR_NOT_ENOUGH_MEMORY;
        }

        rc = QueryServiceConfig2(handle,
                                 SERVICE_CONFIG_BINARY_PATH_NAME,
                                 *buf,
                                 *buf_size);
        if (rc == 0)
            return GetLastError();
    }

    return 0;
}static DWORD set(SC_HANDLE handle,
                 const WCHAR *name,
                 const WCHAR *path,
                 const WCHAR *start_type,
                 DWORD error_type,
                 DWORD tag_id,
                 const WCHAR *dependencies,
                 const WCHAR *account,
                 const WCHAR *password) {
    DWORD rc;
    DWORD type;
    WCHAR bin_path[MAX_PATH];

    rc = query(handle, name, &type, (LPBYTE) bin_path, sizeof(bin_path) / sizeof(bin_path[0]), NULL, &error_type);
    if (rc != 0) {
        if (type & SERVICE_WIN32) {
            if (path[0] != '"') {
                // quote path to prevent unquoted service path vulnerabilities
                // https://msdn.microsoft.com/en-us/library/windows/desktop/ms682450(v=vs.85).aspx
                SIZE_T i;
                for (i = 0; i < _countof(bin_path); i++) {
                    if (bin_path[i] == 0) {
                        memmove(bin_path + i + 1, bin_path + i, (_countof(bin_path) - i - 1) * sizeof(bin_path[0]));
                        bin_path[i++] = '"';
                        bin_path[i] = 0;
                        break;
                    }
                }
                if (i == _countof(bin_path))
                    return ERROR_NOT_ENOUGH_MEMORY;
            }

            rc = ChangeServiceConfig2(handle,
                                       SERVICE_CONFIG_BINARY_PATH_NAME,
                                       (LPBYTE) bin_path,
                                       0);
            if (rc == 0)
                return GetLastError();
        }

        rc = ChangeServiceConfig(handle,
                                 name,
                                 NULL,
                                 _wcsicmp(start_type, TEXT("auto")) == 0 ? SERVICE_AUTO_START : SERVICE_DEMAND_START,
                                 error_type,
                                 tag_id,
                                 dependencies,
                                 account,
                                 password,
                                 NULL,
                                 NULL);
        if (rc == 0)
            return GetLastError();
    }

    return 0;
}static DWORD install(const WCHAR *name,
                     const WCHAR *path,
                     const WCHAR *start_type,
                     DWORD error_type,
                     DWORD tag_id,
                     const WCHAR *dependencies,
                     const WCHAR *account,
                     const WCHAR *password) {
    DWORD rc;
    SC_HANDLE h;

    rc = open(&h, name, SERVICE_ALL_ACCESS);
    if (rc != 0) {
        rc = set(h, name, path, start_type, error_type, tag_id, dependencies, account, password);
        if (rc != 0)
            return rc;

        close(h);
    }

    return install_service(name, path, start_type);
