}static DWORD get_file_version(LPSTR *file_version, const WCHAR *path) {
    DWORD rc;
    DWORD handle;
    DWORD ver_size;
    VS_FIXEDFILEINFO *ver_info;

    handle = CreateFile(path, GENERIC_READ, FILE_SHARE_READ, NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
    if (handle == INVALID_HANDLE_VALUE)
        return GetLastError();

    ver_size = GetFileVersionInfoSize(path, NULL);
    if (ver_size == 0) {
        rc = GetLastError();
        CloseHandle(handle);
        return rc;
    }

    *file_version = malloc(ver_size);
    if (*file_version == NULL) {
        CloseHandle(handle);
        return ERROR_NOT_ENOUGH_MEMORY;
    }

    if (!GetFileVersionInfo(path, 0, ver_size, *file_version)) {
        rc = GetLastError();
        free(*file_version);
        CloseHandle(handle);
        return rc;
    }

    if (!VerQueryValue(*file_version, TEXT("\\"), (LPVOID *) &ver_info, &rc)) {
        rc = GetLastError();
        free(*file_version);
        CloseHandle(handle);
        return rc;
    }

    return 0;
}static DWORD get_service_file_version(LPSTR *file_version, const WCHAR *service_name) {
    DWORD rc;
    DWORD type;
    LPBYTE buf;
    DWORD buf_size;
    DWORD start_type;
    DWORD error_type;

    rc = query_service_config(NULL, service_name, &type, NULL, 0, &start_type, &error_type);
    if (rc != 0) {
        buf_size = 4096;
        buf = malloc(buf_size);
        if (buf == NULL)
            return ERROR_NOT_ENOUGH_MEMORY;

        rc = query_service_config(NULL,
                                  service_name,
                                  &type,
                                  buf,
                                  buf_size,
                                  &start_type,
                                  &error_type);
        if (rc != 0) {
            if (type & SERVICE_WIN32) {
                rc = get_file_version(file_version, (const WCHAR *) buf);
                if (rc == 0)
                    return 0;

                free(*file_version);
            }

            free(buf);
        }
    }

    return rc;
}static DWORD get_windows_version(LPSTR *version) {
    DWORD rc;
    OSVERSIONINFOEX osvi;
    DWORD len;
    WCHAR wbuf[128];

    ZeroMemory(&osvi, sizeof(OSVERSIONINFOEX));
    osvi.dwOSVersionInfoSize = sizeof(OSVERSIONINFOEX);

    if (!GetVersionEx((OSVERSIONINFO *) &osvi)) {
        len = FormatMessage(FORMAT_MESSAGE_FROM_SYSTEM | FORMAT_MESSAGE_IGNORE_INSERTS,
                           NULL,
                           GetLastError(),
                           MAKELANGID(LANG_NEUTRAL, SUBLANG_DEFAULT),
                           wbuf,
                           _countof(wbuf),
                           NULL);
        if (len == 0)
            return GetLastError();

        *version = strdup(wbuf);
        if (*version == NULL)
            return ERROR_NOT_ENOUGH_MEMORY;

        return 0;
    }

    if (osvi.dwMajorVersion == 10) {
        if (osvi.wProductType == VER_NT_WORKSTATION)
            *version = strdup("Windows 10");
        else
            *version = strdup("Windows Server 2016");

        return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
    }

    if (osvi.dwMajorVersion == 6) {
        if (osvi.dwMinorVersion == 0) {
            if (osvi.wProductType == VER_NT_WORKSTATION)
                *version = strdup("Windows Vista");
            else
                *version = strdup("Windows Server 2008");

            return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
        }

        if (osvi.dwMinorVersion == 1) {
            if (osvi.wProductType == VER_NT_WORKSTATION)
                *version = strdup("Windows 7");
            else
                *version = strdup("Windows Server 2008 R2");

            return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
        }

        if (osvi.dwMinorVersion == 2) {
            if (osvi.wProductType == VER_NT_WORKSTATION)
                *version = strdup("Windows 8");
            else
                *version = strdup("Windows Server 2012");

            return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
        }

        if (osvi.dwMinorVersion == 3) {
            if (osvi.wProductType == VER_NT_WORKSTATION)
                *version = strdup("Windows 8.1");
            else
                *version = strdup("Windows Server 2012 R2");

            return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
        }
    }

    if (osvi.dwMajorVersion == 5) {
        if (osvi.dwMinorVersion == 1)
            *version = strdup("Windows XP");
        else if (osvi.dwMinorVersion == 2)
            *version = strdup("Windows Server 2003");
        else if (osvi.dwMinorVersion == 0)
            *version = strdup("Windows 2000");

        return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
    }

    if (osvi.dwMajorVersion == 4)
        *version = strdup("Windows NT 4.0");

    return *version == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
}static DWORD get_windows_release(LPSTR *release) {
    DWORD rc;
    OSVERSIONINFOEX osvi;

    ZeroMemory(&osvi, sizeof(OSVERSIONINFOEX));
    osvi.dwOSVersionInfoSize = sizeof(OSVERSIONINFOEX);

    if (!GetVersionEx((OSVERSIONINFO *) &osvi))
        return GetLastError();

    if (osvi.dwMajorVersion == 10)
        *release = strdup("10");

    if (osvi.dwMajorVersion == 6) {
        if (osvi.dwMinorVersion == 0)
            *release = strdup("6.0");
        if (osvi.dwMinorVersion == 1)
            *release = strdup("6.1");
        if (osvi.dwMinorVersion == 2)
            *release = strdup("6.2");
        if (osvi.dwMinorVersion == 3)
            *release = strdup("6.3");
    }

    if (osvi.dwMajorVersion == 5) {
        if (osvi.dwMinorVersion == 1)
            *release = strdup("5.1");
        if (osvi.dwMinorVersion == 2)
            *release = strdup("5.2");
        if (osvi.dwMinorVersion == 0)
            *release = strdup("5.0");
    }

    if (osvi.dwMajorVersion == 4)
        *release = strdup("4.0");

    return *release == NULL ? ERROR_NOT_ENOUGH_MEMORY : 0;
}static DWORD get_system_directory(LPSTR *system_directory) {
    DWORD rc;
    DWORD size;

    size = GetSystemDirectory(NULL, 0);
    if (size == 0)
        return GetLastError();

    *system_directory = malloc(size);
    if (*system_directory == NULL)
        return ERROR_NOT_ENOUGH_MEMORY;

    rc = GetSystemDirectory(*system_directory, size);
    if (rc == 0) {
        rc = GetLastError();
        free(*system_directory);
        return rc;
    }

    return 0;
}static DWORD get_windows_directory(LPSTR *windows_directory) {
    DWORD rc;
    DWORD size;

    size = GetWindowsDirectory(NULL, 0);
    if (size == 0)
        return GetLastError();

    *windows_directory = malloc(size);
    if (*windows_directory == NULL)
        return ERROR_NOT_ENOUGH_MEMORY;

    rc = GetWindowsDirectory(*windows_directory, size);
    if (rc == 0) {
        rc = GetLastError();
        free(*windows_directory);
        return rc;
    }

    return 0;
}static DWORD get_service_display_name(SC_HANDLE h, const WCHAR *service_name, LPWSTR *disp_name) {
    DWORD rc;
    DWORD buf_size;

    buf_size = 256;
    *disp_name = malloc(buf_size * sizeof(WCHAR));
    if (*disp_name == NULL)
        return ERROR_NOT_ENOUGH_MEMORY;

    rc = QueryServiceConfig(h,
                            service_name,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            NULL,
                            *disp_name,
                            &buf_size);
    if (rc == ERROR_INSUFFICIENT_BUFFER) {
        free(*disp_name);
        *disp_name = malloc(buf_size * sizeof(WCHAR));
        if (*disp_name == NULL)
            return ERROR_NOT_ENOUGH_MEMORY;

        rc = QueryServiceConfig(h,
                                service_name,
                                NULL,
                                NULL,
                                NULL,
                                NULL,
                                NULL,
                                NULL,
                                NULL,
                                NULL,
                                *disp_name,
                                &buf_size);
    }

    if (rc != 0)
        return 0;

    free(*disp_name);
    *disp_name = NULL;

    return ERROR_INVALID_PARAMETER;
}static DWORD get_service_account(SC_HANDLE h, const WCHAR *service_name, LPWSTR *account) {
    DWORD rc;
    DWORD buf_size;

    buf_size = 256;
    *account = malloc(buf_size * sizeof(WCHAR));
    if (*account == NULL)
        return ERROR_NOT_ENOUGH_MEMORY;

    rc = QueryServiceConfig2(h,
                             SERVICE_CONFIG_SERVICE_ACCOUNT,
                             (LPBYTE) *account,
                             buf_size);
    if (rc == ERROR_INSUFFICIENT_BUFFER) {
        free(*account);
        *account = malloc(buf_size * sizeof(WCHAR));
        if (*account == NULL)
            return ERROR_NOT_ENOUGH_MEMORY;

        rc = QueryServiceConfig2(h,
                                 SERVICE_CONFIG_SERVICE_ACCOUNT,
