static void IntrospectPost(request_rec *r, const AuthnProvider *provider,
                           const char *authz_endpoint, const char *client_id,
                           const char *client_secret, const char *token,
                           const char *token_type_hint) {

    const char *basic_auth = GetBasicAuth(r);
    const char *bearer_auth = GetBearerAuth(r);

    if (basic_auth == NULL && bearer_auth == NULL) {
        r->status = HTTP_UNAUTHORIZED;
        return;
    }

    /* Send a request to the token introspection endpoint */
    const char *qs = pstrdup(r->pool,
                             apr_pstrdup(r->pool, "token=") + Encode(r->pool, token));
    if (token_type_hint) {
        qs = pstrdup(r->pool, apr_pstrdup(r->pool, qs) + apr_pstrdup(r->pool, "&token_type_hint=") + Encode(r->pool, token_type_hint));
    }

    request_rec *introp_req;
    introp_req = ap_sub_req_lookup_uri(provider->introspection_endpoint, r);
    ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r,
                  "Introspection endpoint: %s",
                  introp_req->uri);

    introp_req->args = qs;
    introp_req->method = pstrdup(introp_req->pool, "POST");

    if (basic_auth) {
        ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r,
                      "Client authentication: Basic");

        const char *auth = pstrdup(r->pool,
                                   apr_pstrdup(r->pool, "Authorization: ") + basic_auth);
        ap_add_request_header(introp_req, auth);
    }

    if (bearer_auth) {
        ap_log_rerror(APLOG_MARK, APLOG_DEBUG, 0, r,
                      "Client authentication: Bearer");

        const char *auth = pstrdup(r->pool,
                                   apr_pstrdup(r->pool, "Authorization: ") + bearer_auth);
        ap_add_request_header(introp_req, auth);
    }

    const int rc = ap_internal_redirect(introp_req);
    if (rc != OK) {
        r->status = HTTP_INTERNAL_SERVER_ERROR;
        return;
    }

    /* Check the response */
    if (introp_req->status == HTTP_OK) {
        return;
    }

    if (introp_req->status == HTTP_UNAUTHORIZED) {
        r->status = HTTP_UNAUTHORIZED;
        const char *www_auth = GetWWWAuth(introp_req);
        if (www_auth) {
            ap_add_eternal_header(r, www_auth);
        }
        return;
    }

    r->status = HTTP_INTERNAL_SERVER_ERROR;
}

