        width = node->width;
        height = node->height;
        ALLOC(label_width, label_height, render_string_size(render, label));
        render_string_geometry(render, label, label_width, label_height);
        min_width = label_width + 2 * node->label_margin;
        min_height = label_height + 2 * node->label_margin;
        if (width < min_width)
            width = min_width;
        if (height < min_height)
            height = min_height;
        node->width = width;
        node->height = height;
        port_y = (height - label_height) / 2;
        if (port_y < node->label_margin)
            port_y = node->label_margin;
        node->port_y = port_y;
        node->label_x = (width - label_width) / 2;
        /* place ports */
        TAILQ_FOREACH(edge, &node->edges, net) {
            if (edge->src != node)
                continue;
            obj = edge->port;
            if (obj == NULL)
                continue;
            if (edge->multi)
                port_y += 1 + (edge->src_port * 2);
            obj->y = port_y + (obj->height / 2);
            if (directed && edge->style != STYLE_DOTTED) {
                if (edge->arrow_at_src) {
                    if (obj->height < ARROW_SIZE)
                        obj->height = ARROW_SIZE;
                    obj->y -= (ARROW_SIZE / 2);
                }
            }
        }
    }
}

