    if (sl == NULL)
	return FALSE;

    /*
     * Check for a hash match.
     */
    hash = 0;
    for (pp = s1; *pp; ++pp)
	hash = (hash * 131) + *pp;
    hash %= HASHSIZE;

    same = FALSE;
    for (i = 0; i < sl->sl_numchars[hash]; ++i)
    {
	orig_s2 = sl->sl_chars[hash][i];
	chars = orig_s2;

	/*
	 * The list of characters may contain wildcard characters.
	 * Check if one of them matches the first character of s1.
	 */
	if (*chars == '[')
	{
	    ++chars;
	    if (vim_strchr(chars, ']') == NULL)
		chars = orig_s2;	// invalid character class
	    else
	    {
		*wildcard = TRUE;
		if (vim_strchr(chars, *s1) == NULL)
		    chars = NULL;
	    }
	}

	/*
	 * If the list of characters starts with a caret, it must match
	 * the first character of s1.
	 */
	if (chars != NULL && *chars == '^')
	{
	    ++chars;
	    if (*chars == '[')
	    {
		++chars;
		if (vim_strchr(chars, ']') == NULL)
		    chars = NULL;	// invalid character class
		else
		{
		    *wildcard = TRUE;
		    if (vim_strchr(chars, *s1) != NULL)
			chars = NULL;
		}
	    }
	    else if (*chars != *s1)
		chars = NULL;
	}

	if (chars != NULL)
	{
	    /*
	     * The characters must appear in s2, in the same order.
	     * "same" is set to TRUE when the first character is found in s2.
	     */
	    for (pp = s2; *pp; ++pp)
	    {
		if (*pp == *chars)
		{
		    if (same)
		    {
			// found the same character, two characets match
			++chars;
			if (*chars == NUL)
			    return TRUE;
		    }
		    else
		    {
			// found the first character, mark it as found
			same = TRUE;
		    }
		}
		else if (same)
		{
		    /*
		     * When two characters match, a different character in s2
		     * stops the match.
		     */
		    return FALSE;
		}
	    }
	    /*
	     * If the character list ends in a caret, the character before
	     * it must NOT appear in s2.
	     */
	    if (vim_strchr(chars, '^') == chars - 1)
	    {
		if (same)
		    return FALSE;
	    }
	    else
	    {
		/*
		 * If the character list doesn't end in a caret, and it matched
		 * the first character, and that character is found in s2, it
		 * must be the last character of s2.
		 */
		if (same && *pp != NUL)
		    return FALSE;
	    }
	    return TRUE;
	}
    }
