    for (i = 0; i < frag->nb_units; i++) {
        CodedBitstreamUnit *unit = &frag->units[i];

        if (ct->verbose_trace)
            av_log(avct, AV_LOG_DEBUG, "Coding %s unit %d/%d\n",
                   cbs_av1_unit_name(unit->type), i+1, frag->nb_units);

        switch (unit->type) {
        case AV1_UNIT_SEQUENCE_HEADER:
            if ((err = cbs_av1_write_sequence_header(ct, &pb, &unit->content.sequence_header))) return err;
            break;
        case AV1_UNIT_FRAME_HEADER:
            if ((err = cbs_av1_write_frame_header(ct, &pb, &unit->content.frame_header))) return err;
            break;
        case AV1_UNIT_TILE_GROUP:
            if ((err = cbs_av1_write_tile_group(ct, &pb, &unit->content.tile_group))) return err;
