static void _dl_dst_count(const char *rpath, const char *name,
			   int *countp, size_t *lenp)
{
  const char *p;
  size_t len;

  /* Each iteration processes one component.  */
  for (p = rpath; *p; p += len + 1)
    {
      /* Skip over the current component.  */
      len = strlen (p);

      /* If it is the special `$ORIGIN` token, count it.  */
