static int connectToServerWithTimeout(const char *host, int port, int timeout) {
    struct timeval tv;
    redisContext *c;
    int retval;

    if (timeout < 0) {
        /* set a very short timeout in order to perform a non-blocking connect */
        timeout = 1;
    }
    tv.tv_sec = timeout;
    tv.tv_usec = (timeout % 1) * 1000000;

    c = redisConnectWithTimeout(host, port, tv);
    if (c == NULL || c->err) {
        if (c) {
            printf("Connection error: %s\n", c->errstr);
            redisFree(c);
        } else {
            printf("Unable to allocate redis context\n");
        }
        return 1;
    }

    /* setup non blocking mode */
    retval = redisSetNonBlock(c, 1);
    if (retval == -1) {
        printf("Unable to set socket to non-blocking mode\n");
        redisFree(c);
        return 1;
    }

    /* perform the actual connection */
    retval = redisConnectNonBlock(c, host, port);
    if (retval == -1) {
        printf("Connection error: %s\n", c->errstr);
        redisFree(c);
        return 1;
    }

    /* use the original timeout for read/write operations */
    tv.tv_sec = timeout;
    tv.tv_usec = (timeout % 1) * 1000000;
    redisSetTimeout(c, tv);

    return 0;
