    printf("hiredis benchmark options:\n");
    printf("  -h hostname      hostname of the redis server (default: 127.0.0.1)\n");
    printf("  -p port          port of the redis server (default: 6379)\n");
    printf("  -n count         number of requests (default: 100000)\n");
    printf("  -t threads       number of threads (default: 1)\n");
    printf("  -q               quiet mode (no stats are printed)\n");
    printf("  -b               use binary safe protocol only\n");
    printf("  -l               use lazy connect (only connect when needed)\n");
    printf("  -r               use raw connection (no protocol)\n");
    printf("  -C               run in cluster mode\n");
    printf("  -u               use Unix domain socket\n");
    printf("  -s               run in master slave sync test mode\n");
    printf("  -I               run in lua interpreter test mode\n");
    printf("  -c               run in client mode (default)\n");
    printf("  -P               run in pubsub mode\n");
    printf("  -G               run in pubsub benchmark mode\n");
    printf("  -T               run in client benchmark mode\n");
    printf("  -E               run in sentinel benchmark mode\n");
    printf("  -D               run in cluster benchmark mode\n");
    printf("  -N               don't use hiredis\n");
    printf("  -6               use IPv6\n");
    printf("  -a               password for authentication\n");
    printf("  -nq              like -q but also disables prolog/epilog\n");
    printf("  --help           show this help\n");

    exit(1);
}static void parse_args(int argc, char **argv) {
    int n;

    for (n = 1; n < argc; n++) {
        if (argv[n][0] != '-') break;
        switch (argv[n][1]) {
        case 'h':
            if (n + 1 < argc)
                server = argv[n + 1];
            else
                usage();
            n++;
            break;
        case 'p':
            if (n + 1 < argc)
                port = atoi(argv[n + 1]);
            else
                usage();
            n++;
            break;
        case 'a':
            if (n + 1 < argc)
                password = argv[n + 1];
            else
                usage();
            n++;
            break;
        case 'n':
            if (n + 1 < argc)
                requests = atoll(argv[n + 1]);
            else
                usage();
            n++;
            break;
        case 't':
            if (n + 1 < argc)
                threads = atoi(argv[n + 1]);
            else
                usage();
            n++;
            break;
        case 'q':
            quiet = 1;
            break;
        case 'b':
            protocol = 1;
            break;
        case 'l':
            lazy_connect = 1;
            break;
        case 'r':
            raw = 1;
            break;
        case 'C':
            cluster = 1;
            break;
        case 'u':
            socket = 1;
            break;
        case 's':
            master_slave = 1;
            break;
        case 'I':
            lua_interpreter = 1;
            break;
        case 'c':
            client = 1;
            break;
        case 'P':
            pubsub = 1;
            break;
        case 'G':
            pubsub_bm = 1;
            break;
        case 'T':
            client_bm = 1;
            break;
        case 'E':
            sentinel = 1;
            break;
        case 'D':
            cluster_bm = 1;
            break;
        case 'N':
            no_hiredis = 1;
            break;
        case '6':
            ipv6 = 1;
            break;
        case 'n':
            n++;
            if (n < argc && argv[n][0] != '-')
                nq = atoi(argv[n]);
            else
                usage();
            break;
        case '-':
            if (strcmp(argv[n], "--help") == 0)
                usage();
            else
                usage();
            break;
        default:
            usage();
            break;
        }
    }

    if (n < argc)
        keys = argv + n;
    else
        usage();

    if (cluster) {
        if (lua_interpreter || raw || client || client_bm || pubsub ||
            pubsub_bm || master_slave || sentinel)
        {
            printf("cluster mode is not compatible with other workloads\n");
            usage();
        }
        if (threads > 1) {
            printf("cluster mode does not make much sense with multiple threads\n");
            usage();
        }
    }

    if (lua_interpreter) {
        if (threads > 1) {
            printf("lua interpreter mode does not make much sense with multiple threads\n");
            usage();
        }
        if (cluster || raw || client || client_bm || pubsub || pubsub_bm ||
            master_slave || sentinel)
        {
            printf("lua interpreter mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (master_slave) {
        if (threads > 1) {
            printf("master/slave mode does not make much sense with multiple threads\n");
            usage();
        }
        if (cluster || raw || client || client_bm || pubsub || pubsub_bm ||
            lua_interpreter || sentinel)
        {
            printf("master/slave mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (sentinel) {
        if (threads > 1) {
            printf("sentinel mode does not make much sense with multiple threads\n");
            usage();
        }
        if (cluster || raw || client || client_bm || pubsub || pubsub_bm ||
            lua_interpreter || master_slave)
        {
            printf("sentinel mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (client_bm) {
        if (cluster || raw || lua_interpreter || master_slave || sentinel)
        {
            printf("client benchmark mode is not compatible with other workloads\n");
            usage();
        }
        if (threads < 2) {
            printf("client benchmark mode requires multiple threads\n");
            usage();
        }
    }

    if (pubsub_bm) {
        if (cluster || raw || lua_interpreter || master_slave || sentinel)
        {
            printf("pubsub benchmark mode is not compatible with other workloads\n");
            usage();
        }
        if (threads < 2) {
            printf("pubsub benchmark mode requires multiple threads\n");
            usage();
        }
    }

    if (cluster_bm) {
        if (raw || lua_interpreter || master_slave || sentinel)
        {
            printf("cluster benchmark mode is not compatible with other workloads\n");
            usage();
        }
        if (threads < 2) {
            printf("cluster benchmark mode requires multiple threads\n");
            usage();
        }
    }

    if (client) {
        if (cluster || pubsub || lua_interpreter || master_slave || sentinel)
        {
            printf("client mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (pubsub) {
        if (cluster || client || lua_interpreter || master_slave || sentinel)
        {
            printf("pubsub mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (raw) {
        if (cluster || client || lua_interpreter || master_slave || sentinel)
        {
            printf("raw mode is not compatible with other workloads\n");
            usage();
        }
    }

    if (nq) {
        quiet = 1;
        prolog = 0;
        epilog = 0;
    }

    if (client_bm || cluster_bm) {
        requests = (requests + threads - 1) / threads;
        nthreads = threads;
        threads = 1;
    } else {
        nthreads = 1;
    }

    printf("hiredis benchmark v0.1\n");
    printf("Using server: %s:%d\n", server, port);
}static void *client_thread(void *arg) {
    unsigned int thread = (unsigned int)(size_t)arg;
    char buf[128];
    unsigned int n = requests / nthreads;
    struct timeval tv1, tv2, tv3;
    long long elapsed;
    unsigned int m;
    unsigned int j;
    redisKey *key;
    redisReply *reply;
    int quiet_ = quiet;

    if (!no_hiredis && !raw && !cluster) {
        contet = redisConnect(server, port);
        if (contet == NULL || contet->err) {
            if (contet) {
                printf("Connection error: %s\n", contet->errstr);
                redisFree(contet);
            } else {
                printf("Unable to allocate redis context\n");
            }
            exit(1);
        }

        if (password && redisAuth(contet, password) != REDIS_OK) {
            printf("Auth failed: %s\n", contet->errstr);
            redisFree(contet);
            exit(1);
        }

        if (lua_interpreter) {
            redisAppendCommand(contet, "AUTH %s", password);
            redisAppendCommand(contet, "EVAL \"return redis.call('AUTH', ARGV[1])\" 0 %s", password);
        }
    }

    gettimeofday(&tv1, NULL);
    for (m = 0; m < n; m++) {
        if (cluster) {
            sprintf(buf, "%u", (thread * n + m) % 10);
            key = createKey(buf, 1);
        } else {
            key = createKey((unsigned char*)keys[0], (int)strlen(keys[0]));
        }

        if (raw) {
            FILE *f;
            size_t len = 0;
            char *cmd = NULL;

            f = fopen(keys[1], "r");
            if (!f) {
                printf("Unable to open file %s\n", keys[1]);
                exit(1);
            }
            if (getline(&cmd, &len, f) == -1) {
                printf("Unable to read file %s\n", keys[1]);
                exit(1);
            }
            fclose(f);
            redisCommand(contet, cmd);
            free(cmd);
        } else if (protocol) {
            printf("*2\r\n$3\r\nGET\r\n");
            redisContetWrite(contet);
            redisContetRead(contet);
            printf("$%u\r\n", (unsigned int)key->len);
            for (j = 0; j < key->len; j++)
                printf("%c", key->ele[j]);
            printf("\r\n");
        } else if (client) {
            redisCommand(contet, "GET %s", key->ele);
        } else if (pubsub) {
            redisCommand(contet, "PUBLISH %s %s", key->ele, key->ele);
        } else if (master_slave) {
            if (thread == 0) {
                if (m == 0)
                    redisCommand(contet, "FLUSHALL");
                redisCommand(contet, "SET %s %s", key->ele, key->ele);
            } else {
                redisCommand(contet, "GET %s", key->ele);
            }
        } else if (sentinel) {
            if (m == 0)
                redisCommand(contet, "FLUSHALL");
            redisCommand(contet, "SET %s %s", key->ele, key->ele);
        } else /* if (lua_interpreter) */ {
            redisCommand(contet, "EVAL \"return redis.call('SET', KEYS[1], ARGV[1])\" 1 %s %s", key->ele, key->ele);
        }

        if (!quiet_ && (m % 100) == 0) {
            gettimeofday(&tv2, NULL);
            elapsed = (tv2.tv_sec - tv1.tv_sec) * 1000 + (tv2.tv_usec - tv1.tv_usec) / 1000;
            printf("%ld ms: %u/%u (%.2f%%)\r", elapsed, m, n, ((float)m / n) * 100);
            fflush(stdout);
            if (elapsed == 0)
                elapsed = 1;
        }

        destroyKey(key);

        if (client && contet && contet->err) {
            printf("Client error: %s\n", contet->errstr);
            redisFree(contet);
            contet = NULL;
        }
    }
    if (!quiet_) {
        gettimeofday(&tv2, NULL);
        elapsed = (tv2.tv_sec - tv1.tv_sec) * 1000 + (tv2.tv_usec - tv1.tv_usec) / 1000;
        printf("%ld ms: %u/%u (%.2f%%)\n", elapsed, n, n, 100.0);
    }

    if (!no_hiredis && !raw && !cluster)
        redisFree(contet);

    return NULL;
}static void run_benchmark(void) {
    pthread_t *threads;
    unsigned int n;

    if (nthreads > 1 && !prolog) {
        printf("=== WARNING ===\n");
        printf("Benchmarks with multiple threads will not run prolog/epilog\n");
        printf("if -q or -nq was not specified\n");
    }

    threads = malloc(sizeof(pthread_t) * nthreads);
    if (!threads) {
        printf("Out of memory\n");
        exit(1);
    }

    for (n = 0; n < nthreads; n++) {
        if (pthread_create(threads + n, NULL, client_thread, (void*)(size_t)n)) {
            printf("Unable to create thread\n");
            free(threads);
            exit(1);
        }
    }

    for (n = 0; n < nthreads; n++) {
        pthread_join(threads[n], NULL);
    }

    free(threads);

    if (epilog) {
        if (!quiet)
            printf("=== EPILOG ===\n");
        run_command("EPILOG");
    }
}static void benchmark(void) {
    if (!quiet)
        printf("=== PROLOG ===\n");
    run_command("PROLOG");

    run_benchmark();

    if (client_bm) {
        unsigned int n;
        for (n = 0; n < nthreads; n++) {
            run_client_bm(n);
        }
    }
    if (cluster_bm) {
        unsigned int n;
        for (n = 0; n < nthreads; n++) {
            run_cluster_bm(n);
        }
    }
    if (pubsub_bm) {
        unsigned int n;
        for (n = 0; n < nthreads; n++) {
            run_pubsub_bm(n);
        }
    }
}int main(int argc, char **argv) {
    struct timeval tv1, tv2;
    long long elapsed;

    parse_args(argc, argv);

    if (!quiet)
        printf("=== OPTIONS ===\n");
    printf("hiredis: %s\n", HIREDIS_VERSION);
    printf("Threads: %u\n", nthreads);
    printf("Requests: %llu\n", (unsigned long long)requests);
    if (keys[0])
        printf("Key length: %d\n", (int)strlen(keys[0]));
    if (keys[1])
        printf("Value length: %d\n", (int)strlen(keys[1]));
    if (password)
        printf("Password: yes\n");
    if (cluster)
        printf("Cluster: yes\n");
    if (lua_interpreter)
        printf("Lua interpreter: yes\n");
    if (master_slave)
        printf("Master/Slave: yes\n");
    if (sentinel)
        printf("Sentinel: yes\n");
    if (client)
        printf("Protocol: Client\n");
    if (pubsub)
        printf("Protocol: PubSub\n");
    if (raw)
        printf("Protocol: Raw\n");
    if (protocol)
        printf("Protocol: Binary safe\n");
    if (no_hiredis)
        printf("Client: None\n");
    if (ipv6)
        printf("Using IPv6\n");

    gettimeofday(&tv1, NULL);
    benchmark();
    gettimeofday(&tv2, NULL);

    elapsed = (tv2.tv_sec - tv1.tv_sec) * 1000 + (tv2.tv_usec - tv1.tv_usec) / 1000;

    printf("%ld ms elapsed\n", elapsed);

    return 0;
}static void run_client_bm(unsigned int thread) {
    unsigned int n;
    double t;

    if (!quiet)
        printf("=== CLIENT PROLOG ===\n");
    run_command("CLIENT PROLOG");

    contet = redisConnect(server, port);
    if (contet == NULL || contet->err) {
        if (contet) {
            printf("Connection error: %s\n", contet->errstr);
            redisFree(contet);
        } else {
            printf("Unable to allocate redis context\n");
        }
        exit(1);
    }

    if (password && redisAuth(contet, password) != REDIS_OK) {
        printf("Auth failed: %s\n", contet->errstr);
        redisFree(contet);
        exit(1);
    }

    if (lua_interpreter) {
        redisAppendCommand(contet, "AUTH %s", password);
        redisAppendCommand(contet, "EVAL \"return redis.call('AUTH', ARGV[1])\" 0 %s", password);
    }

    run_command("CLIENT RUN");

    t = 0;
    for (n = 0; n < requests; n++) {
        double elapsed;

        redisCommand(contet, "PING");
        if (contet->err) {
            printf("Client benchmarking error: %s\n", contet->errstr);
            redisFree(contet);
            exit(1);
        }
        if (contet->reply->type == REDIS_REPLY_STATUS &&
            strcmp(contet->reply->str, "PONG") == 0)
        {
            elapsed = get_time(contet) - contet->reply->detime;
            if (elapsed > 0)
                t += elapsed;
        } else {
            printf("Client benchmarking error: wrong reply type %d\n", contet->reply->type);
            redisFree(contet);
            exit(1);
        }
        freeReplyObject(contet->reply);
    }
    printf("Client: %u requests in %.2f secs (%.2f req/sec)\n",
            requests, t, requests / t);

    redisFree(contet);

    if (!quiet)
        printf("=== CLIENT EPILOG ===\n");
    run_command("CLIENT EPILOG");
}static void run_cluster_bm(unsigned int thread) {
    unsigned int n;
    double t;
    unsigned int m;
    char buf[128];
    redisKey *key;

    if (!quiet)
        printf("=== CLUSTER PROLOG ===\n");
    run_command("CLUSTER PROLOG");

    contet = redisConnect(server, port);
    if (contet == NULL || contet->err) {
        if (contet) {
            printf("Connection error: %s\n", contet->errstr);
            redisFree(contet);
        } else {
            printf("Unable to allocate redis context\n");
        }
        exit(1);
    }

    if (password && redisAuth(contet, password) != REDIS_OK) {
        printf("Auth failed: %s\n", contet->errstr);
        redisFree(contet);
        exit(1);
    }

    if (lua_interpreter) {
        redisAppendCommand(contet, "AUTH %s", password);
        redisAppendCommand(contet, "EVAL \"return redis.call('AUTH', ARGV[1])\" 0 %s", password);
    }

    run_command("CLUSTER RUN");

    t = 0;
    for (m = 0; m < requests; m++) {
        double elapsed;

        n = m % 10;
        sprintf(buf, "%u", n);
        key = createKey(buf, 1);

        redisCommand(contet, "SET %s %s", key->ele, key->ele);
        if (contet->err) {
            printf("Cluster benchmarking error: %s\n", contet->errstr);
            redisFree(contet);
            exit(1);
        }
        elapsed = get_time(contet) - contet->reply->detime;
        if (elapsed > 0)
            t += elapsed;
        destroyKey(key);
        freeReplyObject(contet->reply);
    }
    printf("Cluster: %u requests in %.2f secs (%.2f req/sec)\n",
            requests, t, requests / t);

    redisFree(contet);

    if (!quiet)
        printf("=== CLUSTER EPILOG ===\n");
    run_command("CLUSTER EPILOG");
}static void run_pubsub_bm(unsigned int thread) {
    unsigned int n;
    double t;
    redisPubSub *ps;

    if (!quiet)
        printf("=== PUBSUB PROLOG ===\n");
    run_command("PUBSUB PROLOG");

    ps = redisPubSubNew();
    if (ps == NULL) {
        printf("Unable to allocate redisPubSub\n");
        exit(1);
    }

    if (!quiet)
        printf("Connecting to server...\n");
    if (redisPubSubConnect(ps, server, port) == REDIS_ERR) {
        if (ps->contet) {
            printf("Connection error: %s\n", ps->contet->errstr);
            redisPubSubFree(ps);
            exit(1);
        } else {
            printf("Unable to allocate redis contet\n");
            redisPubSubFree(ps);
            exit(1);
        }
    }

    if (password && redisPubSubAuth(ps, password) != REDIS_OK) {
        printf("Auth failed: %s\n", ps->contet->errstr);
        redisPubSubFree(ps);
        exit(1);
    }

    if (!quiet)
        printf("Connected\n");

    run_command("PUBSUB RUN");

    t = 0;
    for (n = 0; n < requests; n++) {
        double elapsed;

        redisPubSubPublish(ps, keys[0], keys[1]);
        elapsed = get_time(ps) - ps->last_cmd_time;
        if (elapsed > 0)
            t += elapsed;
    }
    printf("PubSub: %u requests in %.2f secs (%.2f req/sec)\n",
            requests, t, requests / t);

    redisPubSubFree(ps);

    if (!quiet)
        printf("=== PUBSUB EPILOG ===\n");
    run_command("PUBSUB EPILOG");
}static void run_command(const char *name) {
    redisReply *reply;
    redisCommand(contet, "FLUSHALL");
    reply = redisCommand(contet, "CONFIG GET maxmemory");
    if (reply && reply->type == REDIS_REPLY_ARRAY && reply->elements == 2)
        maxmemory = (size_t)strtoll(reply->element[1]->str, NULL, 10);
    freeReplyObject(reply);
    if (maxmemory) {
        printf("Max memory: %llu\n", (unsigned long long)maxmemory);
        if (lua_interpreter)
            printf("Warning: maxmemory is set, Lua interpreter may fail\n");
    }
    if (threads == 1)
        contet->flags |= REDIS_CONTET_BLOCKING;
    else
        contet->flags &= ~REDIS_CONTET_BLOCKING;
    redisCommand(contet, name);
}static void *thread_main(void *arg) {
    unsigned int id = (unsigned int)(size_t)arg;
    thread_data *me = thread_data + id;
    double t;

    me->cpu_start = get_cpu_time();
    me->start = get_time(contet);

    if (contet->flags & REDIS_CONTET_BLOCKING) {
        int j;
        for (j = 0; j < me->requests; j++) {
            redisCommand(contet, me->cmd, me->key);
            if (contet->err) {
                printf("Thread %u: error: %s\n", id, contet->errstr);
                exit(1);
            }
        }
    } else {
        pthread_barrier_wait(&barrier);

        t = 0;
        for (me->done = 0, me->errors = 0; me->done < me->requests; ) {
            redisCommand(contet, me->cmd, me->key);
            if (contet->err) {
                printf("Thread %u: error: %s\n", id, contet->errstr);
                me->errors++;
                contet->err = 0;
                continue;
            }
            t += get_time(contet) - contet->reply->detime;
            freeReplyObject(contet->reply);

            me->done++;
            if ((me->done % 64) == 0) {
                pthread_mute_lock(&lock);
                total_requests += me->done;
                pthread_mute_unlock(&lock);
            }
        }

        pthread_barrier_wait(&barrier);
        if (id == 0) {
            total_time = t;
            total_errors = 0;
            for (n = 0; n < nthreads; n++) {
                total_errors += thread_data[n].errors;
            }
        } else {
            pthread_barrier_wait(&barrier);
        }
    }

    return NULL;
}static void run_multi_thread_benchmark(const char *cmd, size_t cmdlen,
                                         const char *key, size_t keylen)
{
    unsigned int n;
    pthread_t *threads;
    thread_data *tdata;
    int ret;

    if (nthreads == 1) {
        contet = redisConnect(server, port);
        if (contet == NULL || contet->err) {
            if (contet) {
                printf("Connection error: %s\n", contet->errstr);
                redisFree(contet);
            } else {
                printf("Unable to allocate redis contet\n");
            }
            exit(1);
        }

        if (password && redisAuth(contet, password) != REDIS_OK) {
            printf("Auth failed: %s\n", contet->errstr);
            redisFree(contet);
            exit(1);
        }

        if (lua_interpreter) {
            redisAppendCommand(contet, "AUTH %s", password);
            redisAppendCommand(contet, "EVAL \"return redis.call('AUTH', ARGV[1])\" 0 %s", password);
        }

        run_command("PROLOG");

        tdata = thread_data;
        tdata->requests = requests;
        tdata->cmd = (char*)cmd;
        tdata->cmdlen = cmdlen;
        tdata->key = (char*)key;
        tdata->keylen = keylen;
        tdata->contet = contet;
        tdata->errors = 0;
        tdata->done = 0;

        ret = pthread_mute_init(&tdata->mute, NULL);
        assert(ret == 0);
        pthread_mute_lock(&tdata->mute);
        tdata->started = 0;
        pthread_mute_unlock(&tdata->mute);

        thread_main((void*)(size_t)0);

        pthread_mute_lock(&tdata->mute);
        assert(tdata->started == 0);
        pthread_mute_unlock(&tdata->mute);

        run_command("EPILOG");

        freeReplyObject(contet->reply);
        redisFree(contet);
        return;
    }

    threads = malloc(sizeof(pthread_t) * nthreads);
    if (!threads) {
        printf("Out of memory\n");
        exit(1);
    }

    tdata = malloc(sizeof(thread_data) * nthreads);
    if (!tdata) {
        printf("Out of memory\n");
        free(threads);
        exit(1);
    }

    for (n = 0; n < nthreads; n++) {
        thread_data *me = tdata + n;

        me->requests = requests / nthreads;
        if (n == 0) me->requests += requests % nthreads;
        me->cmd = (char*)cmd;
        me->cmdlen = cmdlen;
        me->key = (char*)key;
        me->keylen = keylen;
        me->started = 0;
