static lval eval7(lval e, env rho) {
  //printf("EVAL: %s\n", showlval(e));
  switch (e.type) {
    case LVAL_NUM: 
    case LVAL_ERR: return e;
    case LVAL_SYM: return eval_sym(e, rho);
    case LVAL_FUN: return e;
    case LVAL_CLOS: return e;
    case LVAL_MAC: return e;
    case LVAL_SEXPR:
    case LVAL_QEXPR:
      return eval_list(e, rho, e.type);
  }
  return make_err("Unknown type");
} 

static lval eval_sym(lval s, env rho) {
  //printf("EVAL SYM: %s\n", s.str);
  if (s.str[0] == '\\') return s;
  lval e = get_env(rho, s);
  if (e.type != LVAL_ERR) return e;
  return get_builtins(s);
}

static lval eval_list(lval e, env rho, int q) {
  if (e.count == 0) return e;
  if (e.count == 1 && e.type == LVAL_SEXPR) {
    e.type = LVAL_QEXPR;
  }

  for (int i = 0; i < e.count; i++) {
    e.cell[i] = eval7(e.cell[i], rho);
  }

  // special form
  if (e.type == LVAL_SEXPR && e.count && e.cell[0].type == LVAL_SYM) {
    if (e.cell[0].str[0] == '.') {
      return builtin_load(e);
    }
    lval f = eval7(e.cell[0], rho);
    if (f.type == LVAL_ERR) return f;
    if (f.type != LVAL_FUN &&
        f.type != LVAL_CLOS &&
        f.type != LVAL_MAC) {
      return make_err("Not a function");
    }
    e = apply(f, e, rho, q);
    return e;
  }
  return e;
} 

static lval apply(lval f, lval e, env rho, int q) {
  // showlval(f);
  // showlval(e);
  if (f.type == LVAL_MAC) {
    e = f.cell[0](e, f.cell[1]);
    return eval_list(e, rho, q);
  }

  if (e.count > MAX_ARITY) {
    return make_err("Too many arguments given");
  }

  int original_count = e.count;
  if (f.arity != -1 && e.count < f.arity) {
    e = make_qexpr();
    for (int i = 0; i < f.arity - e.count; i++) {
      e = addlval(e, make_num(0));
    }
    e = addlval(e, f.body);
    e.count = original_count;
    return eval_list(e, rho, q);
  }
  if (f.type == LVAL_CLOS) {
    e = addlval(e, f.env);
    e.type = LVAL_SEXPR;
    return eval_list(e, rho, q);
  }
  if (e.count != f.arity && f.arity != -1) {
    return make_err("Incorrect number of arguments");
  }

  env eenv = make_env(f.env);
  for (int i = 0; i < f.arity; i++) {
    set_env(eenv, f.args[i], e.cell[i]);
  }
  e = f.body;
  e.type = LVAL_SEXPR;
  return eval_list(e, eenv, q);
}

