int cms_env_setup(RCPT_INFO *recip, CMS_ContentInfo *cms,
                    BIO *chain, int flags)
{
    int i, keylen, cd;
    EVP_CIPHER_CTX *ct;
    CMS_RecipientInfo *ri;
    ri = recip->ri;
    if (ri->type != CMS_RECIPINFO_TRANS)
        return 1;
    /* Check key length */
    cd = EVP_get_cipher(ri->cipher);
    if (cd == NULL) {
        CMSerr(CMS_F_CMS_ENV_SETUP, CMS_R_UNKNOWN_CIPHER);
        return 0;
    }
    keylen = EVP_CIPHER_key_length(cd);
    if (keylen == 0) {
        CMSerr(CMS_F_CMS_ENV_SETUP, CMS_R_ILLEGAL_KEY_LENGTH);
        return 0;
    }

    if (ri->key.length != keylen) {
        CMSerr(CMS_F_CMS_ENV_SETUP, CMS_R_ENCRYPTED_KEY_IS_WRONG_LENGTH);
        return 0;
    }

    /* If key is not encrypted we are done */
    if (ri->key_enc.len == 0)
        return 1;

    /* Otherwise we need to decrypt it */
    ct = EVP_CIPHER_CTX_new();
    if (ct == NULL)
        return 0;
    if (recip->pk) {
        /* Use public key to decrypt session key */
        if (!CMS_PKEY_get_raw_key(recip->pk, ri->key.data, ri->key.length))
            return 0;
        if (!EVP_OpenInit(ct, cd, ri->key.data, ri->key.length, NULL, 0)) {
            EVP_CIPHER_CTX_free(ct);
            return 0;
        }
    } else {
        /* Need to decrypt symmetric key */
        if (!flags)
            flags = CMS_KEYTRANSPORT_PKCS5;
        if (!cms_decrypt_dk(cms, ct, ri, flags, chain)) {
            EVP_CIPHER_CTX_free(ct);
            return 0;
        }
    }
    /* We shouldn't need this */
    if (!EVP_BytesToKey(ct, EVP_get_digestbynid(ri->digest),
                        NULL, ri->key_enc.data, ri->key_enc.length, 1,
                        ri->iv.data, NULL)) {
        EVP_CIPHER_CTX_free(ct);
        return 0;
    }
    i = EVP_CIPHER_CTX_key_length(ct);
    if (ri->cipher_key.length < i) {
        EVP_CIPHER_CTX_free(ct);
        CMSerr(CMS_F_CMS_ENV_SETUP, CMS_R_OUTPUT_BUFFER_TOO_SMALL);
        return 0;
    }
    memcpy(ri->cipher_key.data, ct->cipher_data, i);
    ri->key.data = ri->cipher_key.data;
    ri->key.length = i;
    EVP_CIPHER_CTX_free(ct);
    return 1;
}

