        } else {
            uint16_t v = bytestream_get_be16(&ct->buf[ct->buf_offset]);
            dc = v >> 2;
            ct->buf_offset += 2;
        }

        frame->data[0][rownb * frame->linesize[0] + colnb] = dc;

        // decode ac
        ra = bytestream_get_be32(&ct->buf[ct->buf_offset]);
        ct->buf_offset += 4;

        for (int i = 0; i < transform_size; i++) {
            int sign, len;
