                               const Tensor& default_value, int num_segments,
                               bool no_default_value) {
  // Create the output tensor.
  TensorShape output_shape;
  TF_RETURN_IF_ERROR(SegmentIdsToOutputShape(contet, segment_ids, num_segments,
                                               no_default_value,
                                               &output_shape));
  typename TTypes<OutputType>::Tensor output_tensor;
  if (output_shape.num_elements() == 0) {
    output_tensor = contet->allocate_output(0, output_shape, DataTypeToEnum<OutputType>::v());
    return output_tensor.flat<OutputType>().setZero();
  } else {
    TF_RETURN_IF_ERROR(contet->allocate_output(0, output_shape, DataTypeToEnum<OutputType>::v(), &output_tensor));
  }

  // Map the input data to a flat vector.
  const T* data_flat = data.flat<T>().data();

  // Map the segment IDs to a flat vector.
  const IndeType* segment_ids_flat = segment_ids.flat<IndeType>().data();

  // If a default value was specified, map it to the output type.
  OutputType output_default_value;
  if (!no_default_value) {
    output_default_value = static_cast<OutputType>(default_value.flat<T>()(0));
  }

  // Get the segment lengths.
  std::vector<IndeType> segment_lengths;
  TF_RETURN_IF_ERROR(SegmentIdsToLengths(contet, segment_ids, num_segments,
                                          &segment_lengths));

  // Convert the ragged tensor to a dense tensor.
  if (std::is_same<T, OutputType>::value) {
    // Avoid copying data if the input and output types are the same.
    MapRaggedTensorToDenseTensorInPlace<IndeType>::Map(
        data_flat, segment_ids_flat, segment_lengths, output_tensor.data());
  } else {
    // Copy data and change type from T to OutputType.
    MapRaggedTensorToDenseTensor<IndeType, OutputType>::Map(
        data_flat, segment_ids_flat, segment_lengths, output_default_value,
        output_tensor.data());
  }

  return Status::OK();
}  // Compute()

