static int parseMultiBulkReply(char *reply, size_t replylen, int *mlen, redisReply **replys, int type) {
    char *current;
    char *end;
    int elementcount;
    size_t currentheaplen;
    size_t newheaplen;

    current = reply;
    end = reply + replylen;

    /* get the total number of elements */
    if (parseIntegerReply(current,end,&elementcount) == REDIS_ERR)
        return REDIS_ERR;

    /* check that the length of the array is not greater than the remaining
     * length of the reply buffer. */
    if ((size_t)elementcount > (end-current) / 2)
        return REDIS_ERR;

    /* allocate space for the redisReply structures itself.
     * We calloc because we want everything initialized to NULL/0. */
    newheaplen = currentheaplen = (sizeof(redisReply) * elementcount);
    *replys = calloc(elementcount,sizeof(redisReply));
    if (*replys == NULL) return REDIS_ERR;
    redisReply *target_reply = *replys;

    /* for every element, get the type and use the appropriate parser */
    for (int j = 0; j < elementcount; j++) {
        int elementtype;
        redisReply *elementreply = target_reply+j;

        /* check type */
        if (parseType(current,end,&elementtype) == REDIS_ERR)
            goto error;
        elementreply->type = elementtype;

        /* check length */
        if (parseLength(current,end,&elementreply->elements) == REDIS_ERR)
            goto error;

        /* allocate value buffer when needed */
        if (elementreply->elements > 0) {
            size_t valuelen;

            if (parseLength(current,end,&valuelen) == REDIS_ERR)
                goto error;

            /* Every element has a length prefixed, even if it's just
             * the length of the string representing the length itself. */
            valuelen+=2;

            /* total heap length required for this element */
            newheaplen += valuelen + (elementreply->elements * sizeof(char*));

            /* make sure we have enough space for this element's
             * value array, and the strings themselves. */
            if (newheaplen > currentheaplen) {
                expandReplyHeap(*replys, newheaplen);
                currentheaplen = newheaplen;
                elementreply = *replys + j;
            }
            elementreply->ptr = (char*)*replys + currentheaplen - valuelen;
            elementreply->len = valuelen;
            currentheaplen -= valuelen;

            /* allocate space for the element value pointers array */
            elementreply->vi = calloc(elementreply->elements,sizeof(char*));
            if (elementreply->vi == NULL) goto error;
        }

