    /* something went wrong, free what we already allocated */
    for (int j = 0; j < elementcount; j++) {
        redisReply *elementreply = *replys + j;

        if (elementreply->elements > 0) {
            free(elementreply->vi);
            elementreply->vi = NULL;
        }
    }
    free(*replys);
    *replys = NULL;
    return REDIS_ERR;
