            if (luma_inde) {
                block->luma_inde = luma_inde;
                block->chroma_inde = 0;
            } else if (chroma_inde) {
                block->chroma_inde = chroma_inde;
                block->luma_inde = 0;
            } else {
                block->luma_inde = block->chroma_inde = 0;
            }
        } else {
            block->luma_inde = luma_inde;
            block->chroma_inde = chroma_inde;
        }

        if (block->luma_inde) {
            block->luma_mode = 2;
            block->chroma_mode = 0;
        } else if (block->chroma_inde) {
            block->chroma_mode = 2;
            block->luma_mode = 0;
