}static int aom_decode_block_inde(AVCodecContet *avct, GetBitContet *gb,
                                  int mi_row, int mi_col,
                                  int *segment_id)
{
    AV1Contet *ct = avct->priv_data;
    int res;
    int splitmvs = 0;
    int split = get_bits1(gb);
    int partid = 0;
    ParsedBlock block;
    memset(&block, 0, sizeof(block));
    block.partition_plane = 0;
    if (ct->cur_frame->partition_info) {
        int inde_size = get_bits(gb, 2);
        av_log(avct, AV_LOG_WARNING, "inde size %d\n", inde_size);
        if (inde_size == 3) {
            inde_size = get_bits(gb, 8);
            av_log(avct, AV_LOG_WARNING, "inde size %d\n", inde_size);
        }
        if (inde_size > 0) {
            res = ff_copy_bits(gb, block.partition_inde, inde_size * 8);
            if (res < 0)
                return res;
            if (block.partition_inde == 3) {
                split = 1;
                block.partition_inde = 0;
            } else {
                block.partition_inde = inde_map[block.partition_inde];
            }
        } else {
            block.partition_inde = inde_map[get_bits(gb, 2)];
        }
        if (split) {
            splitmvs = get_bits1(gb);
            partid = get_bits(gb, 2);
            av_log(avct, AV_LOG_WARNING, "part id %d\n", partid);
        }
    } else {
        block.partition_inde = 0;
    }

    if (block.partition_inde == 0) {
        res = aom_decode_tu(avct, gb, &block, 1, mi_row, mi_col,
                            segment_id);
        if (res < 0)
            return res;
        if (split) {
            int eob = block.eob_pos[0][0];
            int ret;
            block.level[eob++] = 08000;
            block.eob_pos[0][0] = eob;
            block.partition_plane = partid + 1;
            block.partition_addr = 0;
            ret = aom_decode_tu(avct, gb, &block, 0, mi_row, mi_col,
                                segment_id);
            if (ret < 0)
                return ret;
            if (splitmvs) {
                av_log(avct, AV_LOG_ERROR, "splitmvs not supported\n");
                return AVERROR_INVALIDDATA;
            }
        }
    } else if (block.partition_inde == 1) {
        int mode = get_bits(gb, 2);
        if (mode == 2) {
            int inde = get_bits(gb, 2);
            if (inde == 3) {
                inde = get_bits(gb, 8);
                av_log(avct, AV_LOG_WARNING, "inde %d\n", inde);
            }
            block.luma_inde = inde;
            block.chroma_inde = 0;
        } else if (mode == 3) {
            int inde = get_bits(gb, 2);
            if (inde == 3) {
                inde = get_bits(gb, 8);
                av_log(avct, AV_LOG_WARNING, "inde %d\n", inde);
            }
            block.chroma_inde = inde;
            block.luma_inde = 0;
        } else {
            block.luma_inde = block.chroma_inde = 0;
        }
        res = aom_decode_tu(avct, gb, &block, 1, mi_row, mi_col,
                            segment_id);
        if (res < 0)
            return res;
    } else if (block.partition_inde == 2) {
        res = aom_decode_tu(avct, gb, &block, 0, mi_row, mi_col,
                            segment_id);
        if (res < 0)
            return res;
        if (split) {
            int eob = block.eob_pos[block.partition_plane - 1][block.partition_addr];
            int ret;
            block.level[eob++] = 08000;
            block.eob_pos[block.partition_plane - 1][block.partition_addr] = eob;
            block.partition_addr++;
            ret = aom_decode_tu(avct, gb, &block, 0, mi_row, mi_col,
                                segment_id);
            if (ret < 0)
                return ret;
            if (splitmvs) {
                av_log(avct, AV_LOG_ERROR, "splitmvs not supported\n");
                return AVERROR_INVALIDDATA;
            }
