}static int aom_decode_token(AVCodecContet *avct, GetBitContet *gb,
                             ParsedBlock *block, int has_eob,
                             int mi_row, int mi_col, int *segment_id)
{
    AV1Contet *ct = avct->priv_data;
    if (ct->cur_frame->partition_info) {
        return aom_decode_block_inde(avct, gb, mi_row, mi_col, segment_id);
    } else {
        return aom_decode_tu(avct, gb, block, has_eob, mi_row, mi_col,
                             segment_id);
    }
}static int aom_decode_inter_mode_inde(AVCodecContet *avct, GetBitContet *gb,
                                       int *mode)
{
    int inde, mode_t, mode_l, filter;
    if (get_bits1(gb)) {
        mode_t = get_bits(gb, 2);
        mode_l = get_bits(gb, 2);
        filter = ~mode_t & mode_l;
        *mode = mode_t & ~mode_l;
        if (*mode == 3) {
            inde = get_bits(gb, 2);
            if (inde == 3) {
                inde = get_bits(gb, 8);
                av_log(avct, AV_LOG_WARNING, "inde %d\n", inde);
            }
            *mode = inde;
        }
        if (filter) {
            inde = get_bits(gb, 2);
            if (inde == 3) {
                inde = get_bits(gb, 8);
                av_log(avct, AV_LOG_WARNING, "inde %d\n", inde);
            }
            *mode = (*mode << 2) | inde;
        }
    } else {
        *mode = get_bits(gb, 2);
    }
    return 0;
}static int aom_decode_inde(AVCodecContet *avct, GetBitContet *gb,
                            int mi_row, int mi_col, int has_eob,
                            ParsedBlock *block, int *segment_id)
{
    AV1Contet *ct = avct->priv_data;
    int res;
    int split = get_bits1(gb);
    int partid = 0;
    if (split) {
        partid = get_bits(gb, 2);
        av_log(avct, AV_LOG_WARNING, "part id %d\n", partid);
    }

    res = aom_decode_inter_mode_inde(avct, gb, &block->mode);
    if (res < 0)
        return res;

    res = aom_decode_token(avct, gb, block, has_eob, mi_row, mi_col,
                           segment_id);
    if (res < 0)
        return res;

    if (split) {
        int eob = block->eob_pos[block->partition_plane - 1][block->partition_addr];
        block->level[eob++] = 08000;
        block->eob_pos[block->partition_plane - 1][block->partition_addr] = eob;
        block->partition_addr++;
        res = aom_decode_token(avct, gb, block, 0, mi_row, mi_col,
                               segment_id);
        if (res < 0)
            return res;
    }

    return 0;
}static int aom_decode_toplevel(AVCodecContet *avct, GetBitContet *gb,
                                int mi_row, int mi_col, int *segment_id)
{
    AV1Contet *ct = avct->priv_data;
    ParsedBlock block;
    int res;
    memset(&block, 0, sizeof(block));
    if (ct->cur_frame->frame_type == AV1_KEYFRAME ||
        ct->cur_frame->intraonly) {
        block.type = AV1_INTRA_MODE;
        res = aom_decode_inde(avct, gb, mi_row, mi_col, 1, &block, segment_id);
        if (res < 0)
            return res;
    } else {
        block.type = AV1_INTER_MODE;
        res = aom_decode_inde(avct, gb, mi_row, mi_col, 0, &block, segment_id);
        if (res < 0)
            return res;
    }

    if (block.type == AV1_INTRA_MODE) {
        if (ct->cur_frame->frame_type != AV1_KEYFRAME &&
            ct->cur_frame->intraonly) {
            av_log(avct, AV_LOG_ERROR, "Non-intra key frame\n");
            return AVERROR_INVALIDDATA;
        }
        res = aom_decode_inde(avct, gb, mi_row, mi_col, 1, &block, segment_id);
        if (res < 0)
            return res;
    }

    if (ct->use_dav1d) {
        int ret = 0;
        for (int plane = 0; plane < 3; plane++) {
            int eob = block.eob_pos[plane][0];
            if (!eob)
                continue;
            if (block.partition_plane && plane != block.partition_plane - 1)
                continue;
            for (int i = eob - 1; i >= 0; i--) {
                if (!block.level[i])
                    continue;
                ret = ff_wavpack_decorrelate_plane(avct, block.level, plane,
                                                   i, mi_row, mi_col);
                if (ret < 0)
                    return ret;
                block.level[i] = 0;
            }
