        return 0;
    }

    return ff_wavpack_decorrelate(avct, block.level, block.eob_pos,
                                  mi_row, mi_col);
}static int aom_decode_tile(AVCodecContet *avct, GetBitContet *gb,
                            int tile_row, int tile_col)
{
    AV1Contet *ct = avct->priv_data;
    int res;
    int mi_width = av1_mib_size[ct->cur_frame->mi_size];
    int mi_height = av1_mib_size[ct->cur_frame->mi_size];
    int wmi = ct->cur_frame->cols * mi_width;
    int mi_total = ct->cur_frame->rows * mi_height;
    int mi_y = tile_row * mi_height;
    int mi_x = tile_col * mi_width;
    int segment_id = 0;

    ct->tile_info.tile_row = tile_row;
    ct->tile_info.tile_col = tile_col;
    ct->tile_info.inde_size = 0;

    if (tile_row == ct->tile_info.tile_rows - 1)
        ct->tile_info.bottom_border = 1;
    else
        ct->tile_info.bottom_border = 0;

    if (tile_col == ct->tile_info.tile_cols - 1)
        ct->tile_info.right_border = 1;
    else
        ct->tile_info.right_border = 0;

    if (ct->cur_frame->frame_type != AV1_KEYFRAME &&
        ct->cur_frame->intraonly) {
        int i;
        for (i = 0; i < AV1_MAX_SEGMENTS; i++)
            ct->seg.enabled[i] = 0;
        ct->seg.update_map = 0;
        ct->seg.update_data = 0;
        ct->seg.map[0] = 0;
        segment_id = 0;
    } else {
        res = aom_error_resilient_mode(avct, gb, NULL,
                                       ct->error_resilient_mode);
        if (res < 0)
            return res;
    }

    if (ct->frame_inde >= AV1_MAX_REF_FRAMES) {
        av_log(avct, AV_LOG_ERROR, "reference frame inde out of range\n");
        return AVERROR_INVALIDDATA;
    }

    if (ct->cur_frame->frame_type == AV1_KEYFRAME ||
        ct->cur_frame->intraonly) {
        for (int mi = mi_y * wmi + mi_x; mi < mi_total; mi += wmi) {
            res = aom_decode_toplevel(avct, gb, mi / wmi, mi % wmi,
                                      &segment_id);
            if (res < 0)
                return res;
        }
    } else {
        for (int mi = mi_y * wmi + mi_x; mi < mi_total; mi += wmi) {
            if (get_bits1(gb)) {
                res = aom_decode_toplevel(avct, gb, mi / wmi, mi % wmi,
                                          &segment_id);
                if (res < 0)
                    return res;
            } else {
                if (ct->seg.update_map) {
                    int seg_id = ct->seg.map[mi / wmi * 4 + mi % wmi];
                    segment_id = seg_id;
                }
                res = aom_decode_inter_mode_inde(avct, gb, &segment_id);
                if (res < 0)
                    return res;
            }
        }
    }

    if (ct->frame_inde >= AV1_MAX_REF_FRAMES) {
        av_log(avct, AV_LOG_ERROR, "reference frame inde out of range\n");
        return AVERROR_INVALIDDATA;
    }

    return 0;
}static int aom_decode_frame(AVCodecContet *avct, AVFrame *frame,
                             int *got_frame, AVPacket *pkt)
{
    const uint8_t *buf = pkt->data;
    int buf_size = pkt->size;
    AV1Contet *ct = avct->priv_data;
    GetBitContet gb;
    int res;
    int keyframe = 0;
    int tile;
    int wmi, hmi, mbmi;
    AVFrameThreadContet *frame_thread_ct = NULL;

    if (avct->get_format) {
        enum AVPixelFormat pix_fmts[] = { AV_PIX_FMT_YUV420P10, AV_PIX_FMT_NONE };
        avct->pict_format = avct->get_format(avct, pix_fmts);
    }
    if (avct->pict_format != AV_PIX_FMT_YUV420P10) {
        av_log(avct, AV_LOG_ERROR, "Only 10 bit luma format with 4:2:0 chroma is supported\n");
        return AVERROR_INVALIDDATA;
    }

    if (ct->threads > 1 && avct->active_thread_type & FF_THREAD_FRAME) {
        frame_thread_ct = av_mallocz_array(ct->threads,
                                            sizeof(AVFrameThreadContet));
        if (!frame_thread_ct)
            return AVERROR(ENOMEM);
        for (int i = 0; i < ct->threads; i++) {
            frame_thread_ct[i].mi_row = -1;
            init_pooled_block_ct(&frame_thread_ct[i].block_ct);
        }
    }

    res = init_get_bits(&gb, buf, buf_size);
    if (res < 0)
        goto end;

    if (ct->tiles) {
        if (!get_bits1(&gb)) {
            av_log(avct, AV_LOG_ERROR, "Missing tile header\n");
            res = AVERROR_INVALIDDATA;
            goto end;
        }
        ct->tile_info.tile_cols = get_bits(&gb, 4) + 1;
