void Http2Session::onRstStreamFrame(const auto& frame) {
  auto stream = getStream(frame.stream_id);
  if (!stream) {
    VLOG(5) << "rst_stream frame received for non-eist stream " << frame.stream_id;
    return;
  }

  // If stream is already in pending state, just update error code and return.
  if (stream->isPending()) {
    VLOG(5) << "stream " << frame.stream_id << " is already in pending state";
    stream->setErrorCode(frame.error_code);
    return;
  }

  // If we receive rst_stream frame for the stream which is already
  // closed, it means that we probably race with server.  Just close
  // stream immediately.
  if (stream->isClosed()) {
    VLOG(5) << "stream " << frame.stream_id << " is already closed";
    onStreamClosed(stream, ErrorCode::CANCEL);
    return;
  }

  // If stream is in different state, it means that we are receiving
  // rst_stream frame for the stream eist in the HTTP/2 session.  In
  // this case, we have to close the stream immediately.
  VLOG(5) << "immediately close stream " << frame.stream_id;
  onStreamClosed(stream, toCppErrorCode(frame.error_code));
}

