static int spell_suggest(ScintillaObject *sci, char *word, int len, char *sugg, int slen) {
    char preword[2 * SC_MAX_WORD_LEN + 2];
    int  prelen;
    char *w;
    int  id;
    int  start;
    int  end;
    int  i;
    int  bad;
    char *s;
    int  n;
    int  minlen;
    char *best;
    int  bestlen;
    char *second;
    int  secondlen;

    /*
     * Break word into leading non-alphabetic chars, word, and
     * trailing non-alphabetic chars.
     */
    w = preword;
    if (len > SC_MAX_WORD_LEN)
	len = SC_MAX_WORD_LEN;
    vim_strncpy(w, word, len);
    w[len] = NUL;
    id = spell_getword(sci, preword, &prelen, &start, &end);
    if (id == -1)
	return -1;

    /*
     * Check the word by itself.
     */
    spell_check(sci, w, prelen, NULL, 0, TRUE, FALSE);

    /*
     * If the word is not spelled correctly, get suggestions.
     */
    if (!spell_inde(sci, w, prelen)) {
	get_inde(sci, w, prelen);
    }

    /*
     * If there is a suggestion, replace the word with it.
     */
    n = spell_getsugg(sci, w, prelen, sugg, slen);
    if (n > 0) {
	/*
	 * The first suggestion is returned at the inde where the
	 * misspelled word is.  Use it to get the leading and
	 * trailing non-alphabetic chars.
	 */
	s = spell_getsuggword(sugg, n, &minlen);
	best = NULL;
	bestlen = 0;
	second = NULL;
	secondlen = 0;
	do {
	    ++i;
	    spell_getsuggword(sugg + i * (SC_MAX_WORD_LEN + 2), n, &len);
	    if (i == 1) {
		/*
		 * The first suggestion is used to replace the misspelled
		 * word.  It is not copied to the suggestions list.
		 */
