static bool try_to_flush_cache(tee_time_t not_before, bool user)
{
	if (optee.os_persistent_cache && optee.cache_timeout) {
		if (tee_monotonic_time_cmp(not_before,
					   optee.cache_clean_before) <= 0)
			return false;
		if (user)
			return false;
		tee_ram_flush_cache(0, -1);
		optee.cache_clean_before = not_before;
		optee.cache_clean_before.tv_nsec += optee.cache_timeout * 1000000000UL;
		if (optee.cache_clean_before.tv_nsec >= 1000000000UL) {
			optee.cache_clean_before.tv_sec++;
			optee.cache_clean_before.tv_nsec -= 1000000000UL;
		}
		return true;
	}
	return false;
}

