                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_UNKNOWN_CIPHER_RETURNED);
                    goto f_err;
                } else {
                    sk = ssl_get_ciphers_by_id(s);
                    i = sk_SSL_CIPHER_find(sk, c);
                    if (i < 0) {
                        /* wrong version of cipher */
                        al = SSL_AD_ILLEGAL_PARAMETER;
                        s->s3->tmp.alert_type = al;
                        SSLerr(SSL_F_SSL3_ACCEPT,
                               SSL_R_WRONG_CIPHER_RETURNED);
                        goto f_err;
                    }
                    s->s3->tmp.new_cipher = c;
                    /*
                     * Don't digest cached records if no sigalgs: we may
                     * need them for client authentication.
                     */
                    if (!SSL_USE_SIGALGS(s) && !ssl3_digest_cached_records(s))
                        goto f_err;
                }
