                /* process TLSEXTs */
                if (!ssl_parse_clienthello_tlset(s, p, d + n)) {
                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_PARSE_TLSEXT);
                    goto err;
                }
                /* If we have no signature algorithms, digest cached records */
                if (SSL_USE_SIGALGS(s) && !s->s3->tmp.sigalgs
                    && !ssl3_digest_cached_records(s))
                    goto f_err;
#endif

                /* lets get the client hello version */
                j = get_net16(d);
                if (s->version == SSL3_VERSION && j == TLS1_VERSION)
                    s->version = j;
                if (s->version != j) {
                    /* wrong version */
                    al = SSL_AD_PROTOCOL_VERSION;
                    s->s3->tmp.alert_type = al;
                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_WRONG_VERSION_NUMBER);
                    goto f_err;
                }

                s->accept_state = ssl3_accept_wait_client_key_exchange;
                break;
            }
        }

        if (s->s3->tmp.message_type == SSL3_MT_CLIENT_KEY_EXCHANGE) {
            if (s->s3->tmp.new_cipher->algorithms & SSL_aNULL) {
                /* NULL cipher, no key exchange */
                if (p[0] != 0) {
                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_ILLEGAL_CLIENT_KEY_EXCHANGE);
                    goto err;
                }
                s->s3->tmp.key_material_length = 0;
            } else if (s->method->ssl3_client_key_exchange == NULL) {
                al = SSL_AD_INTERNAL_ERROR;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_UNKNOWN_CIPHER_RETURNED);
                goto f_err;
            } else {
                i = s->method->ssl3_client_key_exchange(s, p, n);
                if (i < 0)
                    return (i);
                if (i == 0) {
                    al = SSL_AD_ILLEGAL_PARAMETER;
                    s->s3->tmp.alert_type = al;
                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_BAD_CLIENT_KEY_EXCHANGE);
                    goto f_err;
                }
                s->s3->tmp.key_material_length = i;
            }
            break;
        }

        if (s->s3->tmp.message_type == SSL3_MT_CLIENT_KEY_EXCHANGE
            && s->s3->tmp.new_cipher->algorithms & SSL_eNULL) {
            /* eNULL, no compression */
            if (p[0] != 0) {
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_ILLEGAL_CLIENT_KEY_EXCHANGE);
                goto err;
            }
            s->s3->tmp.new_compression = NULL;
            break;
        }

        if (s->s3->tmp.message_type == SSL3_MT_COMPRESSED_CERTIFICATE) {
            if (s->method->ssl3_certificate == NULL) {
                al = SSL_AD_INTERNAL_ERROR;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_NO_CERT_SET_FOR_US_TO_VERIFY);
                goto f_err;
            }
            eticklen = n;
            etick = p;
            s->accept_state = ssl3_accept_wait_client_key_exchange;
            break;
        }

        if (s->s3->tmp.message_type == SSL3_MT_CERTIFICATE) {
            if (s->method->ssl3_certificate == NULL) {
                al = SSL_AD_INTERNAL_ERROR;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_NO_CERT_SET_FOR_US_TO_VERIFY);
                goto f_err;
            }
            s->s3->tmp.cert_req = 1;
            s->s3->tmp.need_cert_verify = 1;

            /*
             * must have at least one valid signature algorithm, if
             * signature algorithms extension was received
             */
            if (s->s3->tmp.sigalgs && !ssl3_check_cert_sig(s, p, n)) {
                al = SSL_AD_ILLEGAL_PARAMETER;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_WRONG_SIGNATURE_TYPE);
                goto f_err;
            }

            s->accept_state = ssl3_accept_wait_client_key_exchange;
            break;
        }

        if (s->s3->tmp.message_type == SSL3_MT_CERTIFICATE_REQUEST) {
            if (s->method->ssl3_certificate == NULL) {
                al = SSL_AD_INTERNAL_ERROR;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_NO_CERT_SET_FOR_US_TO_VERIFY);
                goto f_err;
            }
            s->s3->tmp.cert_req = 1;
            if (s->s3->tmp.message_length == 1) {
                /* no signature algorithms sent */
                s->s3->tmp.need_cert_verify = 0;
            } else {
                /* must have at least one valid signature algorithm */
                if (!ssl3_check_cert_sig(s, p, n)) {
                    al = SSL_AD_ILLEGAL_PARAMETER;
                    s->s3->tmp.alert_type = al;
                    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_WRONG_SIGNATURE_TYPE);
                    goto f_err;
                }
                s->s3->tmp.need_cert_verify = 1;
            }

            s->accept_state = ssl3_accept_wait_client_key_exchange;
            break;
        }

        if (s->s3->tmp.message_type == SSL3_MT_SERVER_HELLO_DONE) {

            if (s->s3->tmp.message_length != 0) {
                al = SSL_AD_DECODE_ERROR;
                s->s3->tmp.alert_type = al;
                SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_BAD_MESSAGE_TYPE);
                goto f_err;
            }

            break;
        }

        /* invalid message type */
        al = SSL_AD_DECODE_ERROR;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_BAD_MESSAGE_TYPE);
        goto f_err;
    }

