     * At this point, we have received a client hello, and the message type
     * is correct. We now know the version and can use the right functions.
     */

    /* check is not needed I believe */
    if (s->method->version != s->version) {
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_WRONG_VERSION_NUMBER);
        return (SSL_AD_PROTOCOL_VERSION);
    }

    if (s->info_callback != NULL)
        s->info_callback(s, SSL_CB_HANDSHAKE_START, 0);

    /*
     * Check if the client is allowed to talk to us.  First we check if the
     * hostname in the client's certificate is acceptable.  (This will be a
     * no-op if SSL_OP_NO_SESSION_RESUMPTION_ON_RENEGOTIATION is in
     * effect.)
     */
    if (s->session && s->session->peer && s->session->enc_write_ct
        && (s->peer->cert || s->peercert)) {
        sess = s->session;
        if (!ssl3_session_is_resumable(s, sess)) {
            SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_INCONSISTENT_PROTOCOL_VERSION_NUMBER);
            goto err;
        }
    }

    if (!ssl3_check_client_hello(s, session_id, session_id_num)) {
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_CLIENTHELLO_INCOMPATIBLE);
        goto err;
    }

    if (ct && ct->peer && ct->peer->key && ct->peer->key->type == EVP_PKEY_GOST01) {
        if (!ssl3_check_client_key_exchange(s, etick, eticklen)) {
            SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_CLIENT_KEY_EXCHANGE_ERROR);
            goto err;
        }
    }

    /* get new session information if needed */
    if (s->s3->tmp.new_session) {
        if (!ssl3_get_new_session(s))
            goto err;
    } else {
        /* else reuse old session */
        if (!ssl3_reuse_session(s))
            goto err;
    }

    /* Just in case some client sent us a ticket and we don't support it */
    if (s->session && s->session->tlset_tick && !SSL_TICKET_eENABLED(s)) {
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_SSL_SESSION_TICKET_NOT_SUPPORTED);
        goto err;
    }

    /* Do we need to send a certificate? */
    if (s->method->ssl3_certificate != NULL && s->s3->tmp.cert_req) {
        if (!s->method->ssl3_certificate(s))
            goto err;
    }

    /* Send our server hello */
    i = ssl3_send_server_hello(s);
    if (i < 0)
        return (i);
    if (i == 0) {
        s->accept_state = ssl3_accept_wait_client_hello;
        return (SSL_accept(s));
    }

    /* set up encrpytion and MAC */
    if (!ssl3_setup_cipher_and_mac(s)) {
        al = SSL_AD_INTERNAL_ERROR;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_CIPHER_OR_HASH_UNAVAILABLE);
        goto f_err;
    }

    /* let the application know we're ready for pre-shared tickets */
    if (s->server && SSL_TICKET_eENABLED(s) && s->session && s->session->tlset_tick) {
        if (s->info_callback != NULL)
            s->info_callback(s, SSL_CB_TICKET_CB, 0);
    }

    /*
     * Send a certificate if we have one.  (This will also do server
     * authentication if required.)
     */
    if (ct && ct->peer && ct->peer->key && ct->peer->key->type == EVP_PKEY_GOST01) {
        i = ssl3_send_client_key_exchange(s, etick, eticklen);
        if (i < 0)
            goto err;
        if (i == 0) {
            s->accept_state = ssl3_accept_wait_client_key_exchange;
            return (SSL_accept(s));
        }
    }

    /* We should not send a certificate if we don't have one */
    if (s->method->ssl3_certificate != NULL && s->s3->tmp.cert_req) {
        al = SSL_AD_INTERNAL_ERROR;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_CERTIFICATE_REQ_SENT_BUT_NO_CERTIFICATE_PRESENT);
        goto f_err;
    }

    i = ssl3_send_server_key_exchange(s);
    if (i < 0)
        goto err;
    if (i == 0) {
        s->accept_state = ssl3_accept_wait_server_key_exchange;
        return (SSL_accept(s));
    }

    i = ssl3_send_certificate_request(s);
    if (i < 0)
        goto err;

    /* Send server hello done */
    i = ssl3_send_server_hello_done(s);
    if (i < 0)
        goto err;
    if (i == 0) {
        s->accept_state = ssl3_accept_wait_server_hello_done;
        return (SSL_accept(s));
    }

    s->accept_state = ssl3_accept_wait_change_cipher_spec;
    /* get the client's change cipher spec */
    d = tick;
    n = s->method->ssl_get_message(s, SSL3_RT_CHANGE_CIPHER_SPEC,
            SSL3_MT_CHANGE_CIPHER_SPEC, d, SSL3_RT_MAX_PACKET_SIZE,
            &empty_fragment);
    if (n <= 0)
        return (int)n;
    if (s->s3->tmp.message_type == SSL3_MT_CHANGE_CIPHER_SPEC)
        break;

    /* else HTET */
    al = SSL_AD_UNEXPECTED_MESSAGE;
    s->s3->tmp.alert_type = al;
    SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_BAD_MESSAGE_TYPE);
    goto f_err;

    for (;;) {
        /* get the client's finished */
        d = tick;
        n = s->method->ssl_get_message(s, SSL3_RT_HANDSHAKE,
                SSL3_MT_FINISHED, d, SSL3_RT_MAX_PACKET_SIZE,
                &empty_fragment);
        if (n <= 0)
            return (int)n;         /* error or fatal handshake condition */
        if (s->s3->tmp.message_type == SSL3_MT_FINISHED)
            break;

        /* else HTET */
        al = SSL_AD_UNEXPECTED_MESSAGE;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_BAD_MESSAGE_TYPE);
        goto f_err;
    }

    if (!ssl3_verify_finished(s, p, n)) {
        al = SSL_AD_DECODE_ERROR;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_DIGEST_CHECK_FAILED);
        goto f_err;
    }

    if (s->s3->tmp.new_session)
        ssl3_send_newsession_ticket(s);

    /* send the change cipher spec message */
    i = ssl3_send_change_cipher_spec(s);
    if (i < 0)
        goto err;

    /* get the server's finished */
    d = tick;
    n = s->method->ssl_get_message(s, SSL3_RT_HANDSHAKE,
            SSL3_MT_FINISHED, d, SSL3_RT_MAX_PACKET_SIZE, &empty_fragment);
    if (n <= 0)
        return (int)n;         /* error or fatal handshake condition */

    if (!ssl3_verify_finished(s, p, n)) {
        al = SSL_AD_DECODE_ERROR;
        s->s3->tmp.alert_type = al;
        SSLerr(SSL_F_SSL3_ACCEPT, SSL_R_DIGEST_CHECK_FAILED);
        goto f_err;
    }

    s->s3->tmp.reuse_message = 1;
    return (1);
 f_err:
    ssl3_send_alert(s, SSL3_AL_FATAL, al);
 err:
    return (0);
}

