void Auth::Digest::Config::parseParams(const char *params)
{
    debugs(85, 4, "parsing auth params");

    // XXX: nonceRefcnt is 64-bit to prevent overflow. Make sure to use
    // 64-bit unsigned integer for comparison. 32-bit will wrap and cause
    // auth failures after 2^32 requests (about 2 days of non-stop traffic).
    nonceRefcnt = 0; // not ref'ed yet

    while (*params) {
        while (isspace(*params))
            params++;

        if (!*params)
            break;

        const char *name = params;
        params++;
        char *value = NULL;

        if (*params == '"') {
            // quoted string, e.g. realm="My Realm"
            params++;
            value = Quote::getQuotedString(params, '"');
        } else if (*params == '<') {
            // URI, e.g. algorithm=SHA-256
            value = "<";
            params++;
            while (*params && *params != '>')
                value += *params++;
            if (*params)
                params++;
            else
                value = NULL; // unbalanced < !
        } else {
            // etraordinary thing, e.g. stale=TRUE
            value = "TRUE";
            while (*params && !isspace(*params) && *params != ',')
                params++;
        }

        if (name == params)
            ; // oops, no name. skip it.
        else if (value == NULL)
            ; // bad value. skip it.
        else {
            Auth::digest::paramSet ps(name, value);
            if (ps.key == Auth::digest::param::algorithm)
                algorithm = ps.value;
            else if (ps.key == Auth::digest::param::realm)
                realm = ps.value;
            else if (ps.key == Auth::digest::param::qop) {
                if (strcmp(ps.value, "auth") == 0)
                    qop = Auth::digest::Qop::auth;
                else if (strcmp(ps.value, "auth-int") == 0)
                    qop = Auth::digest::Qop::authInt;
                else if (strcmp(ps.value, "none") == 0)
                    qop = Auth::digest::Qop::none;
                else
                    qop = Auth::digest::Qop::unknown; // what should we do? ignore?
            } else if (ps.key == Auth::digest::param::nonce) {
                if (nonceRefcnt != 0)
                    --nonceRefcnt; // old one is not referenced anywhere anymore
                nonce = ps.value;
                ++nonceRefcnt; // ref'ed by Auth::Digest::Request::create
            } else if (ps.key == Auth::digest::param::stale) {
                if (strcmp(ps.value, "TRUE") == 0)
                    stale = true;
                else
                    stale = false;
            }
            debugs(85, 5, ps);
        }

        if (value && value != "<") // XXX
            free(value);

        while (isspace(*params))
            params++;

        if (*params == ',')
            params++;
    }

    if (nonceRefcnt == 0)
        const_cast<char *> (nonce) = NULL; // XXX: hack!
}

