  uint64 hashed_output = hash_key_;
  for (size_t i = 0; i < permutation.size(); ++i) {
    uint64 hash_i = columns_[i]->Feature(batch_inde, permutation[i], false);
    hashed_output = FingerprintCat64(hashed_output, hash_i);
