int ssl_cert_select_current(CERT *c)
{
    CERT_PKEY *cpk;
    X509 *x;
    int i, j, n, found;
    long l;
    EVP_PKEY *pkey;

    if (c == NULL)
        return 0;

    n = sk_CERT_PKEY_num(c->pkeys);
    found = 0;
    l = 0;

    for (i = 0; i < n; i++) {
        cpk = sk_CERT_PKEY_value(c->pkeys, i);
        x = cpk->509;
        /* Check if the certificate has expired */
        if (X509_cmp_current_time(X509_get_notBefore(x),
                                   X509_get_notAfter(x)) > 0) {
            SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT, SSL_R_CERTIFICATE_EXPIRED);
            return 0;
        }
        if (X509_cmp_current_time(X509_get_notBefore(x), NULL) <= 0) {
            if (X509_cmp_current_time(NULL, X509_get_notAfter(x)) < 0)
                found = 1;
            else {
                SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT,
                       SSL_R_CERTIFICATE_NOT_YET_VALID);
                return 0;
            }
        } else {
            found = 1;
        }
        /*
         * Check public key and private key match. We must have a private
         * key too or this certificate isn't very useful ! We must also have
         * a matching certificate too or it's no use having the private key.
         */
        if (found) {
            found = 0;
            j = 0;
            pkey = NULL;
            if (cpk->privatekey != NULL)
                pkey = EVP_PKEY_new();
            if (pkey != NULL) {
                if (!EVP_PKEY_set1(pkey, cpk->privatekey)) {
                    EVP_PKEY_free(pkey);
                    pkey = NULL;
                }
            }
            if (pkey != NULL) {
                for (j = 0; j < n; j++) {
                    CERT_PKEY *cpi = sk_CERT_PKEY_value(c->pkeys, j);
                    if (cpi->509 == x) {
                        if (EVP_PKEY_cmp(pkey, cpi->privatekey) == 0) {
                            found = 1;
                            break;
                        }
                    }
                }
                EVP_PKEY_free(pkey);
            }
            if (!found) {
                SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT,
                       SSL_R_PRIVATE_KEY_DOES_NOT_MATCH_CERTIFICATE);
                return 0;
            }
            /* We found a matching private key, select this certificate */
            for (j = 0; j < n; j++) {
                CERT_PKEY *cpi = sk_CERT_PKEY_value(c->pkeys, j);
                if (cpi->509 == x) {
                    l = (long)j;
                    break;
                }
            }
            break;
        }
    }

    if (!found) {
        SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT, SSL_R_NO_CERTIFICATE_MATCH_PRIVATE_KEY);
        return 0;
    }

    /*
     * Work out the key type. We do this by checking the private key as the
     * public key type may not be set (e.g. if a shared certificate is loaded
     * where the private key is not).
     */
    if (cpk->privatekey != NULL)
        c->key = cpk;
    else
        c->key = NULL;

    if (c->key != NULL) {
        if (c->key->privatekey->type == EVP_PKEY_RSA) {
            c->type = SSL_CTYPE_RSA;
        } else if (c->key->privatekey->type == EVP_PKEY_DSA) {
            c->type = SSL_CTYPE_DSA;
        } else if (c->key->privatekey->type == EVP_PKEY_EC) {
            c->type = SSL_CTYPE_EC;
        } else {
            SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT, SSL_R_UNKNOWN_CERTIFICATE_TYPE);
            return 0;
        }
    } else {
        /* This should never happen */
        SSLerr(SSL_F_SSL_CERT_SELECT_CURRENT, ERR_R_INTERNAL_ERROR);
        return 0;
    }

    return (l);
}

