	*size -= 2;
	// read this class
	if (*size <= 0) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	if (r_io_read_at (bin->io, p, buf, 2) != 2) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	inde = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	if (inde) {
		cl->name = r_vector_get_i (&bin->consts, inde - 1);
	}
	// read super class
	if (*size <= 0) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	if (r_io_read_at (bin->io, p, buf, 2) != 2) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	inde = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	if (inde) {
		cl->super_name = r_vector_get_i (&bin->consts, inde - 1);
	}
	// read interfaces
	if (*size <= 0) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	n = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	cl->n_interfaces = n;
	if (n) {
		cl->interfaces = malloc (n * sizeof (char*));
		for (inde = 0; inde < n; inde++) {
			if (*size <= 0) {
				break;
			}
			if (r_io_read_at (bin->io, p, buf, 2) != 2) {
				break;
			}
			*size -= 2;
			p += 2;
			inde = *(ut16 *)buf;
			if (!inde) {
				break;
			}
			cl->interfaces[inde - 1] = r_vector_get_i (&bin->consts, inde - 1);
		}
	}
	// read fields
	if (*size <= 0) {
		r_bin_java_free_class (cl);
		return NULL;
	}
	n = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	for (inde = 0; inde < n; inde++) {
		if (*size <= 0) {
			break;
		}
		RBinJavaField f;
		memset (&f, 0, sizeof (RBinJavaField));
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		*size -= 4;
		p += 4;
		f.access_flags = *(ut16 *)buf;
		ut16 name = *(ut16 *)(buf + 2);
		*size -= 2;
		p += 2;
		if (name) {
			f.name = r_vector_get_i (&bin->consts, name - 1);
		}
		if (*size <= 0) {
			break;
		}
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		*size -= 4;
		p += 4;
		f.descriptor = *(ut16 *)buf;
		name = *(ut16 *)(buf + 2);
		*size -= 2;
		p += 2;
		if (name) {
			f.type = r_vector_get_i (&bin->consts, name - 1);
		}
		r_vector_push (&cl->fields, &f);
	}
	// read methods
	n = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	for (inde = 0; inde < n; inde++) {
		if (*size <= 0) {
			break;
		}
		RBinJavaMethod f;
		memset (&f, 0, sizeof (RBinJavaMethod));
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		*size -= 4;
		p += 4;
		f.access_flags = *(ut16 *)buf;
		ut16 name = *(ut16 *)(buf + 2);
		*size -= 2;
		p += 2;
		if (name) {
			f.name = r_vector_get_i (&bin->consts, name - 1);
		}
		if (*size <= 0) {
			break;
		}
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		*size -= 4;
		p += 4;
		f.descriptor = *(ut16 *)buf;
		name = *(ut16 *)(buf + 2);
		*size -= 2;
		p += 2;
		if (name) {
			f.ret = r_vector_get_i (&bin->consts, name - 1);
		}
		r_vector_push (&cl->methods, &f);
	}
	// read consttructors
	n = *(ut16 *)buf;
	*size -= 2;
	p += 2;
	for (inde = 0; inde < n; inde++) {
		if (*size <= 0) {
			break;
		}
		RBinJavaCons f;
		memset (&f, 0, sizeof (RBinJavaCons));
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		*size -= 4;
		p += 4;
		f.access_flags = *(ut16 *)buf;
		ut16 name = *(ut16 *)(buf + 2);
		*size -= 2;
		p += 2;
		if (name) {
			f.name = r_vector_get_i (&bin->consts, name - 1);
		}
		r_vector_push (&cl->cons, &f);
	}
	return cl;
}static int r_bin_java_get_main_class(RBinJavaObj *bin) {
	RBinJavaClass *cl;
	RBinJavaField *f;
	RBinJavaMethod *m;
	int i, j, k;
	// search for main method
	for (i = 0; i < r_vector_len (&bin->classes); i++) {
		cl = r_vector_get_i (&bin->classes, i);
		if (!cl) {
			continue;
		}
		if (!cl->name) {
			continue;
		}
		if (!strcmp (cl->name->u.str, "java/lang/Object")) {
			continue;
		}
		// search for main method
		for (j = 0; j < r_vector_len (&cl->methods); j++) {
			m = r_vector_get_i (&cl->methods, j);
			if (!m) {
				continue;
			}
			if (!m->name) {
				continue;
			}
			if (!strcmp (m->name->u.str, "main")) {
				return i;
			}
		}
		// search for static initializer
		for (j = 0; j < r_vector_len (&cl->cons); j++) {
			m = r_vector_get_i (&cl->cons, j);
			if (!m) {
				continue;
			}
			if (!m->name) {
				continue;
			}
			if (!strcmp (m->name->u.str, "<clinit>")) {
				return i;
			}
		}
		// search for main field
		for (j = 0; j < r_vector_len (&cl->fields); j++) {
			f = r_vector_get_i (&cl->fields, j);
			if (!f) {
				continue;
			}
			if (!f->name) {
				continue;
			}
			if (!strcmp (f->name->u.str, "main")) {
				return i;
			}
		}
	}
	return -1;
}static int r_bin_java_get_entry(RBinJavaObj *bin) {
	int mainclass = r_bin_java_get_main_class (bin);
	if (mainclass < 0) {
		return -1;
	}
	RBinJavaClass *cl = r_vector_get_i (&bin->classes, mainclass);
	if (!cl) {
		return -1;
	}
	// search for main method
	for (int i = 0; i < r_vector_len (&cl->methods); i++) {
		RBinJavaMethod *m = r_vector_get_i (&cl->methods, i);
		if (!m) {
			continue;
		}
		if (!m->name) {
			continue;
		}
		if (!strcmp (m->name->u.str, "main")) {
			return (int) ((ut8*)m - (ut8*)bin);
		}
	}
	// search for static initializer
	for (int i = 0; i < r_vector_len (&cl->cons); i++) {
		RBinJavaMethod *m = r_vector_get_i (&cl->cons, i);
		if (!m) {
			continue;
		}
		if (!m->name) {
			continue;
		}
		if (!strcmp (m->name->u.str, "<clinit>")) {
			return (int) ((ut8*)m - (ut8*)bin);
		}
	}
	return -1;
}static bool r_bin_java_load_class(RBinJavaObj *bin, ut64 p) {
	ut64 size;
	RBinJavaClass *cl = r_bin_java_class (bin, p, &size);
	if (!cl) {
		return false;
	}
	if (!r_vector_push (&bin->classes, cl)) {
		r_bin_java_free_class (cl);
		return false;
	}
	return true;
}static bool r_bin_java_load_classes(RBinJavaObj *bin) {
	ut8 buf[4];
	ut64 p = bin->cfied->methods_off;
	int i;
	int n = bin->cfied->n_methods;
	if (!n) {
		return true;
	}
	r_vector_free (&bin->classes);
	r_vector_init (&bin->classes, sizeof (RBinJavaClass), (RVectorFree)r_bin_java_free_class);
	for (i = 0; i < n; i++) {
		if (p >= bin->size) {
			break;
		}
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		if (!r_bin_java_load_class (bin, *(ut32*)buf)) {
			break;
		}
		p += 4;
	}
	if (i != n) {
		eprintf ("Warning: only %d of %d classes loaded\n", i, n);
	}
	return true;
}static bool r_bin_java_parse_cfe(RBinJavaObj *bin) {
	ut8 buf[8];
	ut64 p = bin->cfied->off;
	if (!bin->cfied) {
		return false;
	}
	r_io_read_at (bin->io, p, buf, 4);
	bin->cfied->magic = *(ut32 *)buf;
	p += 4;
	r_io_read_at (bin->io, p, buf, 4);
	bin->cfied->version = *(ut32 *)buf;
	p += 4;
	r_io_read_at (bin->io, p, buf, 2);
	bin->cfied->n_methods = *(ut16 *)buf;
	p += 2;
	r_io_read_at (bin->io, p, buf, 2);
	bin->cfied->n_fields = *(ut16 *)buf;
	p += 2;
	r_io_read_at (bin->io, p, buf, 2);
	bin->cfied->n_cons = *(ut16 *)buf;
	p += 2;
	r_io_read_at (bin->io, p, buf, 2);
	bin->cfied->n_attrs = *(ut16 *)buf;
	p += 2;
	if (bin->cfied->magic != 0cafebabe) {
		eprintf ("Not a valid java class\n");
		return false;
	}
	bin->entry = r_bin_java_get_entry (bin);
	return true;
}static bool r_bin_java_parse_class(RBinJavaObj *bin) {
	ut8 buf[4];
	ut64 p = 0;
	if (!bin) {
		return false;
	}
	if (bin->entries && r_vector_len (bin->entries) > 0) {
		p = *(ut64 *)r_vector_get_i (bin->entries, 0);
	}
	if (p > bin->size) {
		return false;
	}
	if (!r_io_read_at (bin->io, p, buf, 4)) {
		return false;
	}
	if (*(ut32 *)buf != 0cafebabe) {
		return false;
	}
	bin->cfied = R_NEW0 (RBinJavaCfied);
	if (!bin->cfied) {
		return false;
	}
	bin->cfied->off = p;
	return r_bin_java_parse_cfe (bin);
}static bool r_bin_java_load_meta(RBinJavaObj *bin) {
	bin->entries = r_meta_new_list ();
	if (!bin->entries) {
		return false;
	}
	ut8 buf[4];
	ut64 p = 0;
	while (p < bin->size) {
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		if (*(ut32 *)buf == 0cafebabe) {
			bin->cfied = R_NEW0 (RBinJavaCfied);
			if (!bin->cfied) {
				return false;
			}
			bin->cfied->off = p;
			if (!r_bin_java_parse_cfe (bin)) {
				free (bin->cfied);
				bin->cfied = NULL;
				break;
			}
			p += 4 + 2 + 2 + 2 + 2;
			break;
		}
		RBinMeta *meta = R_NEW0 (RBinMeta);
		if (!meta) {
			break;
		}
		ut64 p1 = p;
		ut64 inde = 0;
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			free (meta);
			break;
		}
		p += 4;
		// inde
		if (buf[0] == 00 || buf[0] == 0ff) {
			inde = *(ut32 *)buf;
			p1 += 4;
		} else {
			eprintf ("Warning: inde not supported\n");
			free (meta);
			break;
		}
		// type
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			free (meta);
			break;
		}
		p += 4;
		char *str = r_str_new_bin (bin, p, *(ut16 *)buf);
		if (!str) {
			free (meta);
			break;
		}
		p1 += *(ut16 *)buf;
		meta->type = str;
		// value
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			free (meta);
			break;
		}
		p += 4;
		p1 += 4;
		switch (buf[0]) {
		case 07:
			// long
			if (r_io_read_at (bin->io, p, buf, 8) != 8) {
				free (meta);
				break;
			}
			p += 8;
			p1 += 8;
			meta->value = ut64ToString (*(ut64 *)buf);
			break;
		case 06:
			// float
			if (r_io_read_at (bin->io, p, buf, 4) != 4) {
				free (meta);
				break;
			}
			p += 4;
			p1 += 4;
			meta->value = f64ToString (*(double *)buf);
			break;
		case 05:
			// double
			if (r_io_read_at (bin->io, p, buf, 8) != 8) {
				free (meta);
				break;
			}
			p += 8;
			p1 += 8;
			meta->value = f64ToString (*(double *)buf);
			break;
		case 04:
			// int
			if (r_io_read_at (bin->io, p, buf, 4) != 4) {
				free (meta);
				break;
			}
			p += 4;
			p1 += 4;
			meta->value = ut32ToString (*(ut32 *)buf);
			break;
		case 03:
			// short
			if (r_io_read_at (bin->io, p, buf, 2) != 2) {
				free (meta);
				break;
			}
			p += 2;
			p1 += 2;
			meta->value = ut16ToString (*(ut16 *)buf);
			break;
		case 02:
			// byte
			if (r_io_read_at (bin->io, p, buf, 1) != 1) {
				free (meta);
				break;
			}
			p += 1;
			p1 += 1;
			meta->value = ut8ToString (*(ut8 *)buf);
			break;
		case 08:
			// string
			// class inde
			if (r_io_read_at (bin->io, p, buf, 4) != 4) {
				free (meta);
				break;
			}
			p += 4;
			p1 += 4;
			inde = *(ut32 *)buf;
			if (!inde) {
				break;
			}
			RBinJavaConst *cn = r_vector_get_i (&bin->consts, inde - 1);
			if (!cn) {
				break;
			}
			if (cn->type != 1) {
				break;
			}
			meta->value = cn->u.str;
			break;
		default:
			break;
		}
		if (!meta->value) {
			free (meta->type);
			free (meta);
			break;
		}
		r_meta_add (bin->entries, inde, meta);
		p = p1;
	}
	return true;
}static bool r_bin_java_parse_field(RBinJavaField *f, RBinJavaObj *bin, ut64 p, int n) {
	ut8 buf[8];
	if (n <= 0) {
		return false;
	}
	while (n > 0) {
		if (p >= bin->size) {
			return false;
		}
		if (r_io_read_at (bin->io, p, buf, 8) != 8) {
			return false;
		}
		f->access_flags = *(ut16 *)buf;
		ut16 nameinde = *(ut16 *)(buf + 2);
		ut16 typeinde = *(ut16 *)(buf + 4);
		ut16 attrsinde = *(ut16 *)(buf + 6);
		if (!nameinde || !typeinde) {
			return false;
		}
		f->name = r_vector_get_i (&bin->consts, nameinde - 1);
		f->descriptor = r_vector_get_i (&bin->consts, typeinde - 1);
		f->n_attrs = attrsinde;
		p += 8;
		n--;
	}
	return true;
}static bool r_bin_java_parse_fields(RBinJavaObj *bin) {
	ut8 buf[4];
	ut64 p = bin->cfied->fields_off;
	int n = bin->cfied->n_fields;
	RBinJavaField f;
	memset (&f, 0, sizeof (RBinJavaField));
	if (!r_bin_java_parse_field (&f, bin, p, n)) {
		return false;
	}
	return true;
}static bool r_bin_java_parse_method(RBinJavaMethod *f, RBinJavaObj *bin, ut64 p, int n) {
	ut8 buf[128];
	if (n <= 0) {
		return false;
	}
	while (n > 0) {
		if (p >= bin->size) {
			return false;
		}
		if (r_io_read_at (bin->io, p, buf, 15) != 15) {
			return false;
		}
		f->access_flags = *(ut16 *)buf;
		ut16 nameinde = *(ut16 *)(buf + 2);
		ut16 typeinde = *(ut16 *)(buf + 4);
		ut16 attrsinde = *(ut16 *)(buf + 6);
		ut16 codeinde = *(ut16 *)(buf + 8);
		ut32 code_length = *(ut32 *)(buf + 10);
		if (!nameinde || !typeinde) {
			return false;
		}
		f->name = r_vector_get_i (&bin->consts, nameinde - 1);
		f->descriptor = r_vector_get_i (&bin->consts, typeinde - 1);
		f->n_attrs = attrsinde;
		if (codeinde && code_length) {
			f->code = R_NEW0 (RBinJavaCode);
			if (!f->code) {
				return false;
			}
			f->code->inde = codeinde;
			f->code->size = code_length;
			if (!r_vector_push (&bin->codes, f->code)) {
				return false;
			}
		}
		p += 15;
		n--;
	}
	return true;
}static bool r_bin_java_parse_methods(RBinJavaObj *bin) {
	ut8 buf[4];
	ut64 p = bin->cfied->methods_off;
	int n = bin->cfied->n_methods;
	RBinJavaMethod f;
	memset (&f, 0, sizeof (RBinJavaMethod));
	if (!r_bin_java_parse_method (&f, bin, p, n)) {
		return false;
	}
	return true;
}static bool r_bin_java_parse_cons(RBinJavaCons *f, RBinJavaObj *bin, ut64 p, int n) {
	ut8 buf[4];
	if (n <= 0) {
		return false;
	}
	while (n > 0) {
		if (p >= bin->size) {
			return false;
		}
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			return false;
		}
		f->access_flags = *(ut16 *)buf;
		ut16 nameinde = *(ut16 *)(buf + 2);
		ut16 attrsinde = *(ut16 *)(buf + 4);
		if (!nameinde) {
			return false;
		}
		f->name = r_vector_get_i (&bin->consts, nameinde - 1);
		f->n_attrs = attrsinde;
		p += 4;
		n--;
	}
