}static bool r_bin_java_parse_constructors(RBinJavaObj *bin) {
	ut8 buf[4];
	ut64 p = bin->cfied->cons_off;
	int n = bin->cfied->n_cons;
	RBinJavaCons f;
	memset (&f, 0, sizeof (RBinJavaCons));
	if (!r_bin_java_parse_cons (&f, bin, p, n)) {
		return false;
	}
	return true;
}static bool r_bin_java_parse_code(RBinJavaObj *bin) {
	ut8 buf[4];
	RBinJavaCode *cd;
	ut64 p;
	int i, j, k;
	int n = r_vector_len (&bin->codes);
	if (!n) {
		return true;
	}
	for (i = 0; i < n; i++) {
		cd = r_vector_get_i (&bin->codes, i);
		if (!cd) {
			continue;
		}
		p = cd->inde;
		if (p >= bin->size) {
			break;
		}
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		p += 4;
		cd->stack_size = *(ut16 *)buf;
		cd->locals_size = *(ut16 *)(buf + 2);
		k = *(ut32 *)buf;
		cd->size = k;
		if (k == 0) {
			continue;
		}
		if (p + k > bin->size) {
			break;
		}
		cd->code = malloc (k);
		if (!cd->code) {
			break;
		}
		if (r_io_read_at (bin->io, p, cd->code, k) != k) {
			break;
		}
		p += k;
		// read exception
		if (r_io_read_at (bin->io, p, buf, 4) != 4) {
			break;
		}
		k = *(ut32 *)buf;
		cd->n_exceptions = k;
		p += 4;
		if (k) {
			cd->exceptions = malloc (k * sizeof (RBinJavaException));
			for (j = 0; j < k; j++) {
				if (r_io_read_at (bin->io, p, buf, 8) != 8) {
					break;
				}
				cd->exceptions[j].start = *(ut16 *)buf;
				cd->exceptions[j].end = *(ut16 *)(buf + 2);
				cd->exceptions[j].handler = *(ut16 *)(buf + 4);
				cd->exceptions[j].catch_type = *(ut16 *)(buf + 6);
				p += 8;
			}
		}
		// read ops
		cd->ops = r_list_new ();
		if (!cd->ops) {
			break;
		}
		ut16 last = 0;
		ut32 c;
		char str[128];
		RList *ops = cd->ops;
		for (i = 0; i < cd->size; i++) {
			ut8 *ptr = cd->code + i;
			ut8 a = *(ut8 *)ptr++;
			ut8 b = *(ut8 *)ptr++;
			ut8 c1 = *(ut8 *)ptr++;
			ut8 c2 = *(ut8 *)ptr++;
			ut8 c3 = *(ut8 *)ptr++;
			RBinJavaOp *op = R_NEW0 (RBinJavaOp);
			if (!op) {
				break;
			}
			op->address = last;
			c = (a << 24) | (b << 16) | (c1 << 8) | c2;
			op->opcode = c3;
			switch (c3) {
			case 0100: // nop
				break;
			case 0118: // aconst_null
				break;
			case 0129: // iconst_m1
				break;
			case 0130: // iconst_0
				break;
			case 0131: // iconst_1
				break;
			case 0132: // iconst_2
				break;
			case 0133: // iconst_3
				break;
			case 0134: // iconst_4
