    redisCommand *cmd;

    if (c == NULL) return;

    /* Create command structure */
    cmd = createCommandFromArgv(c,NULL,argc,(void*)argvlen);
    if (cmd == NULL) return;

    /* Copy the strings */
    for (j = 0; j < argc; j++) {
        arg = malloc(argvlen[j]+1);
        memcpy(arg,argv[j],argvlen[j]);
        arg[argvlen[j]] = '\0';
        cmd->argv[j].s = arg;
    }

    /* Attach user-supplied callback function */
    cmd->callback = fn;
    cmd->privdata = privdata;

    /* Commands are queued into a list of pending commands */
    listAddNodeTail(c->pending,cmd);
