static int get_set_object(pyc_state *pyc, const uint8_t *buf, PyObject **obj)
{
	uint32_t set_size;
	uint32_t i;
	/* set header: SIZE, then SIZE slots */
	const uint8_t *slot_start;
	get_ut32(pyc, buf, &set_size);
	if (set_size > ST32_MAX) {
		return -1;
	}
	*obj = PySet_New(NULL);
	if (*obj == NULL) {
		return -1;
	}
	slot_start = buf + 4 + set_size * pyc->item_size;
	for (i = 0; i < set_size; i++) {
		/* each set item is a hash table entry:
		   KEY, then VALUE */
		uint32_t key_len;
		uint32_t value_len;
		const uint8_t *key_start;
		const uint8_t *value_start;
		get_ut32(pyc, &buf[0], &key_len);
		key_start = &buf[0];
		buf += key_len;
		get_ut32(pyc, &buf[0], &value_len);
		value_start = &buf[0];
		buf += value_len;
		if (PySet_Add(*obj, (PyObject *)get_array_object_generic(pyc, key_start, key_len, value_start, value_len)) < 0) {
			Py_DECREF(*obj);
			*obj = NULL;
			return -1;
		}
	}
	return 0;
}

