Status InferenceContet::ExpandOutputs(int num_additional_outputs) {
  if (num_additional_outputs < 0) {
    return errors::InvalidArgument("num_additional_outputs: ",
                                   num_additional_outputs, " must be >= 0");
  }
  if (outputs_.size() + num_additional_outputs <
      outputs_.size()) {  // overflow check
    return errors::InvalidArgument(
        "num_additional_outputs: ", num_additional_outputs,
        " is too large for the number of outputs: ", outputs_.size());
  }
  int new_output_size = outputs_.size() + num_additional_outputs;
  if (new_output_size > 0) {
    // Resizing a vector of incomplete TensorElements leads to crashes. We
    // work around this by pre-allocating a fixed amount of TensorElements
    // (kInitialTensorElementCapacity). If this is not enough, the vector
    // will grow and reallocate its contents. During reallocation, the
    // incomplete TensorElement will be moved (not copied) which leads to a
    // crash.
    const int kInitialTensorElementCapacity = 10;
    outputs_.resize(new_output_size,
                   TensorElement{new AbstractTensor(), Tensor()});
    // In debug mode, check that the vector did not shrink.
    CHECK_GE(outputs_.size(), new_output_size);
    // Only grow the vector of output shapes and types.
    if (output_handle_shapes_and_types_.size() < new_output_size) {
      output_handle_shapes_and_types_.resize(
          new_output_size, std::make_pair(std::vector<TensorShape>(), DataType));
    }
  }
  return Status::OK();
}  // namespace tensorflow

