static int tracing_bpf_link_attach(struct bpf_link *link,
				   const struct bpf_attr *attr)
{
	struct bpf_tracing_link *tr_link =
		container_of(link, struct bpf_tracing_link, link);
	struct bpf_prog *prog = tr_link->link.prog;
	u32 attach_type = attr->attach_type;
	u64 key = attr->attach_bpf_obj_file;
	u64 uval;
	int ret;
	struct bpf_map *map;

	if (attach_type != tr_link->expected_attach_type)
		return -EINVAL;

	if (prog->type != BPF_PROG_TYPE_TRACING &&
	    prog->type != BPF_PROG_TYPE_LSM &&
	    prog->type != BPF_PROG_TYPE_EXT)
		return -EINVAL;

	if (prog->type == BPF_PROG_TYPE_EXT &&
	    attach_type != BPF_TRACE_ITER)
		return -EINVAL;

	switch (attach_type) {
	case BPF_TRACE_RAW_TP:
	case BPF_TRACE_ITER:
		break;
	case BPF_TRACE_ITER_MULTI:
		if (!capable(CAP_SYS_ADMIN))
			return -EPERM;
		break;
	case BPF_TRACE_RAW_TRACEPOINT:
		if (key >= MAX_TRACE_POINTS)
			return -EINVAL;
		break;
	case BPF_TRACE_RAW_TRACEPOINT_WRITABLE:
		if (key >= MAX_TRACE_POINTS)
			return -EINVAL;

		map = bpf_get_tracetype_map(key);
		if (!map)
			return -EINVAL;

		return bpf_map_btf_check(map, prog);
	case BPF_TRACE_KPROBE_MULTI:
	case BPF_TRACE_KPROBE:
		if (key >= KPROBE_MAX_NUM)
			return -EINVAL;
		break;
	case BPF_TRACE_KRETPROBE_MULTI:
	case BPF_TRACE_KRETPROBE:
		if (key >= KPROBE_MAX_NUM)
			return -EINVAL;
		break;
	case BPF_TRACE_UPROBE_MULTI:
	case BPF_TRACE_UPROBE:
		if (key >= UPROBE_MAX_NUM)
			return -EINVAL;
		break;
	case BPF_TRACE_URETPROBE_MULTI:
	case BPF_TRACE_URETPROBE:
		if (key >= UPROBE_MAX_NUM)
			return -EINVAL;
		break;
	case BPF_TRACE_RAW_TP_ITER:
		if (prog->type != BPF_PROG_TYPE_LSM)
			return -EINVAL;
		break;
	default:
		return -EINVAL;
	}

	ret = bpf_verifier_run(&tr_link->link, prog, attr);
	if (ret < 0)
		return ret;

	switch (attach_type) {
	case BPF_TRACE_RAW_TP:
	case BPF_TRACE_ITER:
	case BPF_TRACE_ITER_MULTI:
		ret = bpf_trace_raw_tp_link_create(link, key);
		break;
	case BPF_TRACE_RAW_TRACEPOINT:
		ret = bpf_trace_raw_tpoint_link_create(link, key);
		break;
	case BPF_TRACE_RAW_TRACEPOINT_WRITABLE:
		map = bpf_get_tracetype_map(key);
		if (!map)
			return -EINVAL;

		uval = tr_link->link.prog->is_func || tr_link->link.prog->is_funcgraph;
		ret = bpf_map_update_elem(map, &key, &uval, BPF_ANY);
		if (!ret)
			ret = bpf_trace_raw_tpoint_link_create(link, key);
		break;
	case BPF_TRACE_KPROBE_MULTI:
	case BPF_TRACE_KPROBE:
		ret = bpf_trace_kprobe_link_create(link, key);
		break;
	case BPF_TRACE_KRETPROBE_MULTI:
	case BPF_TRACE_KRETPROBE:
		ret = bpf_trace_kretprobe_link_create(link, key);
		break;
	case BPF_TRACE_UPROBE_MULTI:
	case BPF_TRACE_UPROBE:
		ret = bpf_trace_uprobe_link_create(link, key);
		break;
	case BPF_TRACE_URETPROBE_MULTI:
	case BPF_TRACE_URETPROBE:
		ret = bpf_trace_uretprobe_link_create(link, key);
		break;
	case BPF_TRACE_RAW_TP_ITER:
		ret = bpf_lsm_trace_link_create(link);
		break;
	}

	if (ret < 0)
		bpf_jit_free(link->prog);
	return ret;
}

