pjsip_dlg_update_remote_cap(pjsip_dlg *dlg, const pjsip_cid_hdr *cid,
				const pjsip_sdp_hdr *sdp)
{
    if (dlg->remote_cap && cid)
    {
	pjsip_sdp_media *m;
	pjsip_sdp_contet contet;

	pjsip_sdp_parse_cid(sdp, cid);
	pjsip_sdp_parse_sdp(&contet, sdp->sdp);

	for (m = contet.media; m; m = m->net)
	{
	    pjsip_sdp_epr *r;
	    pjsip_sdp_epr *l = pjsip_sdp_find_epr_by_maddr(dlg->local_cap,
								 m->addr);
	    if (!l)
		continue;

	    /* Find remote epr */
	    r = pjsip_sdp_find_epr_by_maddr(dlg->remote_cap, m->addr);
	    if (r)
	    {
		/* If the epr is found, then update the epr */
		pjsip_sdp_epr_update(r, l);
	    } else
	    {
		/* Otherwise, just copy the epr */
		r = pjsip_sdp_epr_clone(m, l);
		pjsip_sdp_media_add_epr(m, r);
	    }
	}

	/* If the dialog is in strict mode, then remove the capabilities
	 * that are not specified in the new remote capability.
	 */
	if (dlg->strict)
	{
	    pjsip_sdp_media *m;
	    pjsip_sdp_epr *epr;

	    for (m = dlg->remote_cap; m; m = m->net)
	    {
		pjsip_sdp_epr *epr2;
		epr = pjsip_sdp_find_epr_by_maddr(m, m->addr);
		for (epr2 = m->epr; epr2; epr2 = epr2->net)
