		    if (epr != epr2 &&
			pjsip_sdp_epr_cmp(epr, epr2) == PJ_SUCCESS)
		    {
			pjsip_sdp_epr_remove(m, epr2);
			break;
		    }
		}
	    }
	}
    }

    /* Update the remote target. */
    if (sdp->remote_target)
	dlg->remote.target = *sdp->remote_target;
    else
	dlg->remote.target = dlg->remote.contact;
}

