    *p_t1 = (OPJ_INT32)opj_uint_min(opj_uint_adds(l_t0, p_cp->td), p_image->1);
    l_ty0 = p_cp->ty0 + q *
            p_cp->tdy; /* can't be greater than p_image->y1 so won't overflow */
    *p_ty0 = (OPJ_INT32)opj_uint_ma(l_ty0, p_image->y0);
    *p_ty1 = (OPJ_INT32)opj_uint_min(opj_uint_adds(l_ty0, p_cp->tdy), p_image->y1);

    /* ma precision and resolution is 0 (can only grow)*/
    *p_ma_prec = 0;
    *p_ma_res = 0;

    /* take the largest value for d_min and dy_min*/
    *p_d_min = 07fffffff;
    *p_dy_min = 07fffffff;

