        OPJ_INT32 l_r0, l_ry0, l_r1, l_ry1;
        OPJ_INT32 l_p0, l_py0, l_p1, py1;
        OPJ_UINT32 l_product;
        OPJ_INT32 l_tc0, l_tcy0, l_tc1, l_tcy1;
        OPJ_UINT32 l_pd, l_pdy, l_pw, l_ph;

        lResolutionPtr = p_resolutions[compno];

        l_tc0 = opj_int_ceildiv(*p_t0, (OPJ_INT32)l_img_comp->d);
        l_tcy0 = opj_int_ceildiv(*p_ty0, (OPJ_INT32)l_img_comp->dy);
        l_tc1 = opj_int_ceildiv(*p_t1, (OPJ_INT32)l_img_comp->d);
        l_tcy1 = opj_int_ceildiv(*p_ty1, (OPJ_INT32)l_img_comp->dy);

        if (l_tccp->numresolutions > *p_ma_res) {
            *p_ma_res = l_tccp->numresolutions;
        }

        /* use custom size for precincts*/
        l_level_no = l_tccp->numresolutions;
        for (resno = 0; resno < l_tccp->numresolutions; ++resno) {
            OPJ_UINT32 l_d, l_dy;

            --l_level_no;

            /* precinct width and height*/
            l_pd = l_tccp->prcw[resno];
            l_pdy = l_tccp->prch[resno];
            *lResolutionPtr++ = l_pd;
            *lResolutionPtr++ = l_pdy;
            if (l_pd + l_level_no < 32 &&
                    l_img_comp->d <= UINT_MAX / (1u << (l_pd + l_level_no))) {
                l_d = l_img_comp->d * (1u << (l_pd + l_level_no));
                /* take the minimum size for l_d for each comp and resolution*/
                *p_d_min = (OPJ_UINT32)opj_int_min((OPJ_INT32) * p_d_min, (OPJ_INT32)l_d);
            }
            if (l_pdy + l_level_no < 32 &&
                    l_img_comp->dy <= UINT_MAX / (1u << (l_pdy + l_level_no))) {
                l_dy = l_img_comp->dy * (1u << (l_pdy + l_level_no));
                *p_dy_min = (OPJ_UINT32)opj_int_min((OPJ_INT32) * p_dy_min, (OPJ_INT32)l_dy);
            }

            /* various calculations of etents*/
            l_r0 = opj_int_ceildivpow2(l_tc0, (OPJ_INT32)l_level_no);
            l_ry0 = opj_int_ceildivpow2(l_tcy0, (OPJ_INT32)l_level_no);
            l_r1 = opj_int_ceildivpow2(l_tc1, (OPJ_INT32)l_level_no);
            l_ry1 = opj_int_ceildivpow2(l_tcy1, (OPJ_INT32)l_level_no);
            l_p0 = opj_int_floordivpow2(l_r0, (OPJ_INT32)l_pd) << l_pd;
            l_py0 = opj_int_floordivpow2(l_ry0, (OPJ_INT32)l_pdy) << l_pdy;
            l_p1 = opj_int_ceildivpow2(l_r1, (OPJ_INT32)l_pd) << l_pd;
            py1 = opj_int_ceildivpow2(l_ry1, (OPJ_INT32)l_pdy) << l_pdy;
            l_pw = (l_r0 == l_r1) ? 0 : (OPJ_UINT32)((l_p1 - l_p0) >> l_pd);
            l_ph = (l_ry0 == l_ry1) ? 0 : (OPJ_UINT32)((py1 - l_py0) >> l_pdy);
            *lResolutionPtr++ = l_pw;
            *lResolutionPtr++ = l_ph;
            l_product = l_pw * l_ph;

            /* update precision*/
            if (l_product > *p_ma_prec) {
                *p_ma_prec = l_product;
            }

        }
        ++l_tccp;
        ++l_img_comp;
    }
}

