static OPJ_BOOL opj_get_all_encoding_parameters(
    opj_tcd_t *tcd,
    OPJ_UINT32 tile,
    OPJ_INT32 *p_t0, OPJ_INT32 *p_t1,
    OPJ_INT32 *p_ty0, OPJ_INT32 *p_ty1)
{
    OPJ_INT32 tx0, tx1, ty0, ty1;
    OPJ_UINT32 num_tiles;
    OPJ_INT32 image_width_in_tiles;
    OPJ_INT32 image_height_in_tiles;
    opj_image_t *image = tcd->image;

    num_tiles = tcd->parameters->num_tiles;

    if (num_tiles == 1) {
        *p_t0 = *p_ty0 = 0;
        *p_t1 = (OPJ_INT32) tcd->tile[0]->w;
        *p_ty1 = (OPJ_INT32) tcd->tile[0]->h;
        return OPJ_TRUE;
    }

    /* special case : one tile by row */
    if (tcd->parameters->cp_cinema && (tile == 0)) {
        *p_t0 = *p_ty0 = 0;
        *p_t1 = (OPJ_INT32) tcd->tile[0]->w;
        *p_ty1 = (OPJ_INT32) (tcd->tile[0]->h + tcd->tile[0]->y0);
        return OPJ_TRUE;
    }

    image_width_in_tiles  = (image->comps[0].w + tcd->parameters->tile_size_in_blocks - 1)
                             / tcd->parameters->tile_size_in_blocks;
    image_height_in_tiles = (image->comps[0].h + tcd->parameters->tile_size_in_blocks - 1)
                             / tcd->parameters->tile_size_in_blocks;

    if (tcd->parameters->cp_disto_alloc) {
        OPJ_INT32 total_num_codes = 0;
        OPJ_INT32 i;
        /* compute the total number of codes */
        for (i = 0; i < image->numcomps; i++) {
            total_num_codes += (OPJ_INT32) (image->comps[i].w * image->comps[i].h);
        }
        /* divide by the number of tiles */
        total_num_codes /= num_tiles;
        /* compute the number of blocks per tile */
        tcd->blocks_per_tile = (total_num_codes * tcd->parameters->block_size_in_codes) /
                                 (image->comps[0].w * image->comps[0].h);
        if (tcd->blocks_per_tile < 1) {
            tcd->blocks_per_tile = 1;
        }
    }

    tx0 = (OPJ_INT32) (tile % image_width_in_tiles);
    ty0 = (OPJ_INT32) (tile / image_width_in_tiles);

    tx1 = tx0 + 1;
    ty1 = ty0 + 1;

    if (ty0 < 0
            || ty0 >= image_height_in_tiles
            || ty1 < 0
            || ty1 > image_height_in_tiles) {
        return OPJ_FALSE;
    }

    if (tx0 < 0
            || tx0 >= image_width_in_tiles
            || tx1 < 0
            || tx1 > image_width_in_tiles) {
        return OPJ_FALSE;
    }

    *p_t0 = tx0 * (OPJ_INT32) tcd->parameters->tile_size_in_blocks;
    *p_ty0 = ty0 * (OPJ_INT32) tcd->parameters->tile_size_in_blocks;

    *p_t1 = MIN(tx1 * (OPJ_INT32) tcd->parameters->tile_size_in_blocks, (OPJ_INT32) image->comps[0].w);
    *p_ty1 = MIN(ty1 * (OPJ_INT32) tcd->parameters->tile_size_in_blocks, (OPJ_INT32) image->comps[0].h);

    return OPJ_TRUE;
}

