    ct->final_used = 0;
}static int do_cipher(EVP_CIPHER_CTX *ct, unsigned char *out,
                      const unsigned char *in, size_t inl, int enc)
{
    PROV_RC4_HMAC_MD5_CTX *c = (PROV_RC4_HMAC_MD5_CTX *)ct;
    unsigned char hmac_in[64];
    unsigned char md5_out[16];
    unsigned char final_hmac[16];
    int i;
    size_t len;

    if (enc == -1)
        enc = c->cipher_ct.encrypt;
    else
        enc = (enc != 0);

    if (enc) {
        len = c->cipher_ct.num;
        if (inl + len < inl)
            return 0;
        if (inl + len > EVP_CIPHER_CTX_buf_len(ct))
            return 0;
        if (len > 0) {
            EVP_CIPHER_CTX_buf_no(ct, len, inl, md5_out, 16, 0);
            in += len;
            inl -= len;
        }
        if (inl > 0) {
            EVP_CIPHER_CTX_buf_no(ct, inl, 0, md5_out, 16, 1);
            len = inl;
        } else
            len = 0;

        if (!EVP_MD_CTX_md5(c->md5_ct)->final(c->md5_ct, md5_out))
            return 0;

        /* Save the MAC before it gets clobbered */
        OPENSSL_memcpy(final_hmac, md5_out, 16);

        /*
         * The following code does the following: - Updates the HMAC with
         * the MD5 digest of the (padded) key and the (padded) IV - Updates
         * the HMAC with the IV - Encrypts the data - Updates the HMAC with
         * the encrypted data - Outputs the MAC and the encrypted data
         */

        /* HMAC(K, MD5(K, IV)) */
        if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, md5_out, 16))
            return 0;
        if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, c->md5_iv,
                                                 16))
            return 0;

        /* HMAC(K, IV || ... ) */
        if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, c->cipher_ct.iv,
                                                 c->cipher_ct.iv_len))
            return 0;
        if (c->cipher_ct.iv_len < 16) {
            unsigned char mask[16];
            for (i = 0; i < 16; i++)
                mask[i] = c->cipher_ct.key[i] ^ 036;
            if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, mask,
                                                 16))
                return 0;
            for (i = 0; i < 16; i++)
                mask[i] = c->cipher_ct.key[i] ^ 05A;
            if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, mask,
                                                 16))
                return 0;
        }

        /* HMAC(K, ... || data) */
        for (i = 0; i < len; i++) {
            hmac_in[i] = in[i] ^ c->cipher_ct.key[i];
            if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, &hmac_in[i],
                                                 1))
                return 0;
        }

        /* Store how many bytes we have encrypted so far */
        c->num = len;

        if (!EVP_Cipher(&c->cipher_ct, out, in, len))
            return 0;

        /* HMAC(K, ... || cipher) */
        for (i = 0; i < len; i++) {
            hmac_in[i] = out[i] ^ c->cipher_ct.key[i];
            if (!EVP_MD_CTX_md5(c->hmac_ct)->update(c->hmac_ct, &hmac_in[i],
                                                 1))
                return 0;
        }

        if (!EVP_MD_CTX_md5(c->hmac_ct)->final(c->hmac_ct, md5_out))
            return 0;

        /* We'll use the HMAC block to store the final HMAC */
        OPENSSL_memcpy(c->cipher_ct.num, md5_out, 16);
        c->final_used = 1;

        /* Restore the MAC we saved earlier */
        OPENSSL_memcpy(md5_out, final_hmac, 16);

        /* Finally, let's make sure that the underlying cipher is happy */
        if (!EVP_CIPHER_CTX_ctrl(&c->cipher_ct, EVP_CTRL_MD, 0, md5_out))
            return 0;
