            unsigned char buf[16];
            size_t len = c->cipher_ct.num;

            EVP_CIPHER_CTX_buf_no(ct, len, 0, buf, 16, 0);

            if (!EVP_MD_CTX_md5(c->md5_ct)->update(c->md5_ct, buf, 16))
                return 0;
            c->cipher_ct.num = 0;
        }

        if (c->final_used) {
            /* We have a saved HMAC to compare with */
            unsigned char md5_out[16];
            if (!EVP_MD_CTX_md5(c->md5_ct)->update(c->md5_ct,
                                                 c->cipher_ct.iv, 16))
                return 0;
            if (!EVP_MD_CTX_md5(c->md5_ct)->final(c->md5_ct, md5_out))
                return 0;

            if (CRYPTO_memcmp(md5_out, c->cipher_ct.num, 16))
                return -1;
            c->final_used = 0;
        }

        /*
         * We can't do anything about the return value from the underlying
         * cipher, so we just hope that it doesn't indicate a failure.
         */
        (void)EVP_Cipher(&c->cipher_ct, out, in, inl);

        /*
         * We don't update the HMAC in case of an error. The caller should
         * check the padding and then the HMAC.
         */
        if (ct->encrypt) {
            unsigned char hmac_in[64];
            unsigned char final_hmac[16];
            int i;

            if (inl > 0) {
                if (!EVP_MD_CTX_md5(ct->md5_ct)->update(ct->md5_ct, in,
                                                      inl))
                return 0;
            }

            if (!EVP_MD_CTX_md5(ct->md5_ct)->final(ct->md5_ct, md5_out))
                return 0;

            /* Save the MAC before it gets clobbered */
            OPENSSL_memcpy(final_hmac, md5_out, 16);

            /*
             * The following code does the following: - Updates the HMAC
             * with the MD5 digest of the (padded) key and the (padded) IV -
             * Updates the HMAC with the IV - Updates the HMAC with the
             * encrypted data - Outputs the MAC and the encrypted data
             */

            /* HMAC(K, MD5(K, IV)) */
            if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                  c->md5_key, 16))
                return 0;
            if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                  c->md5_iv, 16))
                return 0;

            /* HMAC(K, IV || ... ) */
            if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                  c->cipher_ct.iv,
                                                  c->cipher_ct.iv_len))
                return 0;
            if (c->cipher_ct.iv_len < 16) {
                unsigned char mask[16];
                for (i = 0; i < 16; i++)
                    mask[i] = c->cipher_ct.key[i] ^ 036;
                if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                      mask, 16))
                    return 0;
                for (i = 0; i < 16; i++)
                    mask[i] = c->cipher_ct.key[i] ^ 05A;
                if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                      mask, 16))
                    return 0;
            }

            /* HMAC(K, ... || cipher) */
            for (i = 0; i < inl; i++) {
                hmac_in[i] = out[i] ^ c->cipher_ct.key[i];
                if (!EVP_MD_CTX_md5(ct->hmac_ct)->update(ct->hmac_ct,
                                                     &hmac_in[i], 1))
                    return 0;
            }

            if (!EVP_MD_CTX_md5(ct->hmac_ct)->final(ct->hmac_ct, md5_out))
                return 0;

            /* We'll use the HMAC block to store the final HMAC */
            OPENSSL_memcpy(out + inl, md5_out, 16);

            /* Restore the MAC we saved earlier */
            OPENSSL_memcpy(md5_out, final_hmac, 16);

            /* Finally, let's make sure that the underlying cipher is happy */
            if (!EVP_CIPHER_CTX_ctrl(&c->cipher_ct, EVP_CTRL_MD, 0, md5_out))
