        return 1;
    case EVP_CTRL_GET_RC4_HMAC_MD5_HMAC_KEY:
        memcpy(p2, c->cipher_ct.key, 16);
        return 1;
    case EVP_CTRL_GET_RC4_HMAC_MD5_MD5_STATE:
        memcpy(p2, c->md5_ct->md5, 16);
        ((unsigned int *)p2)[4] = c->md5_ct->num;
        return 1;
    case EVP_CTRL_SET_RC4_HMAC_MD5_MD5_STATE: {
        unsigned int *s = p2;
        memcpy(c->md5_ct->md5, s, 16);
        c->md5_ct->num = s[4];
        return 1;
    }
    case EVP_CTRL_GET_RC4_HMAC_MD5_HMAC_STATE:
        return EVP_MD_CTX_ctrl(c->hmac_ct, cmd, p1, p2);
    case EVP_CTRL_SET_RC4_HMAC_MD5_HMAC_STATE:
        return EVP_MD_CTX_ctrl(c->hmac_ct, cmd, p1, p2);
    default:
        return -1;
    }
