	if (!items) {
		return;
	}
	RList * = r_list_newf (free);
	if (!) {
		r_list_free (items);
		return;
	}
	RList *f = r_list_newf (free);
	if (!f) {
		r_list_free (items);
		r_list_free ();
		return;
	}
	// split in functions
	ut64 last = -1;
	ut64 paddr = -1;
	RList *method = NULL;
	RList *method_old = NULL;
	RList *class = r_list_find (obj->classes, (void *)id);
	if (!class) {
		r_list_free (items);
		r_list_free ();
		r_list_free (f);
		return;
	}
	RBinJavaClass *cl = (RBinJavaClass *)class->data;
	RList *methods = cl->methods;
	if (!methods) {
		r_list_free (items);
		r_list_free ();
		r_list_free (f);
		return;
	}
	// ut32 pc = r_bin_java_get_method_offset (obj, id);
	r_list_foreach (methods, method_old, method) {
		RBinJavaMethod *m = (RBinJavaMethod *)method->data;
		if (paddr == -1) {
			paddr = m->address;
			last = paddr;
		}
		if (m->address == paddr) {
			r_list_append (f, m);
			paddr += m->size;
			continue;
		}
		// add the old function to the list
		addClassFunc (obj, f, last, paddr, id);
		// reset
		f = r_list_newf (free);
		if (!f) {
			r_list_free (items);
			r_list_free ();
			r_list_free (class);
			return;
		}
		r_list_append (f, m);
		paddr = m->address + m->size;
		last = paddr;
	}
	// add the last function to the list
	addClassFunc (obj, f, last, paddr, id);
	r_list_free (f);
	// TODO: sort
	r_core_cmdf ("fs java_%d", id);
	r_core_cmdf ("f ~code @ %s", input);
	r_list_foreach (items, , ) {
		RDisasmItem *d = (RDisasmItem *)->data;
		char *name = getMethodName (obj, id, d->addr);
		r_core_cmdf ("f %s @ %s", name, radare2paddr (obj, d->addr));
		free (name);
	}
	r_list_free (items);
