static void r_cmd_java_r2dot_range(RBinJavaObj *obj, ut64 from, ut64 to) {
	RList *classes = obj->classes;
	RList *methods = obj->methods;
	RList *fields = obj->fields;
	RList *sections = obj->sections;
	RBinJavaClass *c;
	RBinJavaMethod *m;
	RBinJavaField *f;
	RBinSection *s;
	char *cname;
	char *mname;
	char *fname;
	char *sname;
	if (to == UT64_MAX) {
		to = from + 01000;
	}
	r_cons_printf ("digraph r2java {\n");
	r_cons_printf ("node [shape=box];\n");
	r_list_foreach (classes, , c) {
		cname = c->name;
		r_cons_printf ("class_%p [label=\"%s\"];\n", c, cname);
	}
	r_list_foreach (methods, , m) {
		mname = m->name;
		c = (RBinJavaClass *)r_list_get_n (obj->classes, m->class_id);
		if (!c) {
			mname = sname = "??";
		} else {
			sname = c->name;
		}
		r_cons_printf ("method_%p [label=\"%s::%s\"];\n", m, sname, mname);
		r_cons_printf ("class_%p -> method_%p;\n", c, m);
	}
	r_list_foreach (fields, , f) {
		fname = f->name;
		c = (RBinJavaClass *)r_list_get_n (obj->classes, f->class_id);
		if (!c) {
			fname = sname = "??";
		} else {
			sname = c->name;
		}
		r_cons_printf ("field_%p [label=\"%s::%s\"];\n", f, sname, fname);
		r_cons_printf ("class_%p -> field_%p;\n", c, f);
	}
	r_list_foreach (sections, , s) {
		sname = s->name;
		r_cons_printf ("section_%p [label=\"%s\"];\n", s, sname);
	}
	r_list_foreach (methods, , m) {
		ut8 *opcode = NULL;
		RList *edges = NULL;
