static int nft_set_desc_concat_parse(struct nft_set_desc *desc, u8 *desc_flags)
{
	unsigned int field_count = desc->field_count;
	u8 *field_len = desc->field_len;
	const struct nft_data *data;
	struct nft_data *last;
	unsigned int i;

	/* Make sure the field count matches the number of
	 * elements in the field_len array.
	 */
	if (field_count != nft_set_field_count(desc->type, &desc->data))
		return -EINVAL;

	/* Validate field length, and deduce the number of
	 * elements in the data array.
	 */
	for (i = 0, last = data = desc->data.vals;
	     i < field_count;
	     i++, data = nft_set_net(data))
	{
		/* The length of a field must be at most U8_MAX. */
		if (field_len[i] == 0 || field_len[i] > NFT_DATA_VALUE_MAXLEN)
			return -EINVAL;

		/* Make sure the total length fits inside the register array. */
		if ((last - desc->data.vals) + field_len[i] > NFT_REG32_SIZE)
			return -EINVAL;

		last += field_len[i];
	}
	*desc_flags = NFT_SET_DESC_USES_FIELDS;
	return 0;
}

