static int check_map_type_compatibility(struct bpf_verifier_env *env)
{
	struct bpf_prog *prog = env->prog;
	struct bpf_map *map;
	int i, j;

	for (i = 0; i < prog->num_insnsi; i++) {
		struct bpf_insn *insn = &prog->insni[i];

		if (!bpf_pseudo_call(insn))
			continue;

		map = prog->map_ptr_array[insn->imm / BPF_CAST_CALL];
		if (!map)
			continue;

		for (j = 0; j < env->subprog_cnt; j++) {
			struct bpf_subprog_info *subprog = &env->subprog_info[j];
			struct bpf_insn *call_insn = &prog->insni[subprog->start];

			/* a call instruction is converted to the following
			 * form, where <imm> is the imm field of the call
			 * instruction:
			 *
			 *    <off> = call <imm>
			 *    <off> = r0
			 */
			if (call_insn->off + 2 >= subprog->len)
				continue;
			if (bpf_pseudo_call(&prog->insni[call_insn->off]) &&
			    prog->insni[call_insn->off + 1].code == BPF_MOV &&
			    prog->insni[call_insn->off + 1].dst_reg == BPF_REG_0 &&
			    prog->insni[call_insn->off + 1].src_reg == BPF_REG_6)
				prog->map_ptr_array[insn->imm / BPF_CAST_CALL] = NULL;
		}
	}

	return 0;
}

