Generation:
spell_suggest_file(
    char_u	*file,
    char_u	*preword,
    int		(*skip)(char_u *),
    char_u	*word,
    int		(*check)(char_u *, char_u *),
    char_u	**list,
    int		*count,
    int		*allocated)
{
    FILE	*fd;
    char_u	buf[NUMBUFLEN];
    char_u	*wp;
    char_u	*word2;
    int		sugg;
    char_u	*line;
    int		incl;
    char_u	*filename = NULL;

    *count = 0;
    *list = NULL;

    if (check == NULL)
	check = spell_default_check;

    /*
     * Open the file for reading.
     */
    fd = mch_fopen(file, "r");
    if (fd == NULL)
	return FAIL;

    /*
     * Read lines from the file.
     */
    line = buf;
    while (vim_fgets(fd, NUMBUFLEN, buf) != NULL)
    {
	/*
	 * Lines starting with a space are comments.
	 */
	if (buf[0] == ' ')
	    continue;

	/*
	 * Lines containing white space are not handled well, skip them.
	 */
	if (vim_isspace(buf[0]))
	    continue;

	/*
	 * A leading dot means the suggestion is for a word that starts with
	 * a dot.  Prepend the period to the word.
	 */
	if (buf[0] == '.')
	    wp = buf + 1;
	else
	    wp = buf;

	/*
	 * Check if the suggestion is for the word we were looking for.
	 * The suggestion has to start with the word, to handle words like
	 * "can't" and "cannot".
	 */
	sugg = 0;
	word2 = wp;
	while (*word2 == *word && *word2 != NUL)
	{
	    if (vim_isspace(*word2))
		break;
	    word2++;
	    word++;
	}
	if (word2 == wp && *word == NUL)
	    sugg = 1;

	/*
	 * If a skip function was given, use it to check if we should use
	 * this suggestion.
	 */
	if (sugg && skip != NULL && skip(wp))
	    sugg = 0;

	/*
	 * If the suggestion passes the skip and check filters, add it to
	 * the list.
	 */
	if (sugg && check(preword, wp))
	{
	    if (spell_add_to_list(list, count, allocated, wp) == FAIL)
	    {
		fclose(fd);
		return FAIL;
	    }
	}
    }

    fclose(fd);
    return OK;
}

