Item_decimal::decimal_precision_and_scale(THD *thd,
                                          const Item *item,
                                          uint *precision, uint *scale)
{
  if (item->decimal_precision_and_scale(thd, precision, scale))
    return TRUE;
  if (*scale > DECIMAL_MAX_SCALE)
  {
    uint m;
    /* limit scale to DECIMAL_MAX_SCALE */
    if (session_var(thd)->sql_mode & MODE_STRICT_ALL)
    {
      /* In strict mode, this is an error. */
      my_message(ER_UNKNOWN_ERROR,
                 ER(CR_DECIMAL_SCALE_TOO_BIG), MYF(0));
      return TRUE;
    }
    /* In non-strict mode, truncate the number. */
    m= 1;
    for (*scale= 0; *scale < DECIMAL_MAX_SCALE; (*scale)++)
      m *= 10;
    *precision= *precision - (*scale - DECIMAL_MAX_SCALE);
    *scale= DECIMAL_MAX_SCALE;
  }
  return FALSE;
} /* Item_decimal::decimal_precision_and_scale */

