            printf("  -p port           Connect to port (default: 6379)\n");
            printf("  -a password       Password for AUTH\n");
            printf("  -n database       Database number (default: 0)\n");
            printf("  -C                Enable cluster mode\n");
            printf("  -s                Enable SSL mode\n");
            printf("  -K                Enable SO_KEEPALIVE\n");
            printf("  -q                Quiet mode (no banner)\n");
            printf("  -v                Verbose mode\n");
            printf("  -V                Show version\n");
            printf("  --help            Show this help\n");
