        port = use_cluster ? 6379 : 6380;

    if (hostname) {
        ret = getaddrinfo(hostname, NULL, &hints, &servers);
        if (ret != 0) {
            fprintf(stderr, "Invalid hostname: %s\n", hostname);
            return 1;
        }
        server = servers;
    } else {
