        server = &local;
    }

    if (port) {
        char portbuf[16];
        snprintf(portbuf, sizeof(portbuf), "%d", port);
        server->ai_port = portbuf;
    }

    if (use_ssl) {
        c = redisAsyncConnectWithOptions(server, &options);
        if (c->c->err) {
            redisAsyncFree(c);
            fprintf(stderr, "Unable to connect: %s\n", c->c->errstr);
            return 1;
        }
        fd = redisAsyncFd(c);
        if (fd < 0) {
            redisAsyncFree(c);
            fprintf(stderr, "Unable to get socket descriptor: %s\n", c->c->errstr);
            return 1;
        }
        if (redisEnableSsl(c, NULL, 0, 0) == REDIS_ERR) {
