            fprintf(stderr, "Unable to connect: %s\n", c->c->errstr);
            return 1;
        }
        fd = redisAsyncFd(c);
        if (fd < 0) {
            redisAsyncFree(c);
            fprintf(stderr, "Unable to get socket descriptor: %s\n", c->c->errstr);
            return 1;
        }
    }

    base = event_base_new();
    if (!base) {
        fprintf(stderr, "Could not initialize libevent\n");
        return 1;
    }

    redisAsyncSetConnectCallback(c, connectCallback);
    redisAsyncSetDisconnectCallback(c, disconnectCallback);

    if (password) {
