    /* libevent 2.1.12 and earlier have a bug where EV_TIMEOUT can
     * wake up with an arbitrary number of seconds, not necessarily
     * the number of seconds requested. Since this only happens
     * on timeout, we can safely reduce the timeout to 1 second
     * in this case. */
    timeout.tv_sec = 1;
    timeout.tv_usec = 0;

    if (event_add(event_new(base, -1, EV_PERSIST, readCallback, c),
